# === Hardware Detection & GPU-First Adaptive Performance Governor ===
# GPU-FIRST POLICY: GPU is the primary compute device. CPU is fallback only.
# 1. Always use GPU for gravity, EM forces, and batch position updates when available.
# 2. GPU aims for 50%+ utilization before ANY CPU compute is used.
# 3. Under heavy load, GPU scales to 100% utilization.
# 4. CUDA max-performance mode and overclock support enabled at startup.
# 5. CPU handles only: atom internal dynamics, observer AI, and non-batchable logic.

_PERF_GPU_AVAILABLE = False
_PERF_GPU_NAME = 'None'
_PERF_GPU_VRAM_MB = 0
_PERF_GPU_COMPUTE_CAP = (0, 0)
_PERF_CPU_CORES = max(1, os.cpu_count() or 1)
_PERF_GPU_DEVICE = None  # torch.device object when GPU available

if _TORCH:
    try:
        if torch.cuda.is_available():
            _PERF_GPU_AVAILABLE = True
            _PERF_GPU_NAME = torch.cuda.get_device_name(0)
            props = torch.cuda.get_device_properties(0)
            _PERF_GPU_VRAM_MB = int(props.total_mem / (1024 * 1024))
            _PERF_GPU_COMPUTE_CAP = (props.major, props.minor)
            _PERF_GPU_DEVICE = torch.device('cuda', 0)
            # === CUDA Max Performance Mode ===
            # Allow full GPU utilization up to 100% and support overclocking
            try:
                # Enable TF32 for faster float32 math on Ampere+ GPUs (compute cap >= 8.0)
                if props.major >= 8:
                    torch.backends.cuda.matmul.allow_tf32 = True
                    torch.backends.cudnn.allow_tf32 = True
                # Set memory growth / caching behavior for max throughput
                # Use expandable_segments to allow GPU memory to grow without fragmentation
                os.environ.setdefault('PYTORCH_CUDA_ALLOC_CONF', 'expandable_segments:True')
                # Set CUDA to max-performance power mode via environment hints
                # (actual overclock requires nvidia-smi or driver-level control)
                os.environ.setdefault('CUDA_AUTO_BOOST', '1')  # Enable GPU Boost / overclock
                # Enable cudnn benchmark for fastest kernel selection
                torch.backends.cudnn.benchmark = True
                # Pre-warm GPU: allocate and free a tensor to initialize CUDA context
                _warmup = torch.zeros(1024, device=_PERF_GPU_DEVICE)
                del _warmup
                torch.cuda.empty_cache()
            except Exception:
                pass
    except Exception:
        pass

# Detect broken CUDA: VRAM=0 or compute_cap=(0,0) means the CUDA runtime can't
# fully drive this GPU (e.g. Blackwell before PyTorch adds support).
# Override device to CPU so .to(device) calls don't hang during NN init.
if _PERF_GPU_AVAILABLE and (_PERF_GPU_VRAM_MB == 0 or _PERF_GPU_COMPUTE_CAP == (0, 0)):
    print(f"[WARNING] CUDA reports VRAM={_PERF_GPU_VRAM_MB}MB cap={_PERF_GPU_COMPUTE_CAP[0]}.{_PERF_GPU_COMPUTE_CAP[1]} — NN models will use CPU (GPU physics still enabled)")
    if _TORCH:
        device = torch.device("cpu")

def _gpu_to_tensors(positions_np, masses_np):
    """Move position/mass arrays to GPU. Always attempts GPU when available (no size threshold).
    Returns (positions_tensor, masses_tensor, on_gpu_bool).
    Falls back to numpy arrays (on_gpu=False) if GPU unavailable or fails."""
    if _PERF_GPU_AVAILABLE:
        try:
            pos_t = torch.as_tensor(positions_np, dtype=torch.float32, device=_PERF_GPU_DEVICE)
            mass_t = torch.as_tensor(masses_np, dtype=torch.float32, device=_PERF_GPU_DEVICE)
            return pos_t, mass_t, True
        except Exception:
            pass
    return positions_np, masses_np, False

def _gpu_pairwise_gravity(pos_t, mass_t, G_val, softening=1e-10):
    """GPU-accelerated O(N^2) direct gravity via torch on CUDA.
    Used at ANY particle count when GPU is available. Returns numpy array of accelerations."""
    diff = pos_t.unsqueeze(1) - pos_t.unsqueeze(0)  # (N,N,3)
    dist_sq = (diff * diff).sum(dim=2) + softening   # (N,N)
    dist = torch.sqrt(dist_sq)                         # (N,N)
    inv_dist3 = mass_t.unsqueeze(0) / (dist_sq * dist + softening)  # (N,N)
    inv_dist3.fill_diagonal_(0.0)
    accel = G_val * (inv_dist3.unsqueeze(2) * diff).sum(dim=1)  # (N,3)
    return accel.cpu().numpy()

def _gpu_pairwise_em_forces(pos_t, charges_t, vel_t, masses_t, k_e_val, mu_0_val, cutoff_sq=250000.0, softening=1e-10):
    """GPU-accelerated O(N^2) Coulomb + Lorentz forces via torch on CUDA.
    Returns numpy array of accelerations from EM interactions."""
    n = pos_t.shape[0]
    if n < 2:
        return np.zeros((n, 3), dtype=np.float32)
    diff = pos_t.unsqueeze(1) - pos_t.unsqueeze(0)  # (N,N,3)
    dist_sq = (diff * diff).sum(dim=2) + softening   # (N,N)
    # Mask: skip self-interaction and beyond cutoff
    mask = (dist_sq < cutoff_sq)
    mask.fill_diagonal_(False)
    # Coulomb: F = k_e * q_i * q_j / r^2, direction = r_hat
    charge_product = charges_t.unsqueeze(1) * charges_t.unsqueeze(0)  # (N,N)
    # Only compute where both particles are charged and within cutoff
    coulomb_mask = mask & (charge_product.abs() > 1e-30)
    dist_sq_safe = dist_sq.clamp(min=softening)
    # Coulomb acceleration: a_i = sum_j( -k_e * q_i * q_j / (m_i * r^2) * r_hat )
    # r_hat = diff / |r|, so a_i = sum_j( -k_e * q_i * q_j / (m_i * r^3) * diff )
    dist = torch.sqrt(dist_sq_safe)
    inv_dist3 = 1.0 / (dist_sq_safe * dist + softening)
    inv_dist3 = inv_dist3 * coulomb_mask.float()
    # Force per unit mass of receiver: -k_e * q_j * q_self / (m_self * r^3) * diff
    # We compute acceleration directly: a_i = sum_j( -k_e * q_j / r^3 * diff_ij ) * q_i / m_i
    f_coulomb = -k_e_val * (charges_t.unsqueeze(0) * inv_dist3).unsqueeze(2) * diff  # (N,N,3)
    accel_coulomb = f_coulomb.sum(dim=1)  # (N,3)
    # Apply q_i / m_i for each receiver
    mass_safe = masses_t.clamp(min=1e-60)
    qm_ratio = charges_t / mass_safe  # (N,)
    accel = accel_coulomb * qm_ratio.unsqueeze(1)
    return accel.cpu().numpy()

def _gpu_batch_position_update(positions_np, velocities_np, accels_np, dt_val, prev_accels_np=None):
    """GPU-accelerated Velocity Verlet (symplectic) position + velocity update.
    Velocity Verlet: x(t+dt) = x(t) + v(t)*dt + 0.5*a(t)*dt²
                     v(t+dt) = v(t) + 0.5*(a(t) + a(t+dt))*dt
    When prev_accels is None, falls back to leapfrog kick-drift-kick.
    Returns (new_positions, new_velocities) as numpy arrays.
    Ref: Swope et al. (1982) J. Chem. Phys. 76, 637; Verlet (1967) Phys. Rev. 159, 98."""
    if _PERF_GPU_AVAILABLE:
        try:
            pos_t = torch.as_tensor(positions_np, dtype=torch.float32, device=_PERF_GPU_DEVICE)
            vel_t = torch.as_tensor(velocities_np, dtype=torch.float32, device=_PERF_GPU_DEVICE)
            acc_t = torch.as_tensor(accels_np, dtype=torch.float32, device=_PERF_GPU_DEVICE)
            dt2 = dt_val * dt_val
            # Velocity Verlet position: x += v*dt + 0.5*a*dt²
            pos_t = pos_t + vel_t * dt_val + 0.5 * acc_t * dt2
            if prev_accels_np is not None:
                # Full Verlet: v += 0.5*(a_old + a_new)*dt
                prev_t = torch.as_tensor(prev_accels_np, dtype=torch.float32, device=_PERF_GPU_DEVICE)
                vel_t = vel_t + 0.5 * (prev_t + acc_t) * dt_val
            else:
                # Kick-drift-kick fallback: half-kick with current accel
                vel_t = vel_t + acc_t * dt_val
            return pos_t.cpu().numpy(), vel_t.cpu().numpy()
        except Exception:
            pass
    # CPU fallback — Velocity Verlet
    dt2 = dt_val * dt_val
    new_pos = positions_np + velocities_np * dt_val + 0.5 * accels_np * dt2
    if prev_accels_np is not None:
        new_vel = velocities_np + 0.5 * (prev_accels_np + accels_np) * dt_val
    else:
        new_vel = velocities_np + accels_np * dt_val
    return new_pos, new_vel

# Legacy alias for compatibility
def _gpu_accelerate_positions(positions_np, masses_np):
    return _gpu_to_tensors(positions_np, masses_np)

class _PerformanceGovernor:
    """GPU-first adaptive performance manager.
    GPU is ALWAYS the primary compute device when available.
    Quality levels: 0=survival, 1=low, 2=medium, 3=high, 4=ultra.
    GPU usage scales from 50% (idle) to 100% (heavy load).
    CPU only handles non-batchable work (atom internals, observer AI)."""

    def __init__(self):
        self.quality = 3
        self._frame_times = deque(maxlen=60)
        self._target_fps = 60.0
        self._last_adjust = 0.0
        self._adjust_interval = 0.5
        self._gpu_available = _PERF_GPU_AVAILABLE
        # GPU load tracking
        self._gpu_load_target = 0.50  # Minimum 50% GPU utilization target
        self._gpu_load_max = 1.00     # Allow up to 100% GPU
        self._gpu_batch_em = _PERF_GPU_AVAILABLE  # GPU handles EM forces
        self._gpu_batch_pos = _PERF_GPU_AVAILABLE  # GPU handles position updates
        self._n_particles = 0  # Updated each frame for adaptive throttling
        # Print startup diagnostics
        _gpu_info = 'None (CPU-only mode)'
        if _PERF_GPU_AVAILABLE:
            _oc = 'boost=ON' if os.environ.get('CUDA_AUTO_BOOST') == '1' else 'boost=OFF'
            _tf32 = 'TF32=ON' if _PERF_GPU_COMPUTE_CAP[0] >= 8 else 'TF32=N/A'
            _gpu_info = f'YES {_PERF_GPU_NAME} ({_PERF_GPU_VRAM_MB}MB, cap={_PERF_GPU_COMPUTE_CAP[0]}.{_PERF_GPU_COMPUTE_CAP[1]}, {_oc}, {_tf32})'
        self._startup_msg = (
            f"[PerfGov] GPU-FIRST mode | CPU: {_PERF_CPU_CORES} cores | GPU: {_gpu_info}"
        )
        print(self._startup_msg)
        if _PERF_GPU_AVAILABLE:
            print(f"[PerfGov] GPU compute: gravity=ON, EM-forces=ON, batch-pos=ON | Target GPU load >= {self._gpu_load_target:.0%}")

    def record_frame(self, dt, n_particles=0):
        self._frame_times.append(max(dt, 0.0001))
        self._n_particles = n_particles

    def get_avg_fps(self):
        if len(self._frame_times) < 3:
            return 60.0
        avg_dt = sum(self._frame_times) / len(self._frame_times)
        return 1.0 / max(avg_dt, 0.0001)

    def maybe_adjust(self):
        now = time.time()
        if now - self._last_adjust < self._adjust_interval:
            return
        self._last_adjust = now
        fps = self.get_avg_fps()
        old_q = self.quality
        if fps < self._target_fps * 0.3 and self.quality > 0:
            self.quality = max(0, self.quality - 2)
        elif fps < self._target_fps * 0.5 and self.quality > 0:
            self.quality -= 1
        elif fps > self._target_fps * 1.5 and self.quality < 4:
            self.quality += 1
        elif fps > self._target_fps * 1.1 and self.quality < 3:
            self.quality += 1
        if old_q != self.quality:
            _tag = 'GPU' if self._gpu_available else 'CPU'
            print(f"[PerfGov] Quality {old_q}->{self.quality} (FPS={fps:.1f}) [{_tag}]")

    @property
    def max_substeps(self):
        # GPU can handle more substeps — raise limits when GPU is primary
        if self._gpu_available:
            return [8, 24, 48, 64, 96][self.quality]
        return [4, 12, 24, 48, 64][self.quality]

    @property
    def substep_budget(self):
        # GPU gets more wall-clock budget since it computes faster
        if self._gpu_available:
            return [0.004, 0.008, 0.012, 0.016, 0.024][self.quality]
        return [0.002, 0.004, 0.006, 0.008, 0.012][self.quality]
    @property
    def observer_update_mul(self):
        # Observer AI always runs on CPU — never throttle to death even at quality 0
        # CPU handles AI alongside GPU physics simultaneously
        return [1.5, 1.2, 1.0, 1.0, 0.8][self.quality]

    @property
    def max_render_labels(self):
        return [200, 500, 9999, 9999, 9999][self.quality]

    @property
    def skip_det_frames(self):
        return self.quality < 1

    @property
    def sphere_snap_interval(self):
        # Scale sphere snapshot interval with particle count
        _base = 60
        if self._n_particles > 500:
            _base = 180
        elif self._n_particles > 200:
            _base = 120
        return _base

    @property
    def det_record_interval(self):
        # How often to record deterministic frames (1=every frame, 3=every 3rd, etc.)
        # State copy is expensive - throttle based on quality AND particle count
        _base = [999, 10, 5, 2, 1][self.quality]
        # Scale up interval when many particles (copy cost is O(N))
        if self._n_particles > 500:
            _base = max(_base, 10)
        elif self._n_particles > 200:
            _base = max(_base, 5)
        return _base

    @property
    def use_gpu_gravity(self):
        # GPU-FIRST: always use GPU for gravity when available, at ALL quality levels
        return self._gpu_available

    @property
    def use_gpu_em(self):
        # GPU-FIRST: always use GPU for EM forces when available
        return self._gpu_batch_em

    @property
    def use_gpu_batch_pos(self):
        # GPU-FIRST: always use GPU for batch position updates
        return self._gpu_batch_pos

_perf = _PerformanceGovernor()

