            # ── Layout regions ──
            RIGHT_W = 320
            HEADER_H = 56
            CHART_H = 140
            STATUS_H = 28
            WORLD_W = W - RIGHT_W - 2
            WORLD_H = H - HEADER_H - CHART_H - STATUS_H - 4

            # ── HEADER BAR ──
            self_state = state.get('self_entity', {})
