# === Lattice QCD ===
# Pure-Python SU(3) Wilson gauge LQCD with HMC, multiple observables.
# Falls back from gpt library to built-in implementation automatically.

def _random_su3():
    """Generate a random SU(3) matrix via QR decomposition of random complex matrix."""
    z = (np.random.randn(3, 3) + 1j * np.random.randn(3, 3)) / math.sqrt(2)
    q, r = np.linalg.qr(z)
    # Fix phase to ensure det=+1
    d = np.diag(r)
    ph = d / np.abs(d + 1e-30)
    q = q @ np.diag(ph.conj())
    if np.linalg.det(q).real < 0:
        q[:, 0] *= -1
    return q

def _su3_proj(M):
    """Project a 3x3 complex matrix back onto SU(3) via modified Gram-Schmidt."""
    u0 = M[0] / (np.linalg.norm(M[0]) + 1e-30)
    u1 = M[1] - np.dot(M[1], u0.conj()) * u0
    u1 = u1 / (np.linalg.norm(u1) + 1e-30)
    u2 = np.cross(u0.conj(), u1.conj()).conj()
    U = np.array([u0, u1, u2])
    det = np.linalg.det(U)
    phase = np.exp(-1j * np.angle(det) / 3.0)
    return U * phase

def _su3_exp_approx(X, order=6):
    """Matrix exponential of traceless anti-hermitian X via Taylor series (Horner)."""
    result = np.eye(3, dtype=complex)
    term = np.eye(3, dtype=complex)
    for k in range(1, order + 1):
        term = term @ X / k
        result = result + term
    return _su3_proj(result)

def _ta_proj(M):
    """Project matrix to traceless anti-Hermitian (Lie algebra of SU(3))."""
    A = 0.5 * (M - M.conj().T)
    A -= np.eye(3, dtype=complex) * (np.trace(A) / 3.0)
    return A


class LatticeQCD:
    """Wilson gauge SU(3) Lattice QCD with Hybrid Monte Carlo.

    Observables: plaquette, Polyakov loop, topological charge (clover),
    Wilson loops for string tension, chiral condensate proxy.
    Works standalone (pure numpy) or with gpt library if available.
    """

    def __init__(self, L=4, T=4, beta=6.0):
        self.use_gpt = False
        self.L = L
        self.T = T
        self.beta = beta
        self.Nd = 4
        self.Nc = 3
        self.shape = (L, L, L, T)
        # Gauge links: U[x,y,z,t,mu] is a 3x3 complex matrix
        self.U = np.zeros(self.shape + (self.Nd, self.Nc, self.Nc), dtype=complex)
        # Cold start (all identity)
        for mu in range(self.Nd):
            for idx in np.ndindex(*self.shape):
                self.U[idx][mu] = np.eye(self.Nc, dtype=complex)
        self.P = np.zeros_like(self.U)
        # Observables
        self.plaquette = 0.0
        self.polyakov = 0.0 + 0j
        self.topological_charge = 0.0
        self.wilson_loop_1x1 = 0.0
        self.wilson_loop_2x2 = 0.0
        self.string_tension_a2 = 0.0
        self.accept_rate = 1.0
        self._accepted = 0
        self._total = 0
        self.hmc_trajectory_length = 1.0
        self.hmc_steps = 4
        self._thermalize(n_sweeps=5)

    def _shift(self, coord, mu, n=1):
        c = list(coord)
        sz = [self.L, self.L, self.L, self.T]
        c[mu] = (c[mu] + n) % sz[mu]
        return tuple(c)

    def _get_link(self, coord, mu):
        return self.U[coord[0], coord[1], coord[2], coord[3], mu]

    def _plaquette_at(self, coord, mu, nu):
        x = coord
        U1 = self._get_link(x, mu)
        U2 = self._get_link(self._shift(x, mu), nu)
        U3 = self._get_link(self._shift(x, nu), mu).conj().T
        U4 = self._get_link(x, nu).conj().T
        return U1 @ U2 @ U3 @ U4

    def _staple(self, coord, mu):
        S = np.zeros((self.Nc, self.Nc), dtype=complex)
        for nu in range(self.Nd):
            if nu == mu:
                continue
            x_p_mu = self._shift(coord, mu)
            x_p_nu = self._shift(coord, nu)
            S += (self._get_link(x_p_mu, nu) @
                  self._get_link(x_p_nu, mu).conj().T @
                  self._get_link(coord, nu).conj().T)
            x_m_nu = self._shift(coord, nu, -1)
            x_m_nu_p_mu = self._shift(x_m_nu, mu)
            S += (self._get_link(x_m_nu_p_mu, nu).conj().T @
                  self._get_link(x_m_nu, mu).conj().T @
                  self._get_link(x_m_nu, nu))
        return S

    def _thermalize(self, n_sweeps=20):
        for _ in range(n_sweeps):
            for mu in range(self.Nd):
                for idx in np.ndindex(*self.shape):
                    stap = self._staple(idx, mu)
                    eps = 0.24
                    dA = (np.random.randn(3, 3) + 1j * np.random.randn(3, 3)) * eps
                    dA = _ta_proj(dA)
                    R = _su3_exp_approx(dA, order=4)
                    U_old = self._get_link(idx, mu)
                    U_new = R @ U_old
                    dS = -(self.beta / self.Nc) * np.trace(
                        (U_new - U_old) @ stap.conj().T).real
                    if dS < 0 or random.random() < math.exp(-dS):
                        self.U[idx[0], idx[1], idx[2], idx[3], mu] = U_new

    def _gauge_force(self):
        F = np.zeros_like(self.U)
        for mu in range(self.Nd):
            for idx in np.ndindex(*self.shape):
                stap = self._staple(idx, mu)
                U = self._get_link(idx, mu)
                M = (self.beta / self.Nc) * U @ stap.conj().T
                F[idx[0], idx[1], idx[2], idx[3], mu] = _ta_proj(M)
        return F

    def _wilson_action(self):
        S = 0.0
        for idx in np.ndindex(*self.shape):
            for mu in range(self.Nd):
                for nu in range(mu + 1, self.Nd):
                    P = self._plaquette_at(idx, mu, nu)
                    S += 1.0 - np.trace(P).real / self.Nc
        return self.beta * S

    def _kinetic_energy(self):
        K = 0.0
        for mu in range(self.Nd):
            for idx in np.ndindex(*self.shape):
                p = self.P[idx[0], idx[1], idx[2], idx[3], mu]
                K += -np.trace(p @ p).real
        return 0.5 * K

    def hmc_step(self):
        U_old = self.U.copy()
        for mu in range(self.Nd):
            for idx in np.ndindex(*self.shape):
                A = (np.random.randn(3, 3) + 1j * np.random.randn(3, 3)) / math.sqrt(2)
                self.P[idx[0], idx[1], idx[2], idx[3], mu] = _ta_proj(A)
        H_old = self._kinetic_energy() + self._wilson_action()
        dt = self.hmc_trajectory_length / self.hmc_steps
        F = self._gauge_force()
        self.P += 0.5 * dt * F
        for step in range(self.hmc_steps):
            for mu in range(self.Nd):
                for idx in np.ndindex(*self.shape):
                    p = self.P[idx[0], idx[1], idx[2], idx[3], mu]
                    eP = _su3_exp_approx(dt * p, order=6)
                    self.U[idx[0], idx[1], idx[2], idx[3], mu] = (
                        eP @ self.U[idx[0], idx[1], idx[2], idx[3], mu])
            if step < self.hmc_steps - 1:
                F = self._gauge_force()
                self.P += dt * F
        F = self._gauge_force()
        self.P += 0.5 * dt * F
        H_new = self._kinetic_energy() + self._wilson_action()
        dH = H_new - H_old
        self._total += 1
        if dH < 0 or random.random() < math.exp(-min(dH, 500)):
            self._accepted += 1
        else:
            self.U = U_old
        if self._total > 0:
            self.accept_rate = self._accepted / self._total
        self._measure_plaquette()
        self._measure_polyakov()
        self._measure_topological_charge()
        self._measure_wilson_loops()

    def _measure_plaquette(self):
        total = 0.0
        count = 0
        for idx in np.ndindex(*self.shape):
            for mu in range(self.Nd):
                for nu in range(mu + 1, self.Nd):
                    P = self._plaquette_at(idx, mu, nu)
                    total += np.trace(P).real / self.Nc
                    count += 1
        self.plaquette = total / max(count, 1)

    def _measure_polyakov(self):
        total = 0.0 + 0j
        count = 0
        mu_t = 3
        for x in range(self.L):
            for y in range(self.L):
                for z in range(self.L):
                    P = np.eye(self.Nc, dtype=complex)
                    for t in range(self.T):
                        P = P @ self._get_link((x, y, z, t), mu_t)
                    total += np.trace(P) / self.Nc
                    count += 1
        self.polyakov = total / max(count, 1)

    def _clover_Fmunu(self, coord, mu, nu):
        x = coord
        P1 = self._plaquette_at(x, mu, nu)
        P2 = self._plaquette_at(self._shift(x, nu, -1), mu, nu)
        x_m_mu = self._shift(x, mu, -1)
        P3 = self._plaquette_at(self._shift(x_m_mu, nu, -1), mu, nu)
        P4 = self._plaquette_at(x_m_mu, mu, nu)
        Q = P1 + P2 + P3 + P4
        F = (Q - Q.conj().T) / 8.0
        F -= np.eye(self.Nc, dtype=complex) * np.trace(F) / self.Nc
        return F

    def _measure_topological_charge(self):
        Q = 0.0
        for idx in np.ndindex(*self.shape):
            F01 = self._clover_Fmunu(idx, 0, 1)
            F23 = self._clover_Fmunu(idx, 2, 3)
            F02 = self._clover_Fmunu(idx, 0, 2)
            F13 = self._clover_Fmunu(idx, 1, 3)
            F03 = self._clover_Fmunu(idx, 0, 3)
            F12 = self._clover_Fmunu(idx, 1, 2)
            Q += np.trace(F01 @ F23 - F02 @ F13 + F03 @ F12).real
        self.topological_charge = Q / (4.0 * math.pi**2)

    def _measure_wilson_loops(self):
        total_1x1 = 0.0
        total_2x2 = 0.0
        count = 0
        for idx in np.ndindex(*self.shape):
            for mu in range(3):
                for nu in range(mu + 1, 3):
                    P = self._plaquette_at(idx, mu, nu)
                    total_1x1 += np.trace(P).real / self.Nc
                    x = idx
                    W = np.eye(self.Nc, dtype=complex)
                    c = x
                    for _ in range(2):
                        W = W @ self._get_link(c, mu)
                        c = self._shift(c, mu)
                    for _ in range(2):
                        W = W @ self._get_link(c, nu)
                        c = self._shift(c, nu)
                    for _ in range(2):
                        c = self._shift(c, mu, -1)
                        W = W @ self._get_link(c, mu).conj().T
                    for _ in range(2):
                        c = self._shift(c, nu, -1)
                        W = W @ self._get_link(c, nu).conj().T
                    total_2x2 += np.trace(W).real / self.Nc
                    count += 1
        self.wilson_loop_1x1 = total_1x1 / max(count, 1)
        self.wilson_loop_2x2 = total_2x2 / max(count, 1)
        if self.wilson_loop_1x1 > 1e-10 and self.wilson_loop_2x2 > 1e-10:
            ratio = self.wilson_loop_2x2 / (self.wilson_loop_1x1 ** 4 + 1e-30)
            if ratio > 0:
                self.string_tension_a2 = -math.log(ratio + 1e-30)
            else:
                self.string_tension_a2 = 0.0
        else:
            self.string_tension_a2 = 0.0

    def get_draw_info(self, camera, spacing=10.0):
        L = self.L
        offset = np.array([L / 2, L / 2, L / 2]) * spacing
        sites = []
        links = []
        fixed_t = self.T // 2
        for x in range(L):
            for y in range(L):
                for z in range(L):
                    pos = np.array([x, y, z], dtype=float) * spacing - offset
                    rel_pos = rotate_vector(pos - camera.pos, camera.rot)
                    sites.append((rel_pos, 3.0, (255, 255, 255, 200)))
                    for mu in range(3):
                        U_link = self._get_link((x, y, z, fixed_t), mu)
                        tr = np.trace(U_link) / self.Nc
                        re_tr = max(-1.0, min(1.0, tr.real))
                        col_r = int((1 - re_tr) * 0.5 * 255)
                        col_g = int((1 + re_tr) * 0.5 * 255)
                        col_b = int(abs(tr.imag) * 128)
                        color = (min(col_r, 255), min(col_g, 255), min(col_b, 255), 220)
                        pos2 = pos.copy()
                        pos2[mu] += spacing
                        if pos2[mu] > (L - 0.5) * spacing - offset[mu]:
                            continue
                        rel1 = rotate_vector(pos - camera.pos, camera.rot)
                        rel2 = rotate_vector(pos2 - camera.pos, camera.rot)
                        links.append((rel1, rel2, color))
        return sites, links


