# OpenGL GPU Capability Detection (runs once after GL context is ready)
# Reports renderer, version, display list limits, VBO/extension support.
# ══════════════════════════════════════════════════════════════════
_GL_RENDERER = 'Unknown'
_GL_VERSION = 'Unknown'
_GL_VENDOR = 'Unknown'
_GL_MAX_TEXTURE_SIZE = 0
_GL_MAX_DISPLAY_LISTS = 0
_GL_VBO_SUPPORTED = False
_GL_EXTENSIONS_COUNT = 0

def _gl_get_string_safe(enum_val):
    """Get GL string, handling both PyOpenGL (bytes) and pyglet (LP_c_ubyte) returns."""
    raw = glGetString(enum_val)
    if raw is None:
        return ''
    if isinstance(raw, bytes):
        return raw.decode('utf-8', errors='replace')
    if hasattr(raw, 'decode'):
        return raw.decode('utf-8', errors='replace')
    # pyglet returns ctypes LP_c_ubyte pointer
    try:
        return ctypes.string_at(raw).decode('utf-8', errors='replace')
    except Exception:
        return str(raw)

try:
    from ctypes import c_int as _c_int_gl
    _GL_RENDERER = _gl_get_string_safe(GL_RENDERER) or 'Unknown'
    _GL_VERSION = _gl_get_string_safe(GL_VERSION) or 'Unknown'
    _GL_VENDOR = _gl_get_string_safe(GL_VENDOR) or 'Unknown'
    _ts = _c_int_gl(0)
    glGetIntegerv(GL_MAX_TEXTURE_SIZE, _ts)
    _GL_MAX_TEXTURE_SIZE = _ts.value
    _ext_str = _gl_get_string_safe(GL_EXTENSIONS)
    if _ext_str:
        _ext_list = _ext_str.split()
        _GL_EXTENSIONS_COUNT = len(_ext_list)
        _GL_VBO_SUPPORTED = any('vertex_buffer_object' in e.lower() for e in _ext_list)
    else:
        _GL_VBO_SUPPORTED = True  # Modern GL (3.0+) has VBO built-in
    print(f"[GPU OpenGL] Renderer: {_GL_RENDERER}")
    print(f"[GPU OpenGL] Version:  {_GL_VERSION}  Vendor: {_GL_VENDOR}")
    print(f"[GPU OpenGL] Max Texture: {_GL_MAX_TEXTURE_SIZE}  VBO: {_GL_VBO_SUPPORTED}  Extensions: {_GL_EXTENSIONS_COUNT}")
    if _PERF_GPU_AVAILABLE:
        print(f"[GPU CUDA]   {_PERF_GPU_NAME}  VRAM: {_PERF_GPU_VRAM_MB} MB  Compute: {_PERF_GPU_COMPUTE_CAP[0]}.{_PERF_GPU_COMPUTE_CAP[1]}")
    else:
        print("[GPU CUDA]   Not available — physics will use CPU fallback")
except Exception as _gl_detect_err:
    print(f"[GPU OpenGL] Detection failed: {_gl_detect_err}")

