# Define newmillennium as a function to group 2 or more particles
def newmillennium(particle_group):
    return len(particle_group) >= 2


# Helper to get 3D position (fixed for dims=3)
def get_3d_pos(pos):
    return pos  # Direct 3D position


# Helper to get 3D world position from mouse click
def get_3d_from_mouse(mx, my, model, proj, view, cam=None):
    try:
        near = gluUnProject(mx, my, 0.0, model, proj, view)
        far = gluUnProject(mx, my, 1.0, model, proj, view)
    except (ValueError, Exception):
        return np.zeros(3) if cam is None else cam.pos.copy()
    near = np.array(near)
    far = np.array(far)
    dir_vec = far - near
    if abs(dir_vec[2]) < 1e-6:
        obj_pos = near.copy()
        obj_pos[2] = 0.0
    else:
        t = -near[2] / dir_vec[2]
        obj_pos = near + t * dir_vec
    # Convert from object space (camera-relative rotated) to world space
    if cam is not None:
        world_pos_3d = inverse_rotate_vector(obj_pos[:3], cam.rot) + cam.pos[:3]
        return world_pos_3d
    return obj_pos


# Rotation function â€” optimized: compute combined Rz*Ry*Rx inline without temporary arrays
_rot_cache_key = (0.0, 0.0, 0.0)
_rot_cache_mat = None

def rotate_vector(vec, rot):
    global _rot_cache_key, _rot_cache_mat
    _key = (rot[0], rot[1], rot[2])
    if _key != _rot_cache_key or _rot_cache_mat is None:
        cp = math.cos(rot[0]); sp = math.sin(rot[0])
        cy = math.cos(rot[1]); sy = math.sin(rot[1])
        cr = math.cos(rot[2]); sr = math.sin(rot[2])
        # Combined Rz @ Ry @ Rx
        _rot_cache_mat = np.array([
            [cr*cy,  cr*sy*sp - sr*cp,  cr*sy*cp + sr*sp],
            [sr*cy,  sr*sy*sp + cr*cp,  sr*sy*cp - cr*sp],
            [-sy,    cy*sp,             cy*cp            ]
        ])
        _rot_cache_key = _key
    _result = _rot_cache_mat @ vec
    if not np.all(np.isfinite(_result)):
        return vec
    return _result


def inverse_rotate_vector(vec, rot):
    """Inverse of rotate_vector: undo Rz*Ry*Rx rotation."""
    cos_r = math.cos(-rot[2]); sin_r = math.sin(-rot[2])
    rz_inv = np.array([[cos_r, -sin_r, 0], [sin_r, cos_r, 0], [0, 0, 1]])
    cos_y = math.cos(-rot[1]); sin_y = math.sin(-rot[1])
    ry_inv = np.array([[cos_y, 0, sin_y], [0, 1, 0], [-sin_y, 0, cos_y]])
    cos_p = math.cos(-rot[0]); sin_p = math.sin(-rot[0])
    rx_inv = np.array([[1, 0, 0], [0, cos_p, -sin_p], [0, sin_p, cos_p]])
    return rx_inv @ ry_inv @ rz_inv @ vec


# Helper to get random unit vector
def random_unit_vector():
    vec = np.random.normal(0, 1, dims)
    norm = np.linalg.norm(vec)
    if norm == 0:
        return np.array([1] + [0] * (dims - 1))
    return vec / norm


# Barnes-Hut for gravity (adapted from research-grade implementations)
def TreeWalk(node, node0, thetamax=0.5, G=1.0):
    """
    Adds the contribution to the field at node0's point due to particles in node.
    Calling this with the topnode as node will walk the tree to calculate the total field at node0.
    Source: Adapted from https://mikegrudic.wordpress.com/2017/07/11/a-simple-and-pythonic-barnes-hut-treecode/ with 3D modifications.
    Citation: Barnes, J., & Hut, P. (1986). A hierarchical O(N log N) force-calculation algorithm. Nature, 324(6096), 446-449.
    """
    dx = node.COM - node0.COM  # vector between nodes' centres of mass
    r = np.sqrt(np.sum(dx ** 2))  # distance between them
    if r > 0:
        # if the node only has one particle or theta is small enough,
        #  add the field contribution to value stored in node.g
        if (len(node.children) == 0) or (node.size / r < thetamax):
            node0.g += G * node.mass * dx / r ** 3
        else:
            # otherwise split up the node and repeat
            for c in node.children: TreeWalk(c, node0, thetamax, G)


class OctNode:
    """Stores the data for an octree node, and spawns its children if possible. Adapted for 3D."""

    def __init__(self, center, size, masses, points, ids, leaves=None, depth=0):
        if leaves is None:
            leaves = []
        self.center = center  # center of the node's box
        self.size = size  # maximum side length of the box
        self.children = []  # start out assuming that the node has no children

        Npoints = len(points)

        if Npoints == 1:
            # if we're down to one point, we need to store stuff in the node
            leaves.append(self)
            self.COM = points[0]
            self.mass = masses[0]
            self.ids = [ids[0]]
            self.g = np.zeros(dims)  # at each point, we will want the gravitational field
        else:
            spread = np.max(np.max(points, axis=0) - np.min(points, axis=0))
            if depth < 50 and spread >= 1e-8 * self.size:
                self.GenerateChildren(points, masses, ids, leaves,
                                      depth + 1)  # if we have at least 2 points in the node,
                # spawn its children

                # now we can sum the total mass and center of mass hierarchically, visiting each point once!
                com_total = np.zeros(dims)  # running total for mass moments to get COM
                m_total = 0.  # running total for masses
                for c in self.children:
                    m, com = c.mass, c.COM
                    m_total += m
                    com_total += com * m  # add the moments of each child
                self.mass = m_total
                if self.mass == 0:
                    self.COM = self.center
                else:
                    self.COM = com_total / self.mass
            else:
                # Treat as leaf with multiple points
                leaves.append(self)
                self.mass = np.sum(masses)
                if self.mass > 0:
                    com_total = np.sum(points * masses[:, np.newaxis], axis=0)
                    self.COM = com_total / self.mass
                else:
                    self.COM = self.center
                self.ids = ids
                self.g = np.zeros(dims)

    def GenerateChildren(self, points, masses, ids, leaves, depth):
        """Generates the node's children in 3D (octants)"""
        octant_index = (points > self.center)  # does all comparisons needed to determine points' octants
        for i in range(2):  # looping over the 8 octants
            for j in range(2):
                for k in range(2):
                    in_octant = np.all(octant_index == np.bool_([i, j, k]), axis=1)
                    if not np.any(in_octant): continue  # if no particles, don't make a node
                    dx = 0.5 * self.size * (np.array([i, j, k]) - 0.5)  # offset between parent and child box centers
                    self.children.append(OctNode(self.center + dx,
                                                 self.size / 2,
                                                 masses[in_octant],
                                                 points[in_octant],
                                                 ids[in_octant],
                                                 leaves, depth=depth))


def GravAccel(points, masses, thetamax=0.5, G=1.):
    if len(points) < 2:
        return np.zeros_like(points)
    center = (np.max(points, axis=0) + np.min(points, axis=0)) / 2  # center of bounding box
    topsize = np.max(np.max(points, axis=0) - np.min(points, axis=0))  # size of bounding box
    topsize = max(topsize, 1e-10)  # Prevent zero-size tree when all particles overlap
    leaves = []  # want to keep track of leaf nodes
    topnode = OctNode(center, topsize, masses, points, np.arange(len(masses)), leaves)  # build the tree

    accel = np.empty_like(points)
    for leaf in leaves:
        TreeWalk(topnode, leaf, thetamax, G)  # do field summation
        for id_ in leaf.ids:
            accel[id_] = leaf.g  # get the stored acceleration

    return accel


# Function for relativistic velocity update — proper 4-momentum formalism
# Ref: Jackson "Classical Electrodynamics" §12.1; Landau & Lifshitz "Classical Theory of Fields" §9
def relativistic_velocity_update(v, F, dt, m0, c):
    if not np.all(np.isfinite(v)):
        v = np.zeros_like(v)
    if not np.all(np.isfinite(F)):
        F = np.zeros_like(F)
    if m0 <= 0 or dt == 0:
        return v
    # === 4-momentum method: dp/dt = F, where p = gamma*m0*v ===
    # This is Lorentz-covariant and automatically enforces v < c.
    # Step 1: Compute current relativistic momentum p = gamma * m0 * v
    v2 = np.dot(v, v)
    c2 = c * c
    beta2 = min(v2 / c2, 1.0 - 1e-12)
    gamma = 1.0 / np.sqrt(1.0 - beta2)
    gamma = min(gamma, 1e8)
    p = gamma * m0 * v
    # Step 2: Update momentum: p_new = p + F * dt (exact relativistic EOM)
    p_new = p + F * dt
    p_new = np.nan_to_num(p_new, nan=0.0, posinf=1e30, neginf=-1e30)
    # Step 3: Recover velocity from momentum: v = p / (m0 * gamma_new)
    # where gamma_new = sqrt(1 + |p_new|^2 / (m0*c)^2)
    p2 = np.dot(p_new, p_new)
    m0c = m0 * c
    gamma_new = np.sqrt(1.0 + p2 / (m0c * m0c))
    gamma_new = min(gamma_new, 1e8)
    v_new = p_new / (m0 * gamma_new)
    # Safety: v should be < c by construction, but clamp for numerical safety
    v_new_norm = np.linalg.norm(v_new)
    if v_new_norm >= c:
        v_new = v_new * (c * (1.0 - 1e-10) / v_new_norm)
    return v_new


# === Nuclear Physics: Binding Energy & Reactions ===
# Enhanced Weizsäcker SEMF with shell corrections, Wigner term, surface-symmetry
# Ref: Myers & Swiatecki (1966); Möller et al. (2016) ADNDT 109-110, 1-204
_aV = 15.77   # volume term (Möller 2016 fit)
_aS = 18.34   # surface term
_aC = 0.711   # Coulomb term (CODATA e²/(4πε₀r₀))
_aA = 23.21   # asymmetry (volume symmetry) term
_aSS = 0.0    # surface-symmetry correction (set below)
_aP = 12.0    # pairing term
_aW = 30.0    # Wigner term coefficient

# Magic numbers: proton or neutron shells that are fully closed
_MAGIC_NUMBERS = frozenset({2, 8, 20, 28, 50, 82, 126})

def _shell_correction_MeV(N_or_Z):
    """Shell correction energy from proximity to magic numbers.
    Nuclei at magic numbers gain extra binding (~1-3 MeV per magic closure).
    Ref: Strutinsky (1967) Nucl. Phys. A95, 420; empirical fit to AME2020."""
    if N_or_Z in _MAGIC_NUMBERS:
        return 2.5  # Extra binding at closed shell
    # Proximity bonus: nuclei near magic numbers get partial correction
    min_dist = min(abs(N_or_Z - m) for m in _MAGIC_NUMBERS)
    if min_dist <= 3:
        return 2.5 * math.exp(-0.5 * min_dist * min_dist)
    return 0.0

def binding_energy_MeV(Z, A):
    """Enhanced semi-empirical mass formula with shell corrections, Wigner term,
    surface-symmetry, and deformation energy.
    Returns total nuclear binding energy in MeV.
    Accuracy: ~0.5% for stable nuclei (vs ~2% for basic SEMF)."""
    if A <= 0 or Z < 0 or Z > A:
        return 0.0
    N = A - Z
    A13 = A ** (1.0 / 3.0)
    A23 = A13 * A13
    I = (N - Z) / A  # Isospin asymmetry parameter
    # Volume term
    B = _aV * A
    # Surface term
    B -= _aS * A23
    # Coulomb term (including exchange correction: -0.76 * Z^(2/3) / A^(1/3))
    B -= _aC * Z * (Z - 1) / A13
    B -= 0.76 * _aC * (Z ** (2.0/3.0)) / A13  # Coulomb exchange (Nolen-Schiffer)
    # Volume asymmetry term
    B -= _aA * (N - Z) ** 2 / A
    # Surface-symmetry term: reduces asymmetry penalty for surface nucleons
    # Ref: Danielewicz & Lee (2009) NPA 818, 36
    B += 45.0 * I * I * A23  # Surface-symmetry correction
    # Wigner term: extra binding for N=Z nuclei (T=0 np pairing)
    # Ref: Satula et al. (1997) PLB 407, 103
    if A > 0:
        B += _aW * math.exp(-4.0 * abs(N - Z) / A) / A
    # Pairing term (improved: BCS-type with smooth cutoff)
    if Z % 2 == 0 and N % 2 == 0:
        B += _aP / math.sqrt(A)
    elif Z % 2 == 1 and N % 2 == 1:
        B -= _aP / math.sqrt(A)
    # Shell corrections for magic numbers
    B += _shell_correction_MeV(Z) + _shell_correction_MeV(N)
    # Deformation energy: prolate/oblate nuclei between magic numbers lose binding
    # Ref: Strutinsky shell-correction method
    if A > 16:
        # Midshell nuclei (far from magic numbers) have ground-state deformation
        z_dist = min(abs(Z - m) for m in _MAGIC_NUMBERS if m <= 126)
        n_dist = min(abs(N - m) for m in _MAGIC_NUMBERS if m <= 126)
        # Deformation reduces binding by ~0.5-2 MeV for midshell nuclei
        midshell = min(z_dist, n_dist)
        if midshell > 5:
            B -= 0.3 * math.log(midshell)
    return max(B, 0.0)

def binding_energy_per_nucleon(Z, A):
    if A <= 0:
        return 0.0
    return binding_energy_MeV(Z, A) / A

# He-4 binding energy (real: 28.296 MeV)
_BE_alpha = binding_energy_MeV(2, 4)

def Q_alpha_MeV(Z, A):
    """Q-value for alpha decay: Parent(Z,A) â†’ Daughter(Z-2,A-4) + He-4."""
    if Z < 2 or A < 4:
        return -1e6
    return binding_energy_MeV(Z - 2, A - 4) + _BE_alpha - binding_energy_MeV(Z, A)

_mn_MeV = 939.565   # neutron mass in MeV/cÂ²
_mp_MeV = 938.272   # proton mass in MeV/cÂ²
_me_MeV = 0.511     # electron mass in MeV/cÂ²

def Q_beta_minus_MeV(Z, A):
    """Q-value for beta- decay: (Z,A) â†’ (Z+1,A) + e- + anti_nu_e."""
    return binding_energy_MeV(Z + 1, A) - binding_energy_MeV(Z, A) + (_mn_MeV - _mp_MeV - _me_MeV)

def Q_beta_plus_MeV(Z, A):
    """Q-value for beta+ decay: (Z,A) â†’ (Z-1,A) + e+ + nu_e."""
    if Z < 1:
        return -1e6
    return binding_energy_MeV(Z - 1, A) - binding_energy_MeV(Z, A) + (_mp_MeV - _mn_MeV - _me_MeV)

def Q_electron_capture_MeV(Z, A):
    """Q-value for electron capture: (Z,A) + e- â†’ (Z-1,A) + nu_e."""
    if Z < 1:
        return -1e6
    return binding_energy_MeV(Z - 1, A) - binding_energy_MeV(Z, A) + (_mp_MeV + _me_MeV - _mn_MeV)

def gamow_alpha_rate(Z, A, Q_MeV):
    """Approximate alpha decay rate using Gamow tunneling factor."""
    if Q_MeV <= 0 or Z < 2 or A < 4:
        return 0.0
    Z_d = Z - 2  # daughter Z
    # Gamow factor: log10(lambda) â‰ˆ a + b * Z_d / sqrt(Q)
    # Geiger-Nuttall law: log10(t_half) = a * Z / sqrt(E_alpha) + b
    E_alpha = Q_MeV * (A - 4) / A  # KE of alpha in CM frame
    if E_alpha <= 0:
        return 0.0
    # Simplified Geiger-Nuttall: log10(lambda) â‰ˆ -1.5 * Z_d / sqrt(E_alpha) + 20
    log_rate = -1.5 * Z_d / math.sqrt(E_alpha) + 20.0
    log_rate = max(min(log_rate, 30), -30)  # clamp
    return 10.0 ** log_rate

def fissility_parameter(Z, A):
    """ZÂ²/A parameter: nuclei with ZÂ²/A > ~47 are fissile."""
    if A <= 0:
        return 0.0
    return Z * Z / A

def gamow_fusion_probability(Z1, Z2, A1, A2, KE_cm_MeV):
    """Gamow tunneling probability for two nuclei to fuse.
    Uses WKB barrier penetration: P ∝ exp(-2π η) where η = Sommerfeld parameter.
    η = Z1·Z2·e²/(ℏ·v) = Z1·Z2·√(μ·c²/(2·E_cm)) · α
    where α ≈ 1/137 is the fine-structure constant.
    Returns probability in [0, 1]."""
    if KE_cm_MeV <= 0 or Z1 <= 0 or Z2 <= 0:
        return 0.0
    # Reduced mass in MeV/c²
    m1_MeV = A1 * 931.494  # AMU to MeV/c²
    m2_MeV = A2 * 931.494
    mu_MeV = m1_MeV * m2_MeV / (m1_MeV + m2_MeV)
    # Sommerfeld parameter: η = Z1·Z2·√(μ·c²/(2·E)) · (e²/(ℏ·c))
    # e²/(ℏ·c) = α ≈ 1/137.036, and √(μc²/(2E)) has units 1/velocity in natural units
    # η = α · Z1 · Z2 · √(μ_MeV / (2 · E_cm_MeV)) · c/v → simplified:
    # η = Z1 · Z2 · α · √(μ_MeV / (2 · KE_cm_MeV))
    alpha_fs = 1.0 / 137.036
    eta = Z1 * Z2 * alpha_fs * math.sqrt(mu_MeV / (2.0 * KE_cm_MeV))
    # Gamow factor: P_tunnel ∝ exp(-2π η)
    exponent = 2.0 * math.pi * eta
    exponent = min(exponent, 500.0)  # prevent underflow
    P_gamow = math.exp(-exponent)
    # S-factor enhancement: astrophysical S-factor captures nuclear physics
    # For light nuclei S ~ 1-100 keV·barn; heavier nuclei much smaller
    # Approximate: S decreases with Z1·Z2 product
    S_factor = math.exp(-0.1 * Z1 * Z2)  # phenomenological suppression for heavy-ion
    return min(P_gamow * S_factor, 1.0)

def electron_screening_correction(Z1, Z2, n_electrons):
    """Electron screening reduces the effective Coulomb barrier for fusion.
    U_e ≈ 1.32 · (Z1 + Z2)^(5/3) · Z_eff^(1/3) eV (Salpeter 1954).
    Returns screening energy in MeV that should be subtracted from barrier."""
    if n_electrons <= 0:
        return 0.0
    # Debye-Hückel screening: U_e in eV
    Z_sum = Z1 + Z2
    # Salpeter weak screening: U_e ≈ 1.32 * Z1 * Z2 * (Z_sum)^(1/3) eV
    # for typical stellar plasma conditions
    U_e_eV = 1.32 * Z1 * Z2 * (Z_sum + n_electrons) ** (1.0 / 3.0)
    return U_e_eV * 1e-6  # convert eV to MeV

_NEUTRON_HALF_LIFE_S = 614.6  # Free neutron half-life in seconds (10.24 min)
_NEUTRON_DECAY_LAMBDA = math.log(2) / _NEUTRON_HALF_LIFE_S  # decay constant

def wavelength_to_rgb(wavelength_nm):
    """Convert photon wavelength (nm) to approximate visible RGB color.
    Based on CIE 1931 approximation by Dan Bruton.
    Returns (R, G, B, A) tuple with values 0-255."""
    w = wavelength_nm
    if w < 380:
        return (120, 0, 180, 200)    # UV — faint violet
    elif w < 440:
        t = (w - 380) / (440 - 380)
        r = int(255 * (1 - t) * 0.6)
        return (r, 0, 255, 255)
    elif w < 490:
        t = (w - 440) / (490 - 440)
        return (0, int(255 * t), 255, 255)
    elif w < 510:
        t = (w - 490) / (510 - 490)
        return (0, 255, int(255 * (1 - t)), 255)
    elif w < 580:
        t = (w - 510) / (580 - 510)
        return (int(255 * t), 255, 0, 255)
    elif w < 645:
        t = (w - 580) / (645 - 580)
        return (255, int(255 * (1 - t)), 0, 255)
    elif w < 780:
        return (255, 0, 0, 255)
    else:
        return (180, 0, 0, 150)       # IR — faint red

