# Noble gas Z values (full outer shells - chemically inert)
NOBLE_GAS_Z = {2, 10, 18, 36, 54, 86, 118}

def valence_electrons(Z):
    """Return number of valence electrons for element Z."""
    if Z in NOBLE_GAS_Z:
        return 0
    if Z <= 2: return Z
    shell_config = [2, 8, 8, 18, 18, 32, 32]
    remaining = Z
    for cap in shell_config:
        if remaining <= cap:
            return remaining
        remaining -= cap
    return remaining

def max_bonds(Z):
    """Maximum covalent bonds for element Z.  Accounts for common valences,
    expanded octets (period 3+), and hypervalent species."""
    _MAX_BONDS_TABLE = {
        1: 1, 2: 0, 3: 1, 4: 2, 5: 3, 6: 4, 7: 3, 8: 2, 9: 1, 10: 0,
        11: 1, 12: 2, 13: 3, 14: 4, 15: 5, 16: 6, 17: 1, 18: 0,
        19: 1, 20: 2, 26: 6, 29: 4, 30: 4, 35: 1, 53: 1, 54: 0,
    }
    if Z in _MAX_BONDS_TABLE:
        return _MAX_BONDS_TABLE[Z]
    v = valence_electrons(Z)
    if Z <= 2:
        return max(0, 2 - v)
    if Z > 18:
        return min(v, 6)
    return min(v, 8 - v) if v > 0 else 0

