# === Covalent Bond Radii (pm) â€” Cordero et al. 2008 / Pyykko 2009 ===
COVALENT_RADIUS_PM = {
    1: 31, 2: 28, 3: 128, 4: 96, 5: 84, 6: 76, 7: 71, 8: 66, 9: 57, 10: 58,
    11: 166, 12: 141, 13: 121, 14: 111, 15: 107, 16: 105, 17: 102, 18: 106,
    19: 203, 20: 176, 21: 170, 22: 160, 23: 153, 24: 139, 25: 139, 26: 132,
    27: 126, 28: 124, 29: 132, 30: 122, 31: 122, 32: 120, 33: 119, 34: 120,
    35: 120, 36: 116, 37: 220, 38: 195, 39: 190, 40: 175, 47: 145, 53: 139,
    54: 140, 79: 136, 82: 146,
}

def covalent_bond_length_pm(Z1, Z2):
    """Expected single-bond length in picometers = sum of covalent radii."""
    r1 = COVALENT_RADIUS_PM.get(Z1, 150)
    r2 = COVALENT_RADIUS_PM.get(Z2, 150)
    return r1 + r2

def estimate_bond_energy_eV(Z1, Z2, order=1):
    """Return bond dissociation energy in eV from real data tables.
    Falls back to Pauling estimate only for pairs not in the table."""
    key = (min(Z1, Z2), max(Z1, Z2))
    if order >= 3 and key in BOND_ENERGY_TRIPLE_eV:
        return BOND_ENERGY_TRIPLE_eV[key]
    if order >= 2 and key in BOND_ENERGY_DOUBLE_eV:
        return BOND_ENERGY_DOUBLE_eV[key]
    if key in BOND_ENERGY_SINGLE_eV:
        return BOND_ENERGY_SINGLE_eV[key]
    # Pauling fallback: geometric mean of homonuclear energies + ionic term
    e_aa = BOND_ENERGY_SINGLE_eV.get((key[0], key[0]), 2.0)
    e_bb = BOND_ENERGY_SINGLE_eV.get((key[1], key[1]), 2.0)
    en1 = ELECTRONEGATIVITY.get(Z1, 1.5)
    en2 = ELECTRONEGATIVITY.get(Z2, 1.5)
    return math.sqrt(e_aa * e_bb) + (en1 - en2) ** 2 * 0.5

def preferred_bond_order(Z1, Z2):
    """Return the most likely bond order for a pair of elements in their
    ground-state molecular form (e.g. Nâ‰¡N=3, O=O=2, C-H=1)."""
    key = (min(Z1, Z2), max(Z1, Z2))
    if key in BOND_ENERGY_TRIPLE_eV:
        v1, v2 = valence_electrons(Z1), valence_electrons(Z2)
        mb1, mb2 = max_bonds(Z1), max_bonds(Z2)
        if mb1 >= 3 and mb2 >= 3:
            return 3
    if key in BOND_ENERGY_DOUBLE_eV:
        v1, v2 = valence_electrons(Z1), valence_electrons(Z2)
        mb1, mb2 = max_bonds(Z1), max_bonds(Z2)
        if mb1 >= 2 and mb2 >= 2:
            return 2
    return 1

def is_ionic_bond(Z1, Z2):
    """True if electronegativity difference suggests ionic bond (>1.7)."""
    en1 = ELECTRONEGATIVITY.get(Z1, 1.5)
    en2 = ELECTRONEGATIVITY.get(Z2, 1.5)
    return abs(en1 - en2) > 1.7

