# LOD threshold: when atom's apparent screen size (vis_radius / zoom) < this, use solid sphere
LOD_SOLID_THRESHOLD = 0.005  # Below this fraction of screen, collapse to single sphere
# Human-scale zoom: 1 vis unit â‰ˆ 0.6 fm, 1 meter â‰ˆ 1.67e15 vis units
HUMAN_SCALE_ZOOM = 1e6  # Zoom level for macroscopic viewing


class Atom(Particle):
    def __init__(self, symbol, A, sub_particles, center):
        # Compute Z
        if symbol.startswith('E') and symbol[1:].isdigit():
            Z = int(symbol[1:])
        else:
            matching = [z for z, d in atom_data.items() if d['symbol'] == symbol]
            Z = matching[0] if matching else 0  # Default to 0 if not found

        # Compute decay_prob
        if Z in atom_data:
            std_A = round(atom_data[Z]['atomic_weight'])
            if A == std_A:
                decay_prob = 0.0
            else:
                decay_prob = 1e-5 if Z > 118 else 1e-10
        else:
            decay_prob = 1e-5 if Z > 118 else 1e-10

        super().__init__(type_particle=f"{symbol}-{A}", pos=center, mass=sum(p.mass for p in sub_particles), charge=0.0,
                         spin=0.0, decay_prob=decay_prob, vel=np.mean([p.vel for p in sub_particles], axis=0),
                         energy_kin=sum(p.energy_kin for p in sub_particles),
                         energy_rot=sum(p.energy_rot for p in sub_particles),
                         color=(random.randint(100, 255), random.randint(100, 255), random.randint(100, 255), 255))
        self.sub_particles = sub_particles
        for sp in self.sub_particles:
            sp.in_atom = True
        self.bonds = []
        self.is_atom = True
        self.Z = Z
        self.A = A
        self.atomic_radius = atomic_radii.get(Z, 150) * 1e-12  # in meters
        self.additional_scale = 1  # To amplify atomic scale for visualization
        self.assign_positions()
        self.assign_bonds()
        # Atom bulk thermal velocity (small drift for the whole atom)
        atom_vel = np.random.normal(0, 15.0, dims)
        for sp in self.sub_particles:
            sp.vel += atom_vel
        self.vel = np.mean([sp.vel for sp in self.sub_particles], axis=0)
        self.excitation_energy = 0.0  # Atomic excitation energy (J) for photon emission/absorption
        self.molecular_bonds = []  # List of (other_atom, bond_info_dict) for chemical bonds
        self.pyscf_mf = None  # PySCF mean-field object
        self.td_mf = None  # For time-dependent

    def compute_pyscf(self):
        # Use PySCF for accurate electronic structure - enhanced with TD for radiation/dynamics
        if pyscf is not None and gto is not None and scf is not None:
            atom_str = ''
            for sp in self.sub_particles:
                if getattr(sp, 'base_type', '') in ('proton', 'neutron'):
                    pos = ' '.join(map(str, sp.pos))
                    atom_str += f'H {pos}; '  # Placeholder, use actual symbols
            mol = gto.M(atom=atom_str.strip('; '), basis='sto3g')
            self.pyscf_mf = scf.RHF(mol)
            self.pyscf_mf.kernel()
            # Add time-dependent for realism (e.g., excitations/radiation)
            if TDHF is not None:
                self.td_mf = TDHF(self.pyscf_mf)
                self.td_mf.kernel()
        # If not available, skip or log

    # Real charge radii (fm) - PDG/CODATA values
    PROTON_R_FM = 0.8414    # proton charge radius (CODATA 2022)
    NEUTRON_R_FM = 0.8440   # neutron matter radius (approximate)
    R0_FM = 1.2             # nuclear radius constant r0
    VIS_NUC_R0 = 2.0        # base nuclear radius in vis units
    VIS_SHELL_R0 = 15.0     # first-shell base radius in vis units
    VIS_FM = VIS_NUC_R0 / R0_FM  # vis units per fm
    PROTON_VIS_R = PROTON_R_FM * VIS_FM    # ~1.40 vis units
    NEUTRON_VIS_R = NEUTRON_R_FM * VIS_FM  # ~1.41 vis units
    ELECTRON_VIS_R = 0.05   # point particle, tiny dot
    NUCLEON_MIN_SEP = 2.0 * PROTON_VIS_R * 0.85  # minimum center-to-center (~2.38)

    def assign_positions(self):
        # Visualization-friendly scales for atom internals
        # Real physics: nucleus ~1e-15 m, electrons ~1e-10 m (ratio 100000:1)
        # This ratio makes atoms invisible in the renderer, so we compress it
        # while preserving correct shell structure (Aufbau) and relative sizes
        nucleus_radius = self.VIS_NUC_R0 * max(self.A, 1) ** (1.0 / 3.0)
        electrons = [p for p in self.sub_particles if getattr(p, 'base_type', '') in ('electron', 'positron')]
        nucleons = [p for p in self.sub_particles if getattr(p, 'base_type', '') in ('proton', 'neutron', 'anti_proton', 'anti_neutron')]
        # Nucleons in nucleus - rejection sampling with minimum separation
        placed_positions = []
        for p in nucleons:
            for attempt in range(200):
                u = random.random()
                r = nucleus_radius * u ** (1.0 / 3.0)
                direction = random_unit_vector()
                candidate = self.pos + r * direction
                too_close = False
                for pp in placed_positions:
                    if np.linalg.norm(candidate - pp) < self.NUCLEON_MIN_SEP:
                        too_close = True
                        break
                if not too_close:
                    break
            p.pos = candidate
            placed_positions.append(candidate.copy())
            # Small random velocity for nuclear vibration
            p.vel = np.random.normal(0, 0.5, dims)
            # Create constituent quarks inside this nucleon (uud for proton, udd for neutron)
            p.constituent_quarks = []
            p_bt = getattr(p, 'base_type', '')
            if p_bt in ('proton', 'anti_proton'):
                q_types = ['up_quark', 'up_quark', 'down_quark']
            elif p_bt in ('neutron', 'anti_neutron'):
                q_types = ['up_quark', 'down_quark', 'down_quark']
            else:
                q_types = []
            qcd_colors = ['r', 'g', 'b']
            for qi, qt_name in enumerate(q_types):
                q = Particle(qt_name, pos=p.pos + np.random.normal(0, 0.3, dims))
                q.in_atom = True
                q.vel = np.random.normal(0, 5.0, dims)
                q.color_charge = qcd_colors[qi % 3]  # Assign r, g, b for color singlet
                p.constituent_quarks.append(q)

        # Electrons in shells using Aufbau filling order
        aufbau_order = [
            (1, 0, 2), (2, 0, 2), (2, 1, 6), (3, 0, 2), (3, 1, 6),
            (4, 0, 2), (3, 2, 10), (4, 1, 6), (5, 0, 2), (4, 2, 10),
            (5, 1, 6), (6, 0, 2), (4, 3, 14), (5, 2, 10), (6, 1, 6),
            (7, 0, 2), (5, 3, 14), (6, 2, 10), (7, 1, 6)
        ]
        e_idx = 0
        for n, l, max_electrons in aufbau_order:
            if e_idx >= len(electrons):
                break
            n_in_shell = min(max_electrons, len(electrons) - e_idx)
            # Slater shielding for Z_eff (same physics, just different radii)
            inner_electrons = e_idx
            sigma = 0.35 * max(n_in_shell - 1, 0) + 0.85 * min(inner_electrons, 2 * (n - 1))
            if l >= 2:
                sigma += 1.0 * max(0, inner_electrons - 2 * (n - 1))
            Z_eff = max(self.Z - sigma, 1.0)
            # Visualization shell radius: preserves n^2/Z_eff scaling
            r_shell = self.VIS_SHELL_R0 * n ** 2 / Z_eff
            for j in range(n_in_shell):
                p = electrons[e_idx]
                r = r_shell * (1.0 + 0.1 * (random.random() - 0.5))
                direction = random_unit_vector()
                p.pos = self.pos + r * direction
                # Store target shell radius for radial spring restoring force
                p.target_shell_r = r_shell
                # Orbital velocity: Bohr model v = Z_eff * alpha * c / n
                # Scaled to vis units: period T = 2π r / v, Kepler-like T ~ r^1.5
                r_vec = p.pos - self.pos
                r_norm = np.linalg.norm(r_vec)
                if r_norm > 0:
                    orbital_period = 2.0 * (r_norm / self.VIS_SHELL_R0) ** 1.5
                    v_mag = 2 * math.pi * r_norm / max(orbital_period, 0.1)
                    p.target_orbital_v = v_mag
                    axis = np.array([0, 0, 1]) if abs(np.dot(r_vec / r_norm, [0, 0, 1])) < 0.99 else np.array([1, 0, 0])
                    perp = np.cross(r_vec / r_norm, axis)
                    perp /= np.linalg.norm(perp) + EPSILON
                    p.vel = v_mag * perp
                else:
                    p.target_orbital_v = 1.0
                e_idx += 1
        # Sync prev_pos so first-frame rendering is correct (no lerp to old center)
        for sp in self.sub_particles:
            sp.prev_pos = sp.pos.copy()
            for q in getattr(sp, 'constituent_quarks', []):
                q.prev_pos = q.pos.copy()

    def assign_bonds(self):
        protons = [p for p in self.sub_particles if getattr(p, 'base_type', '') in ('proton', 'anti_proton')]
        neutrons = [p for p in self.sub_particles if getattr(p, 'base_type', '') in ('neutron', 'anti_neutron')]
        electrons = [p for p in self.sub_particles if getattr(p, 'base_type', '') in ('electron', 'positron')]
        # Bonds in nucleus: connect all nucleons
        nucleons = protons + neutrons
        for i in range(len(nucleons)):
            for j in range(i + 1, len(nucleons)):
                if random.random() < 0.5:  # random to not overload
                    self.bonds.append((nucleons[i], nucleons[j]))
        # Bonds for electrons: connect each to a random proton
        for e in electrons:
            if protons:
                p = random.choice(protons)
                self.bonds.append((p, e))

    def _count_nucleons(self):
        """Return (Z, N, A) from actual sub-particles."""
        protons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') in ('proton', 'anti_proton')]
        neutrons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') in ('neutron', 'anti_neutron')]
        return len(protons), len(neutrons), len(protons) + len(neutrons)

    def _rebuild_atom(self, particles):
        """Rebuild atom identity after nuclear change. Updates Z, symbol, type, bonds."""
        Z, N, A = self._count_nucleons()
        self.Z = Z
        self.A = A
        electrons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') in ('electron', 'positron')]
        if Z in atom_data:
            symbol = atom_data[Z]['symbol']
        else:
            symbol = f'E{Z}'
        self.base_type = f"{symbol}-{A}"
        self.type = f"{symbol}-{A}_{Particle.instance_count}"
        self.mass = sum(sp.mass for sp in self.sub_particles)
        self.charge = (Z - len(electrons)) * e
        Q_a = Q_alpha_MeV(Z, A)
        Q_bm = Q_beta_minus_MeV(Z, A)
        Q_bp = Q_beta_plus_MeV(Z, A)
        self.radioactive = (Q_a > 0 and Z > 60) or Q_bm > 2.0 or Q_bp > 2.0 or fissility_parameter(Z, A) > 47
        self.bonds = []
        self.assign_bonds()

    def nuclear_decay(self, particles, dt):
        """Check and perform nuclear decays: alpha, beta-, beta+/EC, fission."""
        Z, N, A = self._count_nucleons()
        if A < 2:
            return
        # === Alpha decay (Z > 60, Q_alpha > 0) ===
        if Z > 2 and A > 4:
            Q_a = Q_alpha_MeV(Z, A)
            if Q_a > 0 and Z > 60:
                rate = gamow_alpha_rate(Z, A, Q_a)
                prob = 1.0 - math.exp(-rate * dt) if rate * dt < 50 else 1.0
                if random.random() < prob:
                    self._do_alpha_decay(particles, Q_a)
                    return
        # === Beta-minus decay (neutron-rich) ===
        if N > 0 and A > 1:
            Q_bm = Q_beta_minus_MeV(Z, A)
            if Q_bm > 0:
                rate_bm = 1e-3 * Q_bm**5 if Q_bm < 20 else 1e10
                rate_bm = min(rate_bm, 1e15)
                prob_bm = 1.0 - math.exp(-rate_bm * dt) if rate_bm * dt < 50 else 1.0
                stability_ratio = 1.0 + 0.015 * A**(2.0/3.0)
                if Z > 0 and N / Z > stability_ratio and random.random() < prob_bm:
                    self._do_beta_minus(particles, Q_bm)
                    return
        # === Beta-plus / Electron capture (proton-rich) ===
        if Z > 1 and A > 1:
            Q_ec = Q_electron_capture_MeV(Z, A)
            if Q_ec > 0:
                rate_ec = 1e-3 * Q_ec**5 if Q_ec < 20 else 1e10
                rate_ec = min(rate_ec, 1e15)
                prob_ec = 1.0 - math.exp(-rate_ec * dt) if rate_ec * dt < 50 else 1.0
                stability_ratio = 1.0 + 0.015 * A**(2.0/3.0)
                if N > 0 and Z > 0 and N / Z < 1.0 / stability_ratio and random.random() < prob_ec:
                    electrons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') == 'electron']
                    if electrons:
                        self._do_electron_capture(particles, Q_ec, electrons[0])
                    else:
                        self._do_beta_plus(particles, Q_ec)
                    return
        # === Spontaneous fission (very heavy nuclei) ===
        if A > 230 and fissility_parameter(Z, A) > 47:
            fiss_rate = 1e-15 * (fissility_parameter(Z, A) - 47)**3
            prob_fiss = 1.0 - math.exp(-fiss_rate * dt) if fiss_rate * dt < 50 else 1.0
            if random.random() < prob_fiss:
                self._do_fission(particles)
                return

    def _do_alpha_decay(self, particles, Q_MeV):
        """Emit alpha particle (2p + 2n), create daughter atom."""
        protons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') == 'proton']
        neutrons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') == 'neutron']
        if len(protons) < 2 or len(neutrons) < 2:
            return
        alpha_parts = protons[:2] + neutrons[:2]
        for sp in alpha_parts:
            sp.in_atom = False
            self.sub_particles.remove(sp)
        alpha_pos = self.pos + random_unit_vector() * 5.0
        alpha = Particle('Alpha_particle', pos=alpha_pos)
        alpha.pos = alpha_pos
        Q_J = Q_MeV * MeV_to_J
        alpha_KE = Q_J * (len(self.sub_particles)) / (len(self.sub_particles) + 4 + EPSILON)
        v_alpha = math.sqrt(2 * alpha_KE / (alpha.mass + EPSILON))
        alpha.vel = random_unit_vector() * min(v_alpha, c * 0.1)
        alpha.energy_kin = alpha_KE
        particles.append(alpha)
        gamma_E = Q_J - alpha_KE
        if gamma_E > 0:
            gamma = Particle('photon', pos=self.pos.copy(), vel=random_unit_vector() * c)
            gamma.energy_kin = gamma_E
            particles.append(gamma)
        self.vel -= alpha.mass * alpha.vel / (self.mass + EPSILON)
        self._rebuild_atom(particles)

    def _do_beta_minus(self, particles, Q_MeV):
        """Beta-minus: neutron -> proton + electron + anti_nu_e inside nucleus."""
        neutrons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') == 'neutron']
        if not neutrons:
            return
        n = neutrons[0]
        n.base_type = 'proton'
        n.type = f'proton_{Particle.instance_count}'
        n.mass = particle_data['proton']['mass']
        n.charge = particle_data['proton']['charge']
        n.color = Particle.PARTICLE_COLORS['proton']
        Particle.instance_count += 1
        # Update quarks: neutron(udd) -> proton(uud) - convert one down to up
        for q in n.constituent_quarks:
            if getattr(q, 'base_type', '') == 'down_quark':
                q.base_type = 'up_quark'
                q.type = f'up_quark_{Particle.instance_count}'
                q.mass = particle_data.get('up_quark', particle_data['Alpha_particle'])['mass']
                q.charge = particle_data.get('up_quark', particle_data['Alpha_particle'])['charge']
                q.color = Particle.PARTICLE_COLORS.get('up_quark', (255, 0, 0, 255))
                break
        Q_J = Q_MeV * MeV_to_J
        beta_e = Particle('electron', pos=self.pos + random_unit_vector() * 10.0)
        beta_e.pos = self.pos + random_unit_vector() * 10.0
        e_KE = Q_J * 0.4
        v_e = math.sqrt(2 * e_KE / (beta_e.mass + EPSILON))
        beta_e.vel = random_unit_vector() * min(v_e, c * 0.99)
        beta_e.energy_kin = e_KE
        particles.append(beta_e)
        nu = Particle('anti_electron_neutrino', pos=self.pos.copy(), vel=random_unit_vector() * c)
        nu.pos = self.pos.copy()
        nu.energy_kin = Q_J * 0.55
        particles.append(nu)
        self._rebuild_atom(particles)

    def _do_beta_plus(self, particles, Q_MeV):
        """Beta-plus: proton -> neutron + positron + nu_e inside nucleus."""
        protons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') == 'proton']
        if not protons:
            return
        p = protons[0]
        p.base_type = 'neutron'
        p.type = f'neutron_{Particle.instance_count}'
        p.mass = particle_data['neutron']['mass']
        p.charge = 0.0
        p.color = Particle.PARTICLE_COLORS['neutron']
        Particle.instance_count += 1
        # Update quarks: proton(uud) -> neutron(udd) - convert one up to down
        for q in p.constituent_quarks:
            if getattr(q, 'base_type', '') == 'up_quark':
                q.base_type = 'down_quark'
                q.type = f'down_quark_{Particle.instance_count}'
                q.mass = particle_data.get('down_quark', particle_data['Alpha_particle'])['mass']
                q.charge = particle_data.get('down_quark', particle_data['Alpha_particle'])['charge']
                q.color = Particle.PARTICLE_COLORS.get('down_quark', (0, 0, 255, 255))
                break
        Q_J = Q_MeV * MeV_to_J
        positron = Particle('positron', pos=self.pos + random_unit_vector() * 10.0)
        positron.pos = self.pos + random_unit_vector() * 10.0
        e_KE = Q_J * 0.4
        v_e = math.sqrt(2 * e_KE / (positron.mass + EPSILON))
        positron.vel = random_unit_vector() * min(v_e, c * 0.99)
        positron.energy_kin = e_KE
        particles.append(positron)
        nu = Particle('electron_neutrino', pos=self.pos.copy(), vel=random_unit_vector() * c)
        nu.pos = self.pos.copy()
        nu.energy_kin = Q_J * 0.55
        particles.append(nu)
        self._rebuild_atom(particles)

    def _do_electron_capture(self, particles, Q_MeV, captured_electron):
        """Electron capture: p + e- -> n + nu_e."""
        protons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') == 'proton']
        if not protons:
            return
        p = protons[0]
        p.base_type = 'neutron'
        p.type = f'neutron_{Particle.instance_count}'
        p.mass = particle_data['neutron']['mass']
        p.charge = 0.0
        p.color = Particle.PARTICLE_COLORS['neutron']
        Particle.instance_count += 1
        # Update quarks: proton(uud) -> neutron(udd) - convert one up to down
        for q in p.constituent_quarks:
            if getattr(q, 'base_type', '') == 'up_quark':
                q.base_type = 'down_quark'
                q.type = f'down_quark_{Particle.instance_count}'
                q.mass = particle_data.get('down_quark', particle_data['Alpha_particle'])['mass']
                q.charge = particle_data.get('down_quark', particle_data['Alpha_particle'])['charge']
                q.color = Particle.PARTICLE_COLORS.get('down_quark', (0, 0, 255, 255))
                break
        if captured_electron in self.sub_particles:
            self.sub_particles.remove(captured_electron)
            captured_electron.in_atom = False
            captured_electron.mass = 0
            captured_electron.base_type = 'decayed'
            captured_electron.type = 'decayed'
        Q_J = Q_MeV * MeV_to_J
        nu = Particle('electron_neutrino', pos=self.pos.copy(), vel=random_unit_vector() * c)
        nu.pos = self.pos.copy()
        nu.energy_kin = Q_J
        particles.append(nu)
        xray = Particle('photon', pos=self.pos.copy(), vel=random_unit_vector() * c)
        xray.energy_kin = 1e-15
        particles.append(xray)
        self._rebuild_atom(particles)

    def _do_fission(self, particles):
        """Spontaneous fission: split into two fragments + prompt neutrons."""
        Z, N, A = self._count_nucleons()
        Z1 = int(Z * random.uniform(0.38, 0.50))
        Z2 = Z - Z1
        A1 = int(A * random.uniform(0.38, 0.50))
        A2 = A - A1
        N1 = A1 - Z1
        N2 = A2 - Z2
        n_prompt = random.randint(2, 3)
        if N1 + N2 + n_prompt > N:
            n_prompt = max(0, N - N1 - N2)
        N1 = min(N1, N - n_prompt - N2)
        if N1 < 0:
            N1 = 0
        protons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') == 'proton']
        neutrons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') == 'neutron']
        electrons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') == 'electron']
        frag1_sp = protons[:Z1] + neutrons[:N1] + electrons[:Z1]
        frag2_sp = protons[Z1:Z1+Z2] + neutrons[N1:N1+N2] + electrons[Z1:Z1+Z2]
        prompt_neutrons = neutrons[N1+N2:N1+N2+n_prompt]
        B_parent = binding_energy_MeV(Z, A)
        B_f1 = binding_energy_MeV(Z1, A1)
        B_f2 = binding_energy_MeV(Z2, A2)
        Q_MeV_fiss = B_f1 + B_f2 - B_parent
        Q_J = max(Q_MeV_fiss, 0) * MeV_to_J
        for sp in self.sub_particles:
            sp.in_atom = False
        self.sub_particles = []
        offset1 = random_unit_vector() * 10.0
        offset2 = -offset1
        v_frag = math.sqrt(2 * Q_J * 0.8 / (self.mass + EPSILON))
        for sp in frag1_sp:
            sp.pos = self.pos + offset1 + np.random.normal(0, 1, dims)
        for sp in frag2_sp:
            sp.pos = self.pos + offset2 + np.random.normal(0, 1, dims)
        if len(frag1_sp) >= 2 and Z1 > 0:
            sym1 = atom_data.get(Z1, {}).get('symbol', f'E{Z1}')
            atom1 = Atom(sym1, A1, frag1_sp, self.pos + offset1)
            atom1.vel = random_unit_vector() * min(v_frag, c * 0.05)
            particles.append(atom1)
        else:
            for sp in frag1_sp:
                particles.append(sp)
        if len(frag2_sp) >= 2 and Z2 > 0:
            sym2 = atom_data.get(Z2, {}).get('symbol', f'E{Z2}')
            atom2 = Atom(sym2, A2, frag2_sp, self.pos + offset2)
            atom2.vel = -random_unit_vector() * min(v_frag, c * 0.05)
            particles.append(atom2)
        else:
            for sp in frag2_sp:
                particles.append(sp)
        for pn in prompt_neutrons:
            pn.vel = random_unit_vector() * min(math.sqrt(2 * Q_J * 0.05 / (pn.mass + EPSILON)), c * 0.1)
            particles.append(pn)
        gamma = Particle('photon', pos=self.pos.copy(), vel=random_unit_vector() * c)
        gamma.energy_kin = Q_J * 0.05
        particles.append(gamma)
        self.mass = 0
        self.base_type = 'decayed'
        self.type = 'decayed'
        self.radioactive = False

    def ionization_check(self, particles, dt):
        """Check if a nearby free electron can be captured, or if excess energy ejects one."""
        Z, N, A = self._count_nucleons()
        electrons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') == 'electron']
        n_electrons = len(electrons)
        # Electron capture from environment: if ion (fewer electrons than protons)
        if n_electrons < Z:
            for p in particles:
                if p.is_atom or p.in_atom or getattr(p, 'base_type', '') != 'electron':
                    continue
                r_dist = np.linalg.norm(p.pos - self.pos)
                capture_radius = self.VIS_SHELL_R0 * 3.0
                if r_dist < capture_radius:
                    prob_cap = 0.1 * dt * (capture_radius / (r_dist + 1.0))
                    if random.random() < prob_cap:
                        p.in_atom = True
                        self.sub_particles.append(p)
                        if p in particles:
                            particles.remove(p)
                        self._rebuild_atom(particles)
                        return
        # Ionization: if atom is excited (high KE), can eject outermost electron
        if n_electrons > 0 and self.energy_kin > 0:
            # Use NIST ionization energy if available, else fall back to hydrogen-like
            ionization_E_eV = IONIZATION_ENERGY.get(Z, 13.6)
            ionization_E_J = ionization_E_eV * eV_to_J
            if self.energy_kin > ionization_E_J * 1e10:
                prob_ion = 0.001 * dt
                if random.random() < prob_ion:
                    ejected = electrons[-1]
                    ejected.in_atom = False
                    self.sub_particles.remove(ejected)
                    ejected.pos = self.pos + random_unit_vector() * self.VIS_SHELL_R0 * 4
                    ejected.vel = random_unit_vector() * math.sqrt(2 * ionization_E_J / (ejected.mass + EPSILON))
                    particles.append(ejected)
                    self.energy_kin -= ionization_E_J
                    self._rebuild_atom(particles)
                    return

    def photon_absorption(self, particles, dt):
        """Absorb nearby photons: excite atom or ionize if energy sufficient."""
        Z, N, A = self._count_nucleons()
        electrons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') == 'electron']
        n_e = len(electrons)
        if n_e == 0:
            return
        # Absorption cross section scales with Z (bigger atoms absorb more)
        capture_r = self.VIS_SHELL_R0 * 2.0 * (1 + 0.1 * Z)
        for p in particles:
            if p.is_atom or p.in_atom or getattr(p, 'base_type', '') != 'photon':
                continue
            r_dist = np.linalg.norm(p.pos - self.pos)
            if r_dist > capture_r:
                continue
            photon_E = p.energy_kin
            if photon_E <= 0:
                continue
            # Use NIST ionization energy; estimate excitation as ~75% of ionization (Rydberg approx)
            ionize_E_eV = IONIZATION_ENERGY.get(Z, 13.6)
            ionize_E_J = ionize_E_eV * eV_to_J
            excite_E_eV = ionize_E_eV * 0.75  # First excitation â‰ˆ 75% of ionization for most atoms
            excite_E_J = excite_E_eV * eV_to_J
            # Photoionization: photon energy > ionization energy
            if photon_E > ionize_E_J:
                prob = 0.05 * dt
                if random.random() < prob:
                    ejected = electrons[-1]
                    ejected.in_atom = False
                    self.sub_particles.remove(ejected)
                    excess_E = photon_E - ionize_E_J
                    v_eject = math.sqrt(2 * excess_E / (ejected.mass + EPSILON))
                    ejected.pos = self.pos + random_unit_vector() * self.VIS_SHELL_R0 * 4
                    ejected.vel = random_unit_vector() * min(v_eject, c * 0.99)
                    ejected.energy_kin = excess_E
                    particles.append(ejected)
                    # Remove photon
                    p.mass = 0
                    p.base_type = 'decayed'
                    p.type = 'decayed'
                    p.energy_kin = 0
                    self._rebuild_atom(particles)
                    return
            # Excitation: photon energy matches transition
            elif photon_E > excite_E_J * 0.8 and photon_E < excite_E_J * 1.2:
                prob = 0.1 * dt
                if random.random() < prob:
                    self.excitation_energy += photon_E
                    p.mass = 0
                    p.base_type = 'decayed'
                    p.type = 'decayed'
                    p.energy_kin = 0
                    return
            # Photodisintegration: very high energy photon breaks nucleus
            if A > 2 and photon_E > binding_energy_per_nucleon(Z, A) * MeV_to_J:
                prob = 0.001 * dt
                if random.random() < prob:
                    self._do_photodisintegration(particles, photon_E)
                    p.mass = 0
                    p.base_type = 'decayed'
                    p.type = 'decayed'
                    p.energy_kin = 0
                    return

    def spontaneous_emission(self, particles, dt):
        """De-excite atom by emitting photon. Rate ~ A_Einstein * excitation_energy."""
        if self.excitation_energy <= 0:
            return
        # Spontaneous emission rate: A ~ 1e8 s^-1 for optical transitions (scaled)
        A_rate = 1e8 * (self.Z / 10.0)  # Heavier atoms radiate faster
        prob = 1.0 - math.exp(-A_rate * dt) if A_rate * dt < 50 else 1.0
        if random.random() < prob:
            photon = Particle('photon', pos=self.pos + random_unit_vector() * self.VIS_SHELL_R0 * 2)
            photon.pos = self.pos + random_unit_vector() * self.VIS_SHELL_R0 * 2
            photon.vel = random_unit_vector() * c
            photon.energy_kin = self.excitation_energy
            particles.append(photon)
            self.excitation_energy = 0.0

    def stimulated_emission(self, particles, dt):
        """Stimulated emission: incoming photon matching excitation triggers identical photon emission (laser physics)."""
        if self.excitation_energy <= 0:
            return
        for p in particles:
            if p.is_atom or p.in_atom or getattr(p, 'base_type', '') != 'photon':
                continue
            r_dist = np.linalg.norm(p.pos - self.pos)
            if r_dist > self.VIS_SHELL_R0 * 2.5:
                continue
            photon_E = p.energy_kin
            if photon_E <= 0:
                continue
            # Resonance condition: photon energy must match excitation energy within ~20%
            if abs(photon_E - self.excitation_energy) < self.excitation_energy * 0.2:
                # Einstein B coefficient: stimulated rate ~ spontaneous rate * n_photons
                prob = 0.15 * dt
                if random.random() < prob:
                    # Emit clone photon in same direction as stimulating photon (coherent)
                    new_photon = Particle('photon', pos=self.pos + random_unit_vector() * self.VIS_SHELL_R0)
                    new_photon.vel = p.vel.copy()  # Same direction (coherence)
                    new_photon.energy_kin = self.excitation_energy
                    particles.append(new_photon)
                    self.excitation_energy = 0.0
                    return

    def neutron_capture(self, particles, dt):
        """Capture nearby free neutrons: (Z,A) + n â†’ (Z,A+1) + gamma."""
        Z, N, A = self._count_nucleons()
        sigma_barn = neutron_capture_cross_section_barn(Z, A)
        # Convert barn to vis-unit cross section (1 barn = 1e-24 cm^2)
        # In vis units, capture radius ~ sigma_barn * scaling
        capture_r = self.VIS_NUC_R0 * A**(1.0/3.0) * 3.0
        for p in particles:
            if p.is_atom or p.in_atom or getattr(p, 'base_type', '') != 'neutron':
                continue
            r_dist = np.linalg.norm(p.pos - self.pos)
            if r_dist > capture_r:
                continue
            # Probability scales with cross section and relative velocity
            v_rel = np.linalg.norm(p.vel - self.vel)
            prob = sigma_barn * 1e-6 * dt * max(v_rel, 1.0)
            prob = min(prob, 0.5)
            if random.random() < prob:
                # Neutron absorbed into nucleus
                p.in_atom = True
                self.sub_particles.append(p)
                if p in particles:
                    particles.remove(p)
                # Emit gamma photon with binding energy
                Q_MeV = binding_energy_MeV(Z, A + 1) - binding_energy_MeV(Z, A)
                if Q_MeV > 0:
                    gamma = Particle('photon', pos=self.pos.copy())
                    gamma.pos = self.pos.copy()
                    gamma.vel = random_unit_vector() * c
                    gamma.energy_kin = Q_MeV * MeV_to_J
                    particles.append(gamma)
                self._rebuild_atom(particles)
                # Check if new isotope is fissile (neutron-induced fission)
                Z_new, N_new, A_new = self._count_nucleons()
                if A_new > 200 and fissility_parameter(Z_new, A_new) > 35:
                    self._neutron_induced_fission(particles, dt)
                return

    def proton_capture(self, particles, dt):
        """Capture nearby free protons: (Z,A) + p â†’ (Z+1,A+1) + gamma."""
        Z, N, A = self._count_nucleons()
        capture_r = self.VIS_NUC_R0 * A**(1.0/3.0) * 2.5
        for p in particles:
            if p.is_atom or p.in_atom or getattr(p, 'base_type', '') != 'proton':
                continue
            r_dist = np.linalg.norm(p.pos - self.pos)
            if r_dist > capture_r:
                continue
            # Coulomb barrier: need kinetic energy to overcome
            r_fm = 1.2 * (A**(1/3) + 1.0)
            E_coulomb_MeV = 1.44 * Z / r_fm
            v_rel = np.linalg.norm(p.vel - self.vel)
            mu = p.mass * self.mass / (p.mass + self.mass + EPSILON)
            KE_cm_MeV = 0.5 * mu * v_rel**2 / MeV_to_J
            if KE_cm_MeV < E_coulomb_MeV * 0.3:
                continue  # Not enough energy to penetrate Coulomb barrier
            Q_MeV = binding_energy_MeV(Z + 1, A + 1) - binding_energy_MeV(Z, A)
            if Q_MeV <= 0:
                continue  # Endothermic
            prob = 0.01 * dt * (KE_cm_MeV / (E_coulomb_MeV + EPSILON))
            prob = min(prob, 0.3)
            if random.random() < prob:
                p.in_atom = True
                self.sub_particles.append(p)
                if p in particles:
                    particles.remove(p)
                gamma = Particle('photon', pos=self.pos.copy())
                gamma.pos = self.pos.copy()
                gamma.vel = random_unit_vector() * c
                gamma.energy_kin = Q_MeV * MeV_to_J
                particles.append(gamma)
                self._rebuild_atom(particles)
                return

    def _neutron_induced_fission(self, particles, dt):
        """Neutron-induced fission for heavy nuclei (U-235, Pu-239 etc)."""
        Z, N, A = self._count_nucleons()
        if A < 200:
            return
        # Fissile nuclei: U-235, Pu-239, U-233 etc (odd-A tend to be fissile)
        fiss_param = fissility_parameter(Z, A)
        # Threshold lower for odd-A (thermal fission) vs even-A (fast fission)
        threshold = 35.0 if A % 2 == 1 else 39.0
        if fiss_param < threshold:
            return
        prob = 0.5 if A % 2 == 1 else 0.1  # Odd-A nuclei fission much more readily
        if random.random() < prob:
            self._do_fission(particles)

    def _do_photodisintegration(self, particles, photon_E_J):
        """High-energy photon knocks out a nucleon from the nucleus."""
        Z, N, A = self._count_nucleons()
        if A < 3:
            return
        # Preferentially eject a neutron (lower barrier)
        neutrons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') == 'neutron']
        protons = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') == 'proton']
        if neutrons and (not protons or random.random() < 0.7):
            ejected = neutrons[0]
        elif protons:
            ejected = protons[0]
        else:
            return
        ejected.in_atom = False
        self.sub_particles.remove(ejected)
        ejected.pos = self.pos + random_unit_vector() * self.VIS_NUC_R0 * 3
        sep_E = binding_energy_per_nucleon(Z, A) * MeV_to_J
        excess = max(photon_E_J - sep_E, 0)
        v_eject = math.sqrt(2 * excess / (ejected.mass + EPSILON))
        ejected.vel = random_unit_vector() * min(v_eject, c * 0.1)
        ejected.energy_kin = excess
        particles.append(ejected)
        self._rebuild_atom(particles)

    def update(self, particles, time_factor, grav_accel, **kwargs):
        dt = PHYSICS_DT * time_factor
        self.last_grav_accel = grav_accel.copy()
        # 0. Nuclear reactions, ionization, and atomic/chemical processes
        self.nuclear_decay(particles, dt)
        if self.base_type == 'decayed':
            return
        self.ionization_check(particles, dt)
        if self.base_type == 'decayed':
            return
        self.photon_absorption(particles, dt)
        if self.base_type == 'decayed':
            return
        self.spontaneous_emission(particles, dt)
        self.stimulated_emission(particles, dt)
        self.neutron_capture(particles, dt)
        if self.base_type == 'decayed':
            return
        self.proton_capture(particles, dt)
        if self.base_type == 'decayed':
            return
        # 1. Move atom center via external gravity
        # Sanitize: NaN/Inf protection (matches Particle.update safeguards)
        if not np.all(np.isfinite(self.vel)):
            self.vel = np.zeros(dims)
        if not np.all(np.isfinite(self.pos)):
            self.pos = np.zeros(dims)
            for sp in self.sub_particles:
                sp.pos = self.pos.copy()
                for q in sp.constituent_quarks:
                    q.pos = self.pos.copy()
        self.vel += grav_accel * dt
        # Clamp velocity magnitude to prevent runaway (relativistic cap)
        _v_mag = np.linalg.norm(self.vel)
        if _v_mag > c * 0.99:
            self.vel *= (c * 0.99) / _v_mag
        delta_pos = self.vel * dt
        self.pos += delta_pos
        # Bound position to simulation volume (same as Particle.update)
        self.pos = np.clip(self.pos, -bound, bound)
        self.pos_history.append(self.pos.copy())
        for sp in self.sub_particles:
            sp.pos += delta_pos
            for q in sp.constituent_quarks:
                q.pos += delta_pos
        # 2. Internal constrained dynamics (visualization-scale)
        _nuc_types = ('proton', 'neutron', 'anti_proton', 'anti_neutron')
        nucleon_list = [sp for sp in self.sub_particles if getattr(sp, 'base_type', '') in _nuc_types]
        A_count = len(nucleon_list)
        nuc_max_r = self.VIS_NUC_R0 * max(A_count, 1) ** (1.0 / 3.0)
        # For large nuclei, cap pairwise interactions to nearest neighbors
        _max_neighbors = 12 if A_count > 30 else A_count
        lambda_vis = 2.36  # 1.414 fm in vis units (1 vis â‰ˆ 0.6 fm)
        _cutoff = 5.0 * lambda_vis
        for sp in self.sub_particles:
            bt = getattr(sp, 'base_type', '')
            r_vec = sp.pos - self.pos
            r_norm = np.linalg.norm(r_vec)
            if bt in ('electron', 'positron') and r_norm > 1e-6:
                # Research-grade Bohr orbital: use velocity RELATIVE to atom center
                # so bulk atom motion doesn't contaminate orbital speed
                v_rel = sp.vel - self.vel
                v_rel_mag = np.linalg.norm(v_rel)
                # Target shell radius and orbital speed (set during assign_positions)
                _target_r = getattr(sp, 'target_shell_r', r_norm)
                _target_v = getattr(sp, 'target_orbital_v', max(v_rel_mag, 1.0))
                # 1. Radial spring: Hooke restoring force toward target shell radius
                #    F = -k*(r - r_target) along radial direction, critically damped
                _r_hat = r_vec / r_norm
                _dr = r_norm - _target_r
                _k_spring = 80.0  # spring constant (vis units)
                _radial_vel = np.dot(v_rel, _r_hat)
                _damping = 2.0 * math.sqrt(_k_spring)  # critical damping
                v_rel -= _r_hat * (_k_spring * _dr + _damping * _radial_vel) * dt
                # 2. Orbital speed regulation: gently steer toward target orbital speed
                v_rel_mag = np.linalg.norm(v_rel)
                if v_rel_mag > 1e-6:
                    _speed_err = v_rel_mag - _target_v
                    _correction = min(abs(_speed_err), _target_v * 0.1) * (1.0 if _speed_err > 0 else -1.0)
                    v_rel *= (1.0 - _correction / (v_rel_mag + EPSILON) * dt * 30.0)
                    v_rel_mag = np.linalg.norm(v_rel)
                # 3. Rodrigues orbital rotation (exact, preserves radius)
                if v_rel_mag > 1e-6:
                    omega = v_rel_mag / r_norm
                    angle = omega * dt
                    if not math.isfinite(angle):
                        # Overflow: reset to clean circular orbit
                        _kick_ax = np.array([0, 0, 1]) if abs(_r_hat[2]) < 0.99 else np.array([1, 0, 0])
                        _kick = np.cross(_r_hat, _kick_ax)
                        _kick /= np.linalg.norm(_kick) + EPSILON
                        sp.vel = _kick * _target_v + self.vel
                        v_rel_mag = 0.0  # skip rest of Rodrigues block
                    L = np.cross(r_vec, v_rel)
                    L_norm = np.linalg.norm(L)
                    if L_norm > 1e-20 and v_rel_mag > 1e-6:
                        ax = L / L_norm
                        cos_a = math.cos(angle)
                        sin_a = math.sin(angle)
                        r_new = r_vec * cos_a + np.cross(ax, r_vec) * sin_a + ax * np.dot(ax, r_vec) * (1 - cos_a)
                        sp.pos = self.pos + r_new
                        # Velocity = tangential orbital (relative) + atom bulk
                        sp.vel = np.cross(ax, r_new) / r_norm * v_rel_mag + self.vel
                    else:
                        # Degenerate angular momentum: give a kick perpendicular to r
                        _kick_ax = np.array([0, 0, 1]) if abs(_r_hat[2]) < 0.99 else np.array([1, 0, 0])
                        _kick = np.cross(_r_hat, _kick_ax)
                        _kick /= np.linalg.norm(_kick) + EPSILON
                        sp.vel = _kick * _target_v + self.vel
                else:
                    # Zero relative velocity: reinitialize orbital velocity
                    _kick_ax = np.array([0, 0, 1]) if abs(_r_hat[2]) < 0.99 else np.array([1, 0, 0])
                    _kick = np.cross(_r_hat, _kick_ax)
                    _kick /= np.linalg.norm(_kick) + EPSILON
                    sp.vel = _kick * _target_v + self.vel
                # 4. Hard clamp: prevent extreme escape (safety net)
                _r_after = np.linalg.norm(sp.pos - self.pos)
                _max_r = _target_r * 2.5
                if _r_after > _max_r and _r_after > EPSILON:
                    sp.pos = self.pos + (sp.pos - self.pos) / _r_after * _target_r
                    # Reset to clean circular orbit at target radius
                    _r2 = sp.pos - self.pos
                    _rh2 = _r2 / np.linalg.norm(_r2)
                    _ka2 = np.array([0, 0, 1]) if abs(_rh2[2]) < 0.99 else np.array([1, 0, 0])
                    _kv2 = np.cross(_rh2, _ka2)
                    _kv2 /= np.linalg.norm(_kv2) + EPSILON
                    sp.vel = _kv2 * _target_v + self.vel
                # 5. NaN/Inf safety net: if orbital math produced bad values, reset to clean orbit
                if not np.all(np.isfinite(sp.pos)) or not np.all(np.isfinite(sp.vel)):
                    _safe_dir = random_unit_vector()
                    sp.pos = self.pos + _safe_dir * _target_r
                    _sa = np.array([0, 0, 1]) if abs(_safe_dir[2]) < 0.99 else np.array([1, 0, 0])
                    _sv = np.cross(_safe_dir, _sa)
                    _sv /= np.linalg.norm(_sv) + EPSILON
                    sp.vel = _sv * _target_v + self.vel
            elif bt in _nuc_types:
                # Nuclear binding toward center
                sp.vel += -30.0 * r_vec * dt
                # Nucleon-nucleon forces: nearest-neighbor capped for large nuclei
                _n_checked = 0
                for other in nucleon_list:
                    if other is sp:
                        continue
                    sep = other.pos - sp.pos
                    sep_dist = np.linalg.norm(sep)
                    if sep_dist < EPSILON or sep_dist > _cutoff:
                        continue
                    _n_checked += 1
                    if _n_checked > _max_neighbors:
                        break
                    sep_dir = sep / sep_dist
                    # Yukawa strong nuclear attraction
                    exp_term = math.exp(-sep_dist / lambda_vis)
                    f_strong = 50.0 * exp_term * (1.0 / (sep_dist + 0.5) + 1.0 / lambda_vis)
                    sp.vel += sep_dir * f_strong * dt
                    # Hard-core repulsion at very close range
                    if sep_dist < self.NUCLEON_MIN_SEP:
                        overlap = self.NUCLEON_MIN_SEP - sep_dist
                        sp.vel -= sep_dir * overlap * 200.0 * dt
                    # Coulomb repulsion between protons
                    if bt in ('proton', 'anti_proton') and getattr(other, 'base_type', '') in ('proton', 'anti_proton'):
                        f_coulomb = 5.0 / (sep_dist ** 2 + 0.1)
                        sp.vel -= sep_dir * f_coulomb * dt
                sp.vel *= 0.98
                old_sp_pos = sp.pos.copy()
                sp.pos += sp.vel * dt
                r_new = np.linalg.norm(sp.pos - self.pos)
                if r_new > nuc_max_r:
                    sp.pos = self.pos + (sp.pos - self.pos) / r_new * nuc_max_r * 0.95
                # Move constituent quarks with nucleon bulk motion
                sp_delta = sp.pos - old_sp_pos
                for q in sp.constituent_quarks:
                    q.pos += sp_delta
        # 2b. QCD dynamics: skip for large atoms (>20 nucleons) — quarks just follow nucleons
        if A_count <= 20:
            for sp in self.sub_particles:
                if not sp.constituent_quarks:
                    continue
                quarks = sp.constituent_quarks
                nuc_r = self.PROTON_VIS_R * 0.8
                for i_q, q1 in enumerate(quarks):
                    for j_q in range(i_q + 1, len(quarks)):
                        q2 = quarks[j_q]
                        r_qq = q2.pos - q1.pos
                        r_qq_norm = np.linalg.norm(r_qq)
                        if r_qq_norm < EPSILON:
                            continue
                        r_qq_dir = r_qq / r_qq_norm
                        a_eff = 20.0
                        sigma_eff = 40.0
                        f_cornell = a_eff / (r_qq_norm ** 2 + 0.01) + sigma_eff
                        f_cornell = min(f_cornell, 500.0)
                        q1.vel += r_qq_dir * f_cornell / (q1.mass / 1e-30 + 1.0) * dt
                        q2.vel -= r_qq_dir * f_cornell / (q2.mass / 1e-30 + 1.0) * dt
                    # Confine quark inside nucleon radius
                    r_qn = q1.pos - sp.pos
                    r_qn_norm = np.linalg.norm(r_qn)
                    if r_qn_norm > nuc_r and r_qn_norm > EPSILON:
                        q1.vel -= (r_qn / r_qn_norm) * (r_qn_norm - nuc_r) * 150.0 * dt
                    q1.vel *= 0.95
                    _qv = np.linalg.norm(q1.vel)
                    if _qv > 500.0:
                        q1.vel *= 500.0 / _qv
                    q1.pos += q1.vel * dt
                    # Hard clamp: force quark back inside nucleon radius (prevents escape)
                    r_qn2 = q1.pos - sp.pos
                    r_qn2_norm = np.linalg.norm(r_qn2)
                    if r_qn2_norm > nuc_r * 1.5 and r_qn2_norm > EPSILON:
                        q1.pos = sp.pos + r_qn2 / r_qn2_norm * nuc_r * 0.9
                        q1.vel *= 0.3
        # 3. Update bulk atom properties
        self.energy_kin = sum(0.5 * sp.mass * np.sum(sp.vel ** 2) for sp in self.sub_particles)
        self.energy_rot = 0.0
        self.mass = sum(sp.mass for sp in self.sub_particles)

    # Aufbau filling order for electron shell rendering: (n, l, max_electrons)
    _AUFBAU_RENDER = [
        (1, 0, 2), (2, 0, 2), (2, 1, 6), (3, 0, 2), (3, 1, 6),
        (4, 0, 2), (3, 2, 10), (4, 1, 6), (5, 0, 2), (4, 2, 10),
        (5, 1, 6), (6, 0, 2), (4, 3, 14), (5, 2, 10), (6, 1, 6),
        (7, 0, 2), (5, 3, 14), (6, 2, 10), (7, 1, 6)
    ]

    def get_draw_info(self, camera):
        # Sub-frame interpolation: lerp atom center between prev_pos and pos
        _al = _render_alpha
        _prev = getattr(self, 'prev_pos', self.pos)
        _rpos = _prev + (self.pos - _prev) * _al
        rel_pos_rot = _rpos - camera.pos
        rel_pos_rot = rotate_vector(rel_pos_rot, camera.rot)
        dist = np.linalg.norm(rel_pos_rot)
        apparent_size = self.VIS_SHELL_R0 / (dist + 1.0)
        # LOD 0: far away — single solid CPK-colored sphere (cheapest)
        if apparent_size < 0.001:
            color = ELEMENT_COLORS.get(self.Z, (200, 200, 200, 255))
            # Cap LOD radius to something reasonable so far atoms don't bloat
            lod_radius = min(self.VIS_SHELL_R0 * 0.5, max(1.5, self.VIS_NUC_R0 * max(self.A, 1) ** (1.0/3.0) * 2.0))
            return [(rel_pos_rot, lod_radius, color, self.base_type, False)]
        # LOD levels based on apparent size
        skip_quarks = apparent_size < 0.01
        skip_electrons = apparent_size < 0.005
        # LOD 1: medium distance — skip electron shells, only show nucleus
        skip_shells = apparent_size < 0.008
        draw_info = []
        # --- Electron cloud shells: translucent Bohr-model orbital shells ---
        # Each occupied principal quantum number n gets a translucent sphere
        # at radius r = VIS_SHELL_R0 * n^2 / Z_eff (Slater shielding)
        # This is the most recognizable feature of an atom visualization
        if not skip_shells:
            n_electrons_total = sum(1 for sp in self.sub_particles
                                    if getattr(sp, 'base_type', '') in ('electron', 'positron'))
            elem_color = ELEMENT_COLORS.get(self.Z, (100, 180, 255, 255))
            # Distance-based alpha fade: shells become fainter as atom gets smaller on screen
            _dist_fade = min(1.0, max(0.3, (apparent_size - 0.008) / 0.192))  # 0.008->0.3, 0.2->1.0
            if n_electrons_total > 0:
                e_placed = 0
                _seen_n = set()
                for n, l, max_e in self._AUFBAU_RENDER:
                    if e_placed >= n_electrons_total:
                        break
                    n_in_sub = min(max_e, n_electrons_total - e_placed)
                    e_placed += n_in_sub
                    if n in _seen_n:
                        continue
                    _seen_n.add(n)
                    # Slater shielding: Z_eff = Z - sigma
                    sigma = 0.35 * max(n_in_sub - 1, 0) + 0.85 * min(e_placed - n_in_sub, 2 * (n - 1))
                    Z_eff = max(self.Z - sigma, 1.0)
                    r_shell = self.VIS_SHELL_R0 * n ** 2 / Z_eff
                    # Filling fraction: how full this shell is (affects alpha)
                    max_in_n = sum(me for nn, ll, me in self._AUFBAU_RENDER if nn == n)
                    fill_frac = min(1.0, n_in_sub / max(max_in_n, 1))
                    # Alpha: outer shells fainter, fuller shells more visible
                    # Research convention: probability density ~ |psi|^2, represented by alpha
                    shell_alpha = int(max(8, min(50, (20 + 30 * fill_frac - 4 * n) * _dist_fade)))
                    shell_color = (elem_color[0], elem_color[1], elem_color[2], shell_alpha)
                    draw_info.append((rel_pos_rot, r_shell, shell_color, '', True))
        # --- Nucleus: semi-transparent nucleon spheres with visible color ---
        for sp in self.sub_particles:
            sp_prev = getattr(sp, 'prev_pos', sp.pos)
            sp_rpos = sp_prev + (sp.pos - sp_prev) * _al
            sp_rel = sp_rpos - camera.pos
            sp_rel = rotate_vector(sp_rel, camera.rot)
            bt = getattr(sp, 'base_type', '')
            color = Particle.PARTICLE_COLORS.get(bt, (255, 255, 255, 255))
            if bt in ('proton', 'anti_proton'):
                size = self.PROTON_VIS_R
            elif bt in ('neutron', 'anti_neutron'):
                size = self.NEUTRON_VIS_R
            elif bt in ('electron', 'positron'):
                # Scale up electron dot for visibility (real: point particle, vis: needs to be seen)
                size = max(0.4, self.ELECTRON_VIS_R * 8.0)
                if skip_electrons:
                    continue
            else:
                size = 0.15
            # Nucleons: semi-transparent so quarks are visible inside
            if bt in ('proton', 'neutron', 'anti_proton', 'anti_neutron'):
                _n_total = len(self.sub_particles)
                if skip_quarks:
                    _sp_alpha = max(200, 245 - _n_total)
                else:
                    _sp_alpha = max(140, 190 - _n_total)
                color = (color[0], color[1], color[2], _sp_alpha)
            draw_info.append((sp_rel, size, color, bt, True))
            # LOD 2: close up — render constituent quarks inside nucleons
            if not skip_quarks and sp.constituent_quarks:
                for q in sp.constituent_quarks:
                    q_prev = getattr(q, 'prev_pos', q.pos)
                    q_rpos = q_prev + (q.pos - q_prev) * _al
                    q_rel = q_rpos - camera.pos
                    q_rel = rotate_vector(q_rel, camera.rot)
                    q_bt = getattr(q, 'base_type', '')
                    q_color = Particle.PARTICLE_COLORS.get(q_bt, (255, 200, 100, 255))
                    # Scale up quark size for visibility (real: <1e-18m, vis: needs to be seen)
                    q_size = max(0.25, Particle.PARTICLE_RADII.get(q_bt, 0.03) * 8.0)
                    draw_info.append((q_rel, q_size, q_color, q_bt, True))
        # Atom name label at center — zero-radius so no sphere is rendered
        draw_info.append((rel_pos_rot, 0.0, (0, 0, 0, 0), self.base_type, False))
        return draw_info

    def get_bonds(self, camera):
        bonds = []
        _al = _render_alpha
        # Distance from atom center to camera for bond culling
        _atom_dist = np.linalg.norm(self.pos - camera.pos)
        _atom_apparent = self.VIS_SHELL_R0 / (_atom_dist + 1.0)
        # Skip ALL internal bonds when atom is far away (LOD cull)
        if _atom_apparent >= 0.002:
            for p1, p2 in self.bonds:
                p1_prev = getattr(p1, 'prev_pos', p1.pos)
                p1_rpos = p1_prev + (p1.pos - p1_prev) * _al
                rel1 = p1_rpos - camera.pos
                rel1 = rotate_vector(rel1, camera.rot)
                p2_prev = getattr(p2, 'prev_pos', p2.pos)
                p2_rpos = p2_prev + (p2.pos - p2_prev) * _al
                rel2 = p2_rpos - camera.pos
                rel2 = rotate_vector(rel2, camera.rot)
                bonds.append((rel1, rel2))
        # Molecular (chemical) bonds to other atoms
        # Distance-cull: skip molecular bonds longer than 150 vis units (broken/drifted)
        _max_mol_bond_len_sq = 150.0 ** 2
        seen_ids = set()
        _self_prev = getattr(self, 'prev_pos', self.pos)
        _self_rpos = _self_prev + (self.pos - _self_prev) * _al
        for bonded_atom, bond_info in getattr(self, 'molecular_bonds', []):
            pair_key = (min(id(self), id(bonded_atom)), max(id(self), id(bonded_atom)))
            if pair_key in seen_ids:
                continue
            seen_ids.add(pair_key)
            if bonded_atom.base_type == 'decayed':
                continue
            # Cull bonds between atoms that have drifted too far apart
            _bond_sep_sq = float(np.sum((self.pos - bonded_atom.pos) ** 2))
            if _bond_sep_sq > _max_mol_bond_len_sq:
                continue
            rel1 = _self_rpos - camera.pos
            rel1 = rotate_vector(rel1, camera.rot)
            ba_prev = getattr(bonded_atom, 'prev_pos', bonded_atom.pos)
            ba_rpos = ba_prev + (bonded_atom.pos - ba_prev) * _al
            rel2 = ba_rpos - camera.pos
            rel2 = rotate_vector(rel2, camera.rot)
            bonds.append((rel1, rel2))
        return bonds

    def get_size(self):
        if not self.sub_particles:
            return self.VIS_SHELL_R0
        max_dist = max(np.linalg.norm(sp.pos - self.pos) for sp in self.sub_particles)
        return max_dist


# Camera class
class Camera:
    def __init__(self):
        self.pos = np.zeros(dims)
        self.zoom = 1.0
        self.rot = np.zeros(3)
        self.MIN_ZOOM = 0.005  # Prevent extreme close-up on sub-atomic particles

    def zoom_in(self):
        self.zoom = max(self.MIN_ZOOM, self.zoom / 1.1)

    def zoom_out(self):
        self.zoom *= 1.1

    def rotate(self, dx, dy):
        self.rot[1] += dx * 0.01
        self.rot[0] += dy * 0.01

    def focus_on_particle(self, particle):
        if particle:
            self.pos = particle.pos.copy()
            size = particle.get_size()
            half_fov_rad = math.radians(45) / 2
            fraction = 0.5
            half_theta = half_fov_rad * fraction
            tan_half_theta = math.tan(half_theta)
            d = size / tan_half_theta
            self.zoom = max(self.MIN_ZOOM, d / 1125) if d > 0 else 1.0
            focus_label.text = f"Focusing on: {('[' + particle.spawned_by + '] ') if getattr(particle, 'spawned_by', '') else ''}{particle.type}"

    def focus_on_position(self, pos, cluster_id):
        self.pos = pos.copy()
        cluster_mass = 1e-27
        mass_list = [p.mass for p in particles if p.mass > 0]
        max_mass = max(mass_list) if mass_list else 1e-27
        size = int(50 * (cluster_mass * 1e27) / (max_mass * 1e27 + EPSILON) + 100)
        half_fov_rad = math.radians(45) / 2
        fraction = 0.5
        half_theta = half_fov_rad * fraction
        tan_half_theta = math.tan(half_theta)
        d = size / tan_half_theta
        self.zoom = d / 1125
        focus_label.text = f"Focusing on Cluster: {cluster_id}"

    def pan(self, dx, dy):
        """Pan the camera in the view plane (right-click drag)."""
        # Build right and up vectors from current rotation
        inv_rot = -self.rot
        right = rotate_vector(np.array([1.0, 0.0, 0.0]), inv_rot)
        up = rotate_vector(np.array([0.0, 1.0, 0.0]), inv_rot)
        speed = self.zoom * 0.5
        self.pos -= right * dx * speed + up * dy * speed

    def zoom_to_human_scale(self):
        """Zoom out to human-size relativity â€” atoms appear as tiny dots."""
        if not particles:
            return
        positions = np.array([p.pos for p in particles if p.mass > 0])
        if len(positions) == 0:
            return
        center = np.mean(positions, axis=0)
        self.pos = center.copy()
        self.zoom = HUMAN_SCALE_ZOOM
        focus_label.text = f"Human Scale View (zoom={self.zoom:.0e})  â€” atoms are sub-pixel dots"

# === Observer Camera Windows ===
_observer_windows = []  # list of ObserverWindow instances
_pending_observer_spawns = []  # deferred ObserverWindow creation (avoid pyglet Set iteration crash)

class ObserverWindow:
    """Independent camera window sharing the same simulation state."""
    _count = 0

    def __init__(self, target_particle=None):
        ObserverWindow._count += 1
        self.id = ObserverWindow._count
        self.cam = Camera()
        if target_particle:
            self.cam.pos = target_particle.pos.copy()
            size = target_particle.get_size()
            self.cam.zoom = max(0.005, size / (math.tan(math.radians(22.5)) * 1125)) if size > 0 else 1.0
        self.target = target_particle
        self._win = pyglet.window.Window(
            width=640, height=480, resizable=True,
            caption=f"Observer {self.id}", vsync=False)
        self._w = 640
        self._h = 480
        self._alive = True
        self._dragging = False
        self._panning = False
        _self = self

        @self._win.event
        def on_draw():
            if not _self._alive:
                return
            _self._render()

        @self._win.event
        def on_mouse_drag(x, y, dx, dy, buttons, modifiers):
            if buttons & pyglet.window.mouse.LEFT:
                _self.cam.rotate(dx, dy)
            elif buttons & pyglet.window.mouse.RIGHT:
                _self.cam.pan(dx, dy)

        @self._win.event
        def on_mouse_scroll(x, y, scroll_x, scroll_y):
            if scroll_y > 0:
                _self.cam.zoom_in()
            elif scroll_y < 0:
                _self.cam.zoom_out()

        @self._win.event
        def on_resize(w, h):
            _self._w = w
            _self._h = h

        @self._win.event
        def on_close():
            _self._alive = False
            if _self in _observer_windows:
                _observer_windows.remove(_self)
            return pyglet.event.EVENT_HANDLED

        @self._win.event
        def on_key_press(symbol, modifiers):
            if symbol == pyglet.window.key.ESCAPE:
                _self._alive = False
                _self._win.close()
                if _self in _observer_windows:
                    _observer_windows.remove(_self)

    def _render(self):
        """Render the simulation from this observer's camera perspective."""
        if not self._alive:
            return
        # Track target particle, or auto-center on all particles
        if self.target and hasattr(self.target, 'pos'):
            self.cam.pos = self.target.pos.copy()
        elif not self.target and particles:
            _positions = [p.pos for p in particles if p.mass > 0]
            if _positions:
                self.cam.pos = np.mean(_positions, axis=0)
        # Disable PyOpenGL error checking to prevent stale GL errors from crashing observer
        _prev_check = OpenGL.ERROR_CHECKING
        OpenGL.ERROR_CHECKING = False
        try:
            self._win.switch_to()
            glClearColor(0.02, 0.02, 0.05, 1)
            glClear(GL_COLOR_BUFFER_BIT | GL_DEPTH_BUFFER_BIT)
            glViewport(0, 0, self._w, self._h)
            glMatrixMode(GL_PROJECTION)
            glLoadIdentity()
            _nc = max(0.001, self.cam.zoom * 0.1)
            _fc = max(1e7, self.cam.zoom * 500)
            gluPerspective(45, self._w / max(self._h, 1), _nc, _fc)
            glMatrixMode(GL_MODELVIEW)
            glLoadIdentity()
            glTranslatef(0, 0, -self.cam.zoom * 100)
            glRotatef(self.cam.rot[0] * 180 / math.pi, 1, 0, 0)
            glRotatef(self.cam.rot[1] * 180 / math.pi, 0, 1, 0)
            glRotatef(self.cam.rot[2] * 180 / math.pi, 0, 0, 1)
            # Lighting
            glEnable(GL_LIGHTING)
            glEnable(GL_LIGHT0)
            _lp = (c_float * 4)(0.0, 0.0, 100.0, 1.0)
            glLightfv(GL_LIGHT0, GL_POSITION, _lp)
            _ld = (c_float * 4)(1.0, 1.0, 1.0, 1.0)
            glLightfv(GL_LIGHT0, GL_DIFFUSE, _ld)
            glEnable(GL_DEPTH_TEST)
            glEnable(GL_COLOR_MATERIAL)
            glColorMaterial(GL_FRONT_AND_BACK, GL_DIFFUSE)
            # Draw grid in observer window (matches main window)
            _obs_grid_spacing = GRID_SPACING * (1 + self.cam.zoom)
            _obs_step = max(1, int(_obs_grid_spacing))
            _obs_eff_grid = GRID_SIZE * (1 + self.cam.zoom)
            if toggle_grid:
                glColor4ub(*GRID_COLOR)
                glDisable(GL_LIGHTING)
                _obs_max_gl = 200
                _obs_gc = int(2 * _obs_eff_grid / _obs_step) if _obs_step > 0 else 0
                if _obs_gc > _obs_max_gl:
                    _obs_step = max(1, int(2 * _obs_eff_grid / _obs_max_gl))
                glBegin(GL_LINES)
                for _gi in range(-int(_obs_eff_grid), int(_obs_eff_grid) + 1, _obs_step):
                    glVertex3f(_gi, -_obs_eff_grid, 0)
                    glVertex3f(_gi, _obs_eff_grid, 0)
                    glVertex3f(-_obs_eff_grid, _gi, 0)
                    glVertex3f(_obs_eff_grid, _gi, 0)
                    glVertex3f(_gi, 0, -_obs_eff_grid)
                    glVertex3f(_gi, 0, _obs_eff_grid)
                    glVertex3f(-_obs_eff_grid, 0, _gi)
                    glVertex3f(_obs_eff_grid, 0, _gi)
                    glVertex3f(0, _gi, -_obs_eff_grid)
                    glVertex3f(0, _gi, _obs_eff_grid)
                    glVertex3f(0, -_obs_eff_grid, _gi)
                    glVertex3f(0, _obs_eff_grid, _gi)
                glEnd()
                glEnable(GL_LIGHTING)
            # Collect draw info — render all particles across all space
            _obs_opaque = []
            _obs_trans = []
            for p in particles:
                if p.in_nanotech:
                    continue
                for rel_pos, radius, color, label_text, is_sub in p.get_draw_info(self.cam):
                    if radius < 0.001:
                        continue
                    if len(color) >= 4 and color[3] <= 0:
                        continue
                    dist = np.linalg.norm(rel_pos)
                    if dist > 1e6:
                        continue
                    item = (rel_pos, radius, color, dist)
                    if len(color) >= 4 and color[3] < 255:
                        _obs_trans.append(item)
                    else:
                        _obs_opaque.append(item)
            for _nt in nanotech_loaded:
                for rel_pos, radius, color, label_text, is_sub in _nt.get_draw_info(self.cam):
                    if radius < 0.001:
                        continue
                    if len(color) >= 4 and color[3] <= 0:
                        continue
                    dist = np.linalg.norm(rel_pos)
                    if dist > 1e6:
                        continue
                    item = (rel_pos, radius, color, dist)
                    if len(color) >= 4 and color[3] < 255:
                        _obs_trans.append(item)
                    else:
                        _obs_opaque.append(item)
            # Draw opaque (using display list cache for performance)
            for rel_pos, radius, color, dist in _obs_opaque:
                glPushMatrix()
                glTranslatef(float(rel_pos[0]), float(rel_pos[1]), float(rel_pos[2]))
                glMaterialfv(GL_FRONT, GL_DIFFUSE,
                             (c_float * 4)(color[0]/255.0, color[1]/255.0, color[2]/255.0, color[3]/255.0))
                sf = radius / (dist + 1.0)
                segs = max(10, 16) if sf > 0.05 else (max(8, 10) if sf > 0.01 else 4)
                _draw_cached_sphere(radius, segs)
                glPopMatrix()
            # Draw transparent (electron clouds + nucleon shells)
            if _obs_trans:
                glEnable(GL_BLEND)
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
                glDepthMask(GL_FALSE)
                _obs_trans.sort(key=lambda s: -s[3])
                for rel_pos, radius, color, dist in _obs_trans:
                    glPushMatrix()
                    glTranslatef(float(rel_pos[0]), float(rel_pos[1]), float(rel_pos[2]))
                    glMaterialfv(GL_FRONT_AND_BACK, GL_DIFFUSE,
                                 (c_float * 4)(color[0]/255.0, color[1]/255.0, color[2]/255.0, color[3]/255.0))
                    sf = radius / (dist + 1.0)
                    segs = max(16, 24) if sf > 0.05 else (max(12, 16) if sf > 0.01 else 6)
                    _draw_cached_sphere(radius, segs)
                    glPopMatrix()
                glDepthMask(GL_TRUE)
                glDisable(GL_BLEND)
            # HUD overlay
            glDisable(GL_LIGHTING)
            glDisable(GL_DEPTH_TEST)
            glMatrixMode(GL_PROJECTION)
            glLoadIdentity()
            glOrtho(0, self._w, 0, self._h, -1, 1)
            glMatrixMode(GL_MODELVIEW)
            glLoadIdentity()
            _lbl = Label(f"Observer {self.id}  |  Particles: {len(particles)}  |  ESC=Close",
                         x=8, y=self._h - 18, font_size=10, color=(180, 220, 255, 220))
            _lbl.draw()
            if self.target:
                _tlbl = Label(f"Tracking: {getattr(self.target, 'type', '?')}",
                              x=8, y=self._h - 34, font_size=9, color=(140, 255, 180, 200))
                _tlbl.draw()
            glEnable(GL_LIGHTING)
        except Exception:
            pass
        finally:
            OpenGL.ERROR_CHECKING = _prev_check


# === Double-Slit Experiment â€” Research-Grade Quantum Optics ===
# Implements Young's double-slit with proper Huygens-Fresnel diffraction.
# Each photon travels as a probability amplitude through both slits simultaneously;
# detection collapses the wavefunction to a single point weighted by |Ïˆâ‚+Ïˆâ‚‚|Â².
# Interference pattern: I(x) = Iâ‚€ Â· cosÂ²(Ï€Â·dÂ·x/(Î»Â·L)) Â· sincÂ²(Ï€Â·aÂ·x/(Î»Â·L))
#   d = slit separation, a = slit width, L = source-to-screen distance, Î» = wavelength
class DoubleSlitExperiment:
    def __init__(self, center=None, direction=None, slit_sep=40.0, slit_width=5.0,
                 barrier_dist=200.0, screen_dist=400.0, photon_energy_eV=2.25,
                 n_detector_bins=200):
        self.center = center if center is not None else np.zeros(dims)
        self.direction = direction if direction is not None else np.array([1.0, 0.0, 0.0])
        self.direction = self.direction / (np.linalg.norm(self.direction) + EPSILON)
        # Perpendicular axis for slit separation (y-axis by default)
        self.perp = np.array([0.0, 1.0, 0.0])
        if abs(np.dot(self.direction, self.perp)) > 0.9:
            self.perp = np.array([0.0, 0.0, 1.0])
        self.perp = self.perp - np.dot(self.perp, self.direction) * self.direction
        self.perp = self.perp / (np.linalg.norm(self.perp) + EPSILON)
        # Physical parameters (vis-units for positions, SI for wavelength)
        self.slit_sep = slit_sep          # d: center-to-center slit separation (vis units)
        self.slit_width = slit_width      # a: width of each slit (vis units)
        self.barrier_dist = barrier_dist  # source to barrier distance (vis units)
        self.screen_dist = screen_dist    # source to detector screen distance (vis units)
        # Photon energy -> wavelength: E = hf = hc/lambda -> lambda = hc/E
        self.photon_energy_eV = photon_energy_eV  # Default 2.25 eV ~ 551nm green
        self.photon_energy_J = photon_energy_eV * eV_to_J
        self.wavelength = h * c / (self.photon_energy_J + EPSILON)  # meters
        # Scale wavelength to vis-units: 1 vis unit ~ 0.6 fm = 6e-16 m
        # For visible interference we use an effective wavelength in vis-units
        # that preserves the correct fringe spacing ratio d/lambda
        self.wavelength_vis = self.wavelength / 6e-16  # vis-unit equivalent
        # Detector screen
        self.n_bins = n_detector_bins
        self.detector_counts = np.zeros(n_detector_bins, dtype=np.int64)
        self.detector_width = screen_dist * 0.8  # total detector width (vis units)
        self.total_photons_emitted = 0
        self.total_photons_detected = 0
        # State
        self.active = False
        self.emit_rate = 5  # photons per physics step
        self.which_path_detector = False  # If True, collapses interference (observer effect)
        # Positions
        self.source_pos = self.center - self.direction * self.barrier_dist * 0.5
        self.barrier_pos = self.center
        self.screen_pos = self.center + self.direction * (self.screen_dist - self.barrier_dist * 0.5)
        self.slit1_pos = self.barrier_pos + self.perp * (self.slit_sep / 2)
        self.slit2_pos = self.barrier_pos - self.perp * (self.slit_sep / 2)
        # Precompute interference pattern for fast sampling
        self._precompute_pattern()

    def _precompute_pattern(self):
        """Precompute the theoretical interference probability distribution."""
        x = np.linspace(-self.detector_width / 2, self.detector_width / 2, self.n_bins)
        lam = self.wavelength_vis
        L = self.screen_dist - self.barrier_dist * 0.5
        d = self.slit_sep
        a = self.slit_width
        if lam > 0 and L > 0:
            # Double-slit interference x single-slit diffraction envelope
            # I(x) = cos^2(pi*d*x/(lam*L)) * sinc^2(pi*a*x/(lam*L))
            alpha = math.pi * d * x / (lam * L + EPSILON)
            beta = math.pi * a * x / (lam * L + EPSILON)
            interference = np.cos(alpha) ** 2
            # sinc^2 for diffraction envelope (avoid division by zero)
            with np.errstate(divide='ignore', invalid='ignore'):
                diffraction = np.where(np.abs(beta) < 1e-12, 1.0, (np.sin(beta) / beta) ** 2)
            self._pattern = interference * diffraction
        else:
            self._pattern = np.ones(self.n_bins)
        # Normalize to probability distribution
        total = np.sum(self._pattern)
        if total > 0:
            self._pattern_prob = self._pattern / total
        else:
            self._pattern_prob = np.ones(self.n_bins) / self.n_bins
        # Which-path pattern: no interference, just diffraction from two slits
        x1 = x - d / 2
        x2 = x + d / 2
        beta1 = math.pi * a * x1 / (lam * L + EPSILON)
        beta2 = math.pi * a * x2 / (lam * L + EPSILON)
        with np.errstate(divide='ignore', invalid='ignore'):
            p1 = np.where(np.abs(beta1) < 1e-12, 1.0, (np.sin(beta1) / beta1) ** 2)
            p2 = np.where(np.abs(beta2) < 1e-12, 1.0, (np.sin(beta2) / beta2) ** 2)
        wp_pattern = (p1 + p2) * 0.5
        wp_total = np.sum(wp_pattern)
        self._wp_pattern_prob = wp_pattern / wp_total if wp_total > 0 else np.ones(self.n_bins) / self.n_bins

    def set_which_path(self, enabled):
        """Toggle which-path detector (collapses interference when True)."""
        self.which_path_detector = enabled
        self._precompute_pattern()

    def emit_photons(self, particles):
        """Emit coherent photons from the source toward the barrier."""
        if not self.active:
            return
        for _ in range(self.emit_rate):
            spread = random.gauss(0, 0.01)
            vel_dir = self.direction + self.perp * spread
            vel_dir = vel_dir / (np.linalg.norm(vel_dir) + EPSILON)
            photon = Particle('photon', pos=self.source_pos.copy(), vel=vel_dir * c)
            photon.energy_kin = self.photon_energy_J
            photon.wave_wavelength = self.wavelength
            photon.wave_frequency = self.photon_energy_J / h
            photon.wave_coherence = 1.0
            photon.wave_phase = 0.0
            photon.polarization = 0.0
            photon.slit_path = -1
            photon.detected = False
            particles.append(photon)
            self.total_photons_emitted += 1

    def step(self, particles):
        """Check photons passing through barrier and hitting detector screen."""
        if not self.active:
            return
        barrier_x = np.dot(self.barrier_pos - self.source_pos, self.direction)
        screen_x = np.dot(self.screen_pos - self.source_pos, self.direction)
        for p in list(particles):
            if getattr(p, 'base_type', '') != 'photon' or getattr(p, 'detected', False):
                continue
            if getattr(p, 'wave_coherence', 0) < 0.5:
                continue
            rel = p.pos - self.source_pos
            along = np.dot(rel, self.direction)
            if along >= barrier_x - 1 and along <= barrier_x + 1 and getattr(p, 'slit_path', -1) == -1:
                perp_pos = np.dot(rel, self.perp)
                in_slit1 = abs(perp_pos - self.slit_sep / 2) < self.slit_width / 2
                in_slit2 = abs(perp_pos + self.slit_sep / 2) < self.slit_width / 2
                if not in_slit1 and not in_slit2:
                    p.mass = 0
                    p.base_type = 'decayed'
                    p.type = 'decayed'
                    p.energy_kin = 0
                    continue
                if self.which_path_detector:
                    if in_slit1 and in_slit2:
                        p.slit_path = random.choice([0, 1])
                    elif in_slit1:
                        p.slit_path = 0
                    else:
                        p.slit_path = 1
                else:
                    p.slit_path = -1
            if along >= screen_x - 2:
                if self.which_path_detector:
                    prob = self._wp_pattern_prob
                else:
                    prob = self._pattern_prob
                bin_idx = np.random.choice(self.n_bins, p=prob)
                self.detector_counts[bin_idx] += 1
                self.total_photons_detected += 1
                p.detected = True
                p.wave_coherence = 0.0
                p.slit_path = bin_idx
                det_x = -self.detector_width / 2 + (bin_idx + 0.5) * self.detector_width / self.n_bins
                p.pos = self.screen_pos + self.perp * det_x
                p.vel = np.zeros(dims)

    def reset(self):
        """Reset detector counts."""
        self.detector_counts = np.zeros(self.n_bins, dtype=np.int64)
        self.total_photons_emitted = 0
        self.total_photons_detected = 0

    def get_fringe_visibility(self):
        """V = (I_max - I_min) / (I_max + I_min). V=1 perfect, V=0 none."""
        if self.total_photons_detected < 10:
            return 0.0
        smoothed = np.convolve(self.detector_counts.astype(float), np.ones(3) / 3, mode='same')
        I_max = np.max(smoothed)
        I_min = np.min(smoothed)
        if I_max + I_min < 1:
            return 0.0
        return (I_max - I_min) / (I_max + I_min)

    def get_theoretical_pattern(self):
        """Return the theoretical interference pattern for comparison."""
        return self._pattern.copy()

    def get_status_lines(self):
        """Return status text for HUD display."""
        lines = []
        lines.append(f"Double-Slit Experiment {'[ACTIVE]' if self.active else '[INACTIVE]'}")
        lines.append(f"  Photon lam = {self.wavelength * 1e9:.1f} nm  ({self.photon_energy_eV:.2f} eV)")
        lines.append(f"  Slit sep d = {self.slit_sep:.1f}  width a = {self.slit_width:.1f}")
        lines.append(f"  Emitted: {self.total_photons_emitted}  Detected: {self.total_photons_detected}")
        lines.append(f"  Fringe visibility V = {self.get_fringe_visibility():.3f}")
        lines.append(f"  Which-path: {'ON (no interference)' if self.which_path_detector else 'OFF (interference)'}")
        return lines

# Global double-slit experiment instance
_double_slit_exp = DoubleSlitExperiment()



class NanotechEntity:
    """Base class for nanotech items loaded into the simulation."""
    def __init__(self, pos):
        self.pos = np.array(pos[:3], dtype=float)
        self.vel = np.zeros(3)
        self.aura_active = False
        self.energy = 1.0
        self.alive = True
        self.mass = 1e-21
        self.type = 'nanotech'
        self.spawned_by = ''

    def update(self, dt, particles):
        pass

    def get_draw_info(self, camera):
        return []


