def _key_name_to_sym(name):
    """Convert a key name string (e.g. 'P', 'F1', '_1') to a pyglet key symbol int."""
    return getattr(pyglet.window.key, name, None)

def _sym_to_display(sym):
    """Convert a pyglet key symbol int to a short display string."""
    if sym is None:
        return '???'
    _SYM_SHORT = {
        'SEMICOLON': ';', 'MINUS': '-', 'COMMA': ',', 'PERIOD': '.',
        'SLASH': '/', 'BACKSLASH': '\\', 'APOSTROPHE': "'", 'GRAVE': '`',
        'EQUAL': '=', 'SPACE': 'SPC', 'TAB': 'TAB', 'RETURN': 'RET',
        'BACKSPACE': 'BKSP', 'DELETE': 'DEL', 'INSERT': 'INS',
        'HOME': 'HOME', 'END': 'END', 'PAGEUP': 'PGUP', 'PAGEDOWN': 'PGDN',
        'NUM_ADD': 'N+', 'NUM_SUBTRACT': 'N-', 'NUM_MULTIPLY': 'N*',
        'NUM_DIVIDE': 'N/', 'NUM_DECIMAL': 'N.',
        'NUMPAD_0': 'NP0', 'NUMPAD_1': 'NP1', 'NUMPAD_2': 'NP2',
        'NUMPAD_3': 'NP3', 'NUMPAD_4': 'NP4', 'NUMPAD_5': 'NP5',
        'NUMPAD_6': 'NP6', 'NUMPAD_7': 'NP7', 'NUMPAD_8': 'NP8',
        'NUMPAD_9': 'NP9',
    }
    s = pyglet.window.key.symbol_string(sym)
    if s in _SYM_SHORT:
        return _SYM_SHORT[s]
    # Clean up number key prefixes: '_1' -> '1'
    s = s.replace('_', '') if s.startswith('_') and len(s) == 2 else s
    return s

def _build_default_hotkey_map():
    """Build default hotkey_map dict: action_id -> pyglet key symbol int."""
    m = {}
    for aid, _dname, dkey in _HOTKEY_ACTIONS:
        m[aid] = _key_name_to_sym(dkey)
    return m

hotkey_map = _build_default_hotkey_map()

def _save_hotkeys():
    """Save current hotkey_map to JSON file."""
    data = {}
    for aid in hotkey_map:
        sym = hotkey_map[aid]
        data[aid] = pyglet.window.key.symbol_string(sym) if sym else ''
    try:
        with open(_HOTKEY_FILE, 'w') as f:
            _json_mod.dump(data, f, indent=2)
    except Exception as e:
        print(f"Failed to save hotkeys: {e}")

def _load_hotkeys():
    """Load hotkey_map from JSON file, falling back to defaults for missing keys."""
    global hotkey_map
    if not _os_mod.path.exists(_HOTKEY_FILE):
        return
    try:
        with open(_HOTKEY_FILE, 'r') as f:
            data = _json_mod.load(f)
        for aid in data:
            if aid in hotkey_map:
                sym_name = data[aid]
                sym = getattr(pyglet.window.key, sym_name, None)
                if sym is not None:
                    hotkey_map[aid] = sym
    except Exception as e:
        print(f"Failed to load hotkeys: {e}")

_load_hotkeys()

def _hotkey_display(action_id):
    """Get short display string for an action's current hotkey."""
    sym = hotkey_map.get(action_id)
    return _sym_to_display(sym)

