# ==============================================================================
# MUSIC MATHEMATICS & SPECTRUM ANALYSIS SYSTEM  (research-grade)
# Full frequency-domain analysis of the physics audio signal.
# Every audio update passes the signal through FFT, identifies notes/chords,
# and produces a spectrum the AI observers can reason about.
# Sources: Helmholtz "On the Sensations of Tone"; Sethares "Tuning, Timbre,
#   Spectrum, Scale"; Loy "Musimathics"; ASA/ISO 16:1975 standard pitch.
# ==============================================================================

# -- 1. EQUAL TEMPERAMENT: f(n) = 440 * 2^((n-69)/12) --
# MIDI note 69 = A4 = 440 Hz (ISO 16:1975 concert pitch)
_MT_A4_FREQ = 440.0
_MT_A4_MIDI = 69
_MT_NOTE_NAMES = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B']

def _midi_to_freq(midi_note):
    """Convert MIDI note number to frequency (Hz) in 12-TET."""
    return _MT_A4_FREQ * (2.0 ** ((midi_note - _MT_A4_MIDI) / 12.0))

def _freq_to_midi(freq):
    """Convert frequency (Hz) to fractional MIDI note number."""
    if freq <= 0:
        return 0
    return _MT_A4_MIDI + 12.0 * math.log2(freq / _MT_A4_FREQ)

def _freq_to_note_name(freq):
    """Convert frequency to closest note name + octave + cents deviation."""
    if freq <= 0:
        return 'rest', 0, 0.0
    midi = _freq_to_midi(freq)
    midi_round = int(round(midi))
    cents = (midi - midi_round) * 100.0
    note_idx = midi_round % 12
    octave = (midi_round // 12) - 1
    return _MT_NOTE_NAMES[note_idx], octave, cents

def _note_name_to_freq(name, octave=4):
    """Convert note name + octave to frequency. e.g. ('A', 4) -> 440.0"""
    idx = _MT_NOTE_NAMES.index(name) if name in _MT_NOTE_NAMES else 0
    midi = (octave + 1) * 12 + idx
    return _midi_to_freq(midi)

# Pre-compute all note frequencies for 10 octaves (C0 to B9, MIDI 12-131)
_MT_NOTE_FREQS = {}  # {(name, octave): freq_hz}
_MT_ALL_FREQS = []   # [(freq, name, octave, midi)] sorted by freq
for _mt_oct in range(0, 10):
    for _mt_ni, _mt_nn in enumerate(_MT_NOTE_NAMES):
        _mt_midi = (_mt_oct + 1) * 12 + _mt_ni
        _mt_f = _midi_to_freq(_mt_midi)
        _MT_NOTE_FREQS[(_mt_nn, _mt_oct)] = _mt_f
        _MT_ALL_FREQS.append((_mt_f, _mt_nn, _mt_oct, _mt_midi))
_MT_ALL_FREQS.sort()

