def _toggle_loadin(key, source='USER'):
    """Toggle an AI load-in effect.  source = 'USER' or observer name (e.g. 'OB1')."""
    if key in _ai_loadins:
        li = _ai_loadins[key]
        li['enabled'] = not li['enabled']
        li['source'] = source if li['enabled'] else None
        tag = '[AI]' if source not in ('USER', None) else '[USER]'
        _ai_loadins_log.append((simulation_time, tag, key, li['enabled']))
        _history_log.append((simulation_time, f"{tag} Load-In {'ON' if li['enabled'] else 'OFF'}: {li['name']}"))
        if len(_history_log) > _history_max:
            _history_log.pop(0)

def _any_loadins_active():
    """Return True if any visual/info load-in is enabled (audio excluded)."""
    return any(v['enabled'] and v['category'] != 'audio' for v in _ai_loadins.values())

