# â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
# SELF-ASSEMBLY & INFORMATION CODE SYSTEM
# Nature self-assembles matter into complex structures using physics/chemistry.
# Information codes (DNA-like and alternative) emerge from environmental
# conditions and direct further assembly. "Run Odds of User1" is a Monte Carlo
# mode that fast-forwards probabilistic outcomes until stable self-assembled
# structures or information codes are found.
# â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

class InformationCode:
    """A replicable molecular information sequence (like DNA but generalized).
    Multiple code chemistries can emerge depending on available elements."""
    CODE_TYPES = {
        'DNA':  {'bases': 'ATCG', 'elements': {6, 1, 8, 7, 15},
                 'name': 'Deoxyribonucleic Acid',
                 'desc': 'Carbon-based double helix, phosphate backbone'},
        'RNA':  {'bases': 'AUCG', 'elements': {6, 1, 8, 7, 15},
                 'name': 'Ribonucleic Acid',
                 'desc': 'Single-strand carbon, ribose sugar backbone'},
        'PNA':  {'bases': 'ATCG', 'elements': {6, 1, 8, 7},
                 'name': 'Peptide Nucleic Acid',
                 'desc': 'Peptide backbone, no phosphorus needed'},
        'XNA':  {'bases': 'ATCGX', 'elements': {6, 1, 8, 7, 15, 14},
                 'name': 'Xeno Nucleic Acid',
                 'desc': 'Non-standard sugars, silicon-doped'},
        'TNA':  {'bases': 'ATCG', 'elements': {6, 1, 8, 7, 15},
                 'name': 'Threose Nucleic Acid',
                 'desc': 'Simpler 4-carbon sugar, possible prebiotic'},
        'SiNA': {'bases': 'EFGH', 'elements': {14, 1, 8, 6},
                 'name': 'Silicon Nucleic Acid',
                 'desc': 'Silicon-based backbone, alien chemistry'},
    }

    def __init__(self, code_type, sequence='', origin_time=0.0):
        self.code_type = code_type
        self.sequence = sequence
        self.origin_time = origin_time
        self.replications = 0
        self.mutations = 0
        self.stability = 1.0
        self.pos = np.zeros(3)
        self.host_particle = None

    def can_replicate(self, available_z, avg_ke):
        """Check if replication conditions are met (elements + temperature)."""
        info = self.CODE_TYPES.get(self.code_type, {})
        required = info.get('elements', set())
        if not required.issubset(available_z):
            return False
        if avg_ke < 1e-22 or avg_ke > 1e-19:
            return False
        return len(self.sequence) >= 3 and self.stability > 0.3

    def replicate(self, sim_time):
        """Create a copy with possible mutation."""
        new_seq = list(self.sequence)
        mutated = False
        bases = self.CODE_TYPES[self.code_type]['bases']
        for i in range(len(new_seq)):
            if random.random() < 0.001:
                new_seq[i] = random.choice(bases)
                mutated = True
        child = InformationCode(self.code_type, ''.join(new_seq), sim_time)
        child.mutations = self.mutations + (1 if mutated else 0)
        self.replications += 1
        return child

    def __repr__(self):
        info = self.CODE_TYPES.get(self.code_type, {})
        return f"{info.get('name', self.code_type)}[{len(self.sequence)}bp]"


class AssemblyStructure:
    """A self-assembled structure formed from multiple particles/atoms."""
    def __init__(self, name, parts, stability, origin_time):
        self.name = name
        self.particles = list(parts)
        self.stability = stability
        self.origin_time = origin_time
        self.info_codes = []
        self.complexity = len(parts)
        self.is_alive = False
        self.center = np.mean([p.pos for p in parts], axis=0) if parts else np.zeros(3)

    def update_center(self, particle_list):
        living = [p for p in self.particles if p in particle_list]
        if living:
            self.center = np.mean([p.pos for p in living], axis=0)
            self.complexity = len(living)
        else:
            self.stability = 0.0


class SelfAssemblyEngine:
    """Monitors the simulation for self-assembly and information code emergence.
    Uses existing physics (gravity, EM, bonds, van der Waals) to detect when
    matter self-assembles into complex structures â€” like nature does.
    Run Odds mode: Monte Carlo search for stable assemblies via fast-forward."""

    def __init__(self):
        self.structures = []
        self.info_codes = []
        self.check_interval = 30
        self.frame_counter = 0
        self.total_assemblies = 0
        self.total_codes = 0
        # Run Odds of User1 state
        self.run_odds_active = False
        self.run_odds_iterations = 0
        self.run_odds_found_assemblies = 0
        self.run_odds_found_codes = 0
        self.run_odds_max_iter = 100000
        self.run_odds_start_time = 0.0
        self.run_odds_last_event = ''
        self.run_odds_events = []
        self.run_odds_target = None       # key of target life form from KNOWN_LIFE_FORMS
        self.run_odds_target_name = ''    # display name of target life form
        # Deterministic forward search state
        self._ro_pre_snapshot = None       # Full particle states before search started
        self._ro_pre_sim_time = 0.0
        self._ro_pre_expansion = 1.0
        self._ro_pre_cloud_r = 100.0
        self._ro_pre_V_total = 0.0
        self._ro_pre_V_pct = 0.0
        self._ro_found_life_atoms = []    # Atoms of found life form for camera targeting
        self._ro_particle_hash = 0        # Hash of particle config for change detection
        self._ro_discovery_time = None    # sim_time when life was found (for history)

    def particle_config_hash(self, particle_list):
        """Hash the current particle configuration for change detection."""
        # Simple hash for now: sum of particle positions and velocities
        return sum(p.pos.sum() + p.vel.sum() for p in particle_list)

    def scan_for_assembly(self, particle_list, sim_time):
        """Periodic scan for assembly opportunities and code emergence."""
        self.frame_counter += 1
        if self.frame_counter % self.check_interval != 0:
            return
        atoms = [(p, getattr(p, 'Z', 0)) for p in particle_list if getattr(p, 'is_atom', False)]
        if len(atoms) < 2:
            return
        self._check_bonded_structures(atoms, particle_list, sim_time)
        self._check_code_emergence(atoms, sim_time)
        self._check_code_replication(atoms, sim_time)
        # Prune dead structures
        for s in self.structures:
            s.update_center(particle_list)
        self.structures = [s for s in self.structures if s.stability > 0.01]
        # Cap codes
        if len(self.info_codes) > 200:
            self.info_codes.sort(key=lambda c: c.stability * (1 + c.replications), reverse=True)
            self.info_codes = self.info_codes[:200]

    def _check_bonded_structures(self, atoms, particle_list, sim_time):
        """Detect clusters of bonded atoms forming larger structures."""
        particle_set = set(particle_list)
        visited_global = set()
        for a, z in atoms:
            if a in visited_global:
                continue
            bonds = getattr(a, 'bonds', [])
            if not bonds:
                continue
            cluster = self._bfs_bonds(a, particle_set)
            visited_global.update(cluster)
            if len(cluster) < 3:
                continue
            # Already tracked?
            cset = frozenset(id(p) for p in cluster)
            already = False
            for s in self.structures:
                if frozenset(id(p) for p in s.particles) == cset:
                    already = True
                    break
            if already:
                continue
            z_set = {getattr(p, 'Z', 0) for p in cluster}
            name = self._name_assembly(cluster, z_set)
            stab = min(1.0, 0.5 + len(cluster) * 0.05)
            new_s = AssemblyStructure(name, cluster, stab, sim_time)
            # Check if it contains info codes
            if any(6 in z_set and 7 in z_set and 8 in z_set for _ in [0]):
                new_s.is_alive = len(self.info_codes) > 0
            self.structures.append(new_s)
            self.total_assemblies += 1

    @staticmethod
    def _bfs_bonds(start, particle_set):
        visited = set()
        queue = [start]
        while queue:
            cur = queue.pop(0)
            if cur in visited:
                continue
            visited.add(cur)
            for bonded in getattr(cur, 'bonds', []):
                if bonded in particle_set and bonded not in visited:
                    queue.append(bonded)
        return list(visited)

    @staticmethod
    def _name_assembly(cluster, z_set):
        n = len(cluster)
        organic = {1, 6, 7, 8, 15, 16}
        if z_set.issubset(organic):
            if 6 in z_set and 7 in z_set and 8 in z_set and n >= 15:
                return f'Organic Complex ({n} atoms)'
            elif 6 in z_set and 7 in z_set:
                return f'Amino Group ({n} atoms)'
            elif n >= 8:
                return f'Organic Chain ({n} atoms)'
            else:
                return f'Organic Fragment ({n} atoms)'
        elif 14 in z_set:
            return f'Silicate Structure ({n} atoms)'
        elif z_set.issubset({26, 28, 27, 29, 24, 25}):
            return f'Metallic Cluster ({n} atoms)'
        else:
            return f'Molecular Assembly ({n} atoms)'

    def _check_code_emergence(self, atoms, sim_time):
        """Check if environmental conditions allow spontaneous code emergence.
        Nature develops information codes when the right elements are nearby
        at the right temperature â€” like prebiotic chemistry on early Earth.
        During Run Odds mode, the KE window is broadened and probability boosted
        to accelerate discovery of viable chemistries."""
        z_atoms = {}
        for a, z in atoms:
            z_atoms.setdefault(z, []).append(a)
        _ro = self.run_odds_active
        # KE window: normal 1e-22..1e-19; Run Odds broadens to 1e-24..1e-17
        _ke_lo = 1e-24 if _ro else 1e-22
        _ke_hi = 1e-17 if _ro else 1e-19
        _ke_peak = 5e-21  # ~360K equivalent
        _prob_boost = 100.0 if _ro else 1.0  # Run Odds accelerates emergence
        _prox_r = 60.0 if _ro else 30.0  # wider proximity scan during Run Odds
        for code_type, info in InformationCode.CODE_TYPES.items():
            required = info['elements']
            if not all(z in z_atoms for z in required):
                continue
            candidates = []
            for z in required:
                candidates.extend(z_atoms[z])
            if len(candidates) < 4:
                continue
            # Scan multiple cluster centers (up to 3) for broader coverage
            _n_centers = 3 if _ro else 1
            _centers_tried = []
            for _ci in range(min(_n_centers, max(1, len(candidates) // 4))):
                if _ci == 0:
                    center = np.mean([a.pos for a in candidates[:12]], axis=0)
                else:
                    # Random sub-sample for additional cluster center
                    _sample = random.sample(candidates, min(6, len(candidates)))
                    center = np.mean([a.pos for a in _sample], axis=0)
                # Skip if too close to a previously tried center
                if any(np.linalg.norm(center - pc) < _prox_r * 0.5 for pc in _centers_tried):
                    continue
                _centers_tried.append(center)
                nearby = [a for a in candidates if np.linalg.norm(a.pos - center) < _prox_r]
                nearby_z = {getattr(a, 'Z', 0) for a in nearby}
                if not required.issubset(nearby_z):
                    continue
                avg_ke = np.mean([a.energy_kin for a in nearby]) if nearby else 0
                if avg_ke < _ke_lo or avg_ke > _ke_hi:
                    continue
                n_nearby = len(nearby)
                # Temperature factor: Gaussian-like peak around _ke_peak
                _ke_ratio = abs(avg_ke - _ke_peak) / max(_ke_peak, 1e-30)
                temp_factor = max(0.01, math.exp(-_ke_ratio * 0.5))
                # Element diversity bonus: more unique elements = higher probability
                _div_bonus = 1.0 + 0.2 * (len(nearby_z) - len(required))
                prob = 1e-8 * n_nearby * temp_factor * _div_bonus * _prob_boost
                prob = max(0, min(prob, 5e-3 if _ro else 1e-4))
                if random.random() < prob:
                    bases = info['bases']
                    seq_len = random.randint(3, 12 if _ro else 8)
                    seq = ''.join(random.choice(bases) for _ in range(seq_len))
                    new_code = InformationCode(code_type, seq, sim_time)
                    new_code.pos = center.copy()
                    self.info_codes.append(new_code)
                    self.total_codes += 1
                    break  # One emergence per code type per scan

    def _check_code_replication(self, atoms, sim_time):
        """Existing codes replicate when conditions allow."""
        if not self.info_codes:
            return
        z_set = {z for _, z in atoms}
        all_a = [a for a, _ in atoms]
        avg_ke = np.mean([a.energy_kin for a in all_a]) if all_a else 0
        for code in list(self.info_codes):
            if code.can_replicate(z_set, avg_ke):
                if random.random() < 0.001 * code.stability:
                    child = code.replicate(sim_time)
                    child.pos = code.pos + (np.random.randn(3) * 5.0)
                    self.info_codes.append(child)
                    self.total_codes += 1

    def run_odds_step(self, particle_list, sim_time):
        """One deterministic forward search iteration for Run Odds.
        Returns 'found' if life form discovered, True on other notable event,
        False otherwise. Automatically seeds missing elements and detects
        atom configuration changes that require search recalculation."""
        if not self.run_odds_active:
            return False
        self.run_odds_iterations += 1
        # Atom change detection: if particle config changed, recalculate search
        # (quantum physics / determinism shifts when atoms are added/removed/changed)
        if self.run_odds_iterations % 50 == 0:
            _new_hash = self.particle_config_hash(particle_list)
            if abs(_new_hash - self._ro_particle_hash) > 1e-6:
                self._ro_particle_hash = _new_hash
                self._ro_pre_snapshot = _record_particle_states(particle_list)
                self._ro_pre_sim_time = sim_time
                evt = f"Determinism shifted â€” recalculating search (iter {self.run_odds_iterations})"
                self.run_odds_last_event = evt
                self.run_odds_events.append((sim_time, evt))
        # Every 500 iterations, seed missing elements if needed
        if self.run_odds_iterations % 500 == 0:
            self._seed_missing_elements(particle_list, sim_time)
        old_ci = self.check_interval
        self.check_interval = 1
        self.frame_counter = 0
        self.scan_for_assembly(particle_list, sim_time)
        self.check_interval = old_ci
        found = False
        if self.total_assemblies > self.run_odds_found_assemblies:
            self.run_odds_found_assemblies = self.total_assemblies
            evt = f"Assembly #{self.total_assemblies} found at T={sim_time:.1f}s"
            self.run_odds_last_event = evt
            self.run_odds_events.append((sim_time, evt))
            found = True
        if self.total_codes > self.run_odds_found_codes:
            self.run_odds_found_codes = self.total_codes
            evt = f"Code #{self.total_codes} emerged at T={sim_time:.1f}s"
            self.run_odds_last_event = evt
            self.run_odds_events.append((sim_time, evt))
            found = True
        # Check if target life form has naturally occurred â€” jump to discovery
        if self.run_odds_target and self._check_target_life_form(particle_list, sim_time):
            global time_factor
            self.run_odds_active = False
            _discovered_name = self.run_odds_target_name
            evt = f"FOUND: {_discovered_name} at T={sim_time:.1f}s ({self.run_odds_iterations} iter)"
            self.run_odds_last_event = evt
            self.run_odds_events.append((sim_time, evt))
            # Keep target info for HUD display; clear search target
            self.run_odds_target = None
            # Restore pre-search time factor (stop fast-forward)
            if hasattr(self, '_pre_run_odds_tf'):
                time_factor = self._pre_run_odds_tf
            return 'found'
        if self.run_odds_iterations >= self.run_odds_max_iter:
            self.run_odds_active = False
            self.run_odds_last_event = f'Limit reached ({self.run_odds_max_iter} iter)'
        return found

    def _seed_missing_elements(self, particle_list, sim_time):
        """Auto-spawn atoms of elements needed for information code emergence
        if they are missing from the simulation. Nature needs C, H, O, N, P
        (and optionally Si) to develop codes â€” Run Odds adds the matter needed."""
        present_z = set()
        for p in particle_list:
            if getattr(p, 'is_atom', False):
                present_z.add(getattr(p, 'Z', 0))
        # Essential elements for code emergence: C(6), H(1), O(8), N(7), P(15)
        needed = {1, 6, 7, 8, 15} - present_z
        if not needed:
            return
        # Find a spawn center near existing atoms
        atom_positions = [p.pos for p in particle_list if getattr(p, 'is_atom', False)]
        if atom_positions:
            center = np.mean(atom_positions, axis=0)
        else:
            center = np.zeros(3)
        z_to_sym = {1: ('H', 1), 6: ('C', 12), 7: ('N', 14), 8: ('O', 16), 15: ('P', 31)}
        for z in needed:
            sym, a_mass = z_to_sym.get(z, ('?', z * 2))
            n_neutrons = a_mass - z
            spawn_pos = center + np.random.uniform(-50.0, 50.0, 3)
            subs = []
            for _ in range(z):
                subs.append(Particle('proton', pos=spawn_pos.copy()))
            for _ in range(n_neutrons):
                subs.append(Particle('neutron', pos=spawn_pos.copy()))
            for _ in range(z):
                subs.append(Particle('electron', pos=spawn_pos.copy()))
            new_atom = Atom(sym, a_mass, subs, spawn_pos.copy())
            particle_list.append(new_atom)
            evt = f"Seeded {sym} (Z={z}) for code emergence"
            self.run_odds_last_event = evt
            self.run_odds_events.append((sim_time, evt))

    def toggle_run_odds(self, sim_time, target_key=None, target_name='',
                        particle_list=None):
        """Toggle Run Odds of User1 mode. When activated with a target life form,
        runs deterministic forward search through simulated time until the target
        naturally occurs. Saves pre-search snapshot for time travel back.
        target_key must be set (from life forms list) to activate.
        If already active, calling this deactivates (stop odds)."""
        global time_factor, expansion_scale, cloud_radius, V_total, V_total_percent
        if target_key is not None and not self.run_odds_active:
            # Activate with target life form
            self.run_odds_active = True
            self.run_odds_target = target_key
            self.run_odds_target_name = target_name
            self.run_odds_iterations = 0
            self.run_odds_found_assemblies = self.total_assemblies
            self.run_odds_found_codes = self.total_codes
            self.run_odds_start_time = sim_time
            self.run_odds_last_event = f'Searching for {target_name}...'
            self.run_odds_events = []
            self._pre_run_odds_tf = time_factor
            self._ro_found_life_atoms = []
            self._ro_discovery_time = None
            # Save full pre-search snapshot for deterministic time travel back
            if particle_list is not None:
                self._ro_pre_snapshot = _record_particle_states(particle_list)
                self._ro_particle_hash = self.particle_config_hash(particle_list)
            self._ro_pre_sim_time = sim_time
            self._ro_pre_expansion = expansion_scale
            self._ro_pre_cloud_r = cloud_radius
            self._ro_pre_V_total = V_total
            self._ro_pre_V_pct = V_total_percent
            # Auto-accelerate to 30% speed minimum for faster deterministic search
            if time_factor < 0.3:
                time_factor = 0.3
        elif self.run_odds_active:
            # Deactivate
            self.run_odds_active = False
            self.run_odds_last_event = f'Stopped ({self.run_odds_iterations} iter)'
            self.run_odds_target = None
            self.run_odds_target_name = ''
            # Restore previous time factor
            if hasattr(self, '_pre_run_odds_tf'):
                time_factor = self._pre_run_odds_tf

    def _check_target_life_form(self, particle_list, sim_time):
        """Check if the target life form has naturally occurred in the simulation.
        Each life form has specific detection criteria based on its KNOWN_LIFE_FORMS entry.
        Returns True if the target life form's conditions are met.
        On success, stores the atoms of the best matching structure in
        self._ro_found_life_atoms for camera auto-targeting."""
        target = None
        for lf in KNOWN_LIFE_FORMS:
            if lf['key'] == self.run_odds_target:
                target = lf
                break
        if target is None:
            return False
        # Check required elements are present in the simulation
        if target['elements']:
            present_z = {getattr(p, 'Z', 0) for p in particle_list if getattr(p, 'is_atom', False)}
            if not target['elements'].issubset(present_z):
                return False
        # Check minimum bonded atom count in any structure
        min_atoms = target.get('min_atoms', 1)
        matching_structures = [s for s in self.structures if s.complexity >= min_atoms and s.stability > 0.3]
        if not matching_structures and min_atoms > 1:
            return False
        # Check information code requirement
        if target.get('requires_code', False):
            if not self.info_codes:
                return False
            code_type = target.get('code_type')
            if code_type:
                if not any(c.code_type == code_type and len(c.sequence) >= 3 for c in self.info_codes):
                    return False
            else:
                if not any(len(c.sequence) >= 3 for c in self.info_codes):
                    return False
        # Check minimum codes for unified systems
        min_codes = target.get('min_codes', 0)
        if min_codes > 0:
            if len([c for c in self.info_codes if len(c.sequence) >= 3]) < min_codes:
                return False
        # Check for self-replicating machine (special case â€” needs replicating codes)
        if target['key'] == 'machine_life':
            replicating = any(c.replications > 0 for c in self.info_codes)
            if not replicating and not matching_structures:
                return False
        # Success â€” collect atoms of the largest matching structure for camera targeting
        if matching_structures:
            best = max(matching_structures, key=lambda s: s.complexity)
            self._ro_found_life_atoms = [p for p in best.particles if p in particle_list]
        else:
            # Fallback: target all atoms with required elements
            self._ro_found_life_atoms = [p for p in particle_list
                                         if getattr(p, 'is_atom', False)
                                         and getattr(p, 'Z', 0) in target.get('elements', set())]
        self._ro_discovery_time = sim_time
        return True


