# â”€â”€ Symbol â€” enriched symbolic reasoning atom â”€â”€

class _ObsSymbol:
    __slots__ = ('value','name','associations','confidence','access_count',
                 'last_accessed','inference_links','history','embedding')
    def __init__(self, value, name=""):
        self.value = value; self.name = name; self.associations = {}
        self.confidence = 0.5; self.access_count = 0
        self.last_accessed = time.time(); self.inference_links = {}
        self.history = deque(maxlen=80)
        self.embedding = np.random.randn(16).astype(np.float32) * 0.1
    def operate(self, other):
        if self.value == 0 or other.value == 0:
            return _ObsSymbol(0, f"{self.name}_n_{other.name}")
        rv = self.value * other.value
        r = _ObsSymbol(rv, f"{self.name}_{'p' if rv>0 else 'n'}_{other.name}")
        r.confidence = (self.confidence + other.confidence) / 2
        r.embedding = (self.embedding + other.embedding) * 0.5
        self.inference_links[other.name] = self.inference_links.get(other.name, 0) + 0.1
        return r
    def evolve(self, phi=0.0):
        self.last_accessed = time.time(); self.access_count += 1
        self.history.append((self.value, phi, self.last_accessed))
        if random.random() > (0.8 - phi * 0.3):
            self.value = -self.value if self.value != 0 else random.choice([-1, 1])
        for a in list(self.associations):
            self.associations[a] = np.clip(
                self.associations[a] + random.uniform(-0.1, 0.1) * (1 + phi), -1, 1)
            if abs(self.associations[a]) < 0.01: del self.associations[a]
        for lk in list(self.inference_links):
            self.inference_links[lk] *= 0.99
            if self.inference_links[lk] < 0.01: del self.inference_links[lk]
        self.confidence = float(np.clip(self.confidence + (phi - 0.5) * 0.05, 0, 1))
        self.embedding += np.random.randn(16).astype(np.float32) * 0.01 * phi
    def relevance_score(self):
        age_s = time.time() - self.last_accessed
        return (self.confidence * 0.4 + 1.0 / (1.0 + age_s / 3600) * 0.3
                + min(1.0, self.access_count / 100) * 0.3)

