# â”€â”€ Numpy utilities â”€â”€

def _obs_np_gelu(x):
    x = np.clip(np.nan_to_num(x, nan=0.0, posinf=1e4, neginf=-1e4), -20, 20)
    return 0.5 * x * (1.0 + np.tanh(np.sqrt(2.0 / np.pi) * (x + 0.044715 * x**3)))

def _obs_np_softmax(x, axis=-1):
    x = np.nan_to_num(x, nan=0.0, posinf=1e4, neginf=-1e4)
    e = np.exp(x - np.max(x, axis=axis, keepdims=True))
    return e / (e.sum(axis=axis, keepdims=True) + 1e-8)

def _obs_np_layer_norm(x, eps=1e-5):
    mu = x.mean(axis=-1, keepdims=True)
    var = x.var(axis=-1, keepdims=True)
    return (x - mu) / np.sqrt(var + eps)

def _obs_np_linear(x, w, b):
    x = np.nan_to_num(x, nan=0.0, posinf=1e4, neginf=-1e4)
    w = np.nan_to_num(w, nan=0.0, posinf=1e4, neginf=-1e4)
    return x @ w.T + b

def _obs_shannon_entropy(arr):
    a = np.asarray(arr, dtype=np.float32).flatten()
    if len(a) == 0: return 0.0
    rng = a.max() - a.min()
    if not np.all(np.isfinite(a)):
        a = np.nan_to_num(a, nan=0.0, posinf=1e6, neginf=-1e6)
        rng = a.max() - a.min()
    if rng > 0: a = (a - a.min()) / rng
    bins = max(8, min(64, int(np.sqrt(len(a)))))
    h, _ = np.histogram(a, bins=bins, range=(0, 1))
    p = h / (h.sum() + 1e-12); p = p[p > 0]
    return float(-np.sum(p * np.log2(p + 1e-12)))

# â”€â”€ Numpy modules (fallback when torch unavailable) â”€â”€

class _NpExpert:
    def __init__(self, d_in, d_out):
        s = np.sqrt(2.0 / d_in)
        self.w1 = np.random.randn(d_out*2, d_in).astype(np.float32) * s
        self.b1 = np.zeros(d_out*2, dtype=np.float32)
        self.w2 = np.random.randn(d_out, d_out*2).astype(np.float32) * s
        self.b2 = np.zeros(d_out, dtype=np.float32)
    def __call__(self, x):
        h = _obs_np_gelu(_obs_np_linear(x.reshape(1,-1), self.w1, self.b1))
        return _obs_np_layer_norm(_obs_np_linear(h, self.w2, self.b2)).flatten()

class _NpMoE:
    def __init__(self, d_in, d_out, n_experts=_OBS_N_EXPERTS, top_k=_OBS_TOP_K):
        self.experts = [_NpExpert(d_in, d_out) for _ in range(n_experts)]
        self.gate_w = np.random.randn(n_experts, d_in).astype(np.float32) * 0.1
        self.gate_b = np.zeros(n_experts, dtype=np.float32)
        self.top_k = top_k
        self.last_gate_probs = np.zeros(n_experts)
    def __call__(self, x):
        logits = _obs_np_linear(x.reshape(1,-1), self.gate_w, self.gate_b).flatten()
        probs = _obs_np_softmax(logits); self.last_gate_probs = probs
        top_idx = np.argsort(probs)[-self.top_k:]
        top_p = probs[top_idx]; top_p = top_p / (top_p.sum() + 1e-8)
        out = np.zeros(_OBS_HS, dtype=np.float32)
        for i, idx in enumerate(top_idx):
            out += top_p[i] * self.experts[idx](x)
        return out

class _NpSSM:
    def __init__(self, d_model, d_state=_OBS_SSM_N):
        self.d = d_model; self.n = d_state
        self.A = -np.exp(np.random.randn(d_model, d_state).astype(np.float32) * 0.5)
        self.B_proj = np.random.randn(d_state, d_model).astype(np.float32) * 0.1
        self.C_proj = np.random.randn(d_model, d_state).astype(np.float32) * 0.1
        self.dt_proj = np.random.randn(d_model).astype(np.float32) * 0.1
        self.state = np.zeros((d_model, d_state), dtype=np.float32)
    def __call__(self, x):
        x = x.flatten()[:self.d]
        if len(x) < self.d: x = np.pad(x, (0, self.d - len(x)))
        dt = np.clip(1.0 / (1.0 + np.exp(-self.dt_proj * x)), 0.001, 1.0)
        B = _obs_np_softmax(self.B_proj @ x)
        self.state = self.state * np.exp(self.A * dt[:, None]) + np.outer(x * dt, B)
        return (self.state @ self.C_proj.T).diagonal()

class _NpMemoryBank:
    def __init__(self, n_slots=_OBS_MEM_SLOTS, d_slot=_OBS_MEM_DIM):
        self.n = n_slots; self.d = d_slot
        self.keys = np.random.randn(n_slots, d_slot).astype(np.float32) * 0.01
        self.values = np.zeros((n_slots, d_slot), dtype=np.float32)
        self.usage = np.zeros(n_slots, dtype=np.float32)
    def read(self, query):
        q = query.flatten()[:self.d]
        if len(q) < self.d: q = np.pad(q, (0, self.d - len(q)))
        sim = self.keys @ q / (np.linalg.norm(self.keys, axis=1) * np.linalg.norm(q) + 1e-8)
        w = _obs_np_softmax(sim * 10.0); self.usage = 0.9 * self.usage + 0.1 * w
        return w @ self.values
    def write(self, key, value):
        k = key.flatten()[:self.d]; v = value.flatten()[:self.d]
        if len(k) < self.d: k = np.pad(k, (0, self.d - len(k)))
        if len(v) < self.d: v = np.pad(v, (0, self.d - len(v)))
        idx = int(np.argmin(self.usage))
        self.keys[idx] = 0.8 * self.keys[idx] + 0.2 * k
        self.values[idx] = 0.7 * self.values[idx] + 0.3 * v
        self.usage[idx] = 1.0

class _NpPredictiveCoding:
    def __init__(self, dims, n_levels=_OBS_PC_LEVELS):
        self.n_levels = n_levels
        self.predictions = [np.zeros(dims, dtype=np.float32) for _ in range(n_levels)]
        self.errors = [np.zeros(dims, dtype=np.float32) for _ in range(n_levels)]
        self.precisions = [np.ones(dims, dtype=np.float32) * 0.5 for _ in range(n_levels)]
        self.weights = [np.random.randn(dims, dims).astype(np.float32) * 0.1
                        for _ in range(n_levels)]
        self.free_energy = 0.0
        self.surprise_history = deque(maxlen=200)
    def update(self, sensory_input):
        x = sensory_input.flatten(); d = self.predictions[0].shape[0]
        if len(x) < d: x = np.pad(x, (0, d - len(x)))
        elif len(x) > d: x = x[:d]
        total_fe = 0.0
        self.errors[0] = (x - self.predictions[0]) * self.precisions[0]
        total_fe += float(np.mean(self.errors[0] ** 2))
        for lvl in range(1, self.n_levels):
            pred_below = _obs_np_layer_norm(_obs_np_gelu(self.weights[lvl] @ self.predictions[lvl]))[:d]
            self.errors[lvl] = (self.predictions[lvl-1] - pred_below) * self.precisions[lvl]
            total_fe += float(np.mean(self.errors[lvl] ** 2))
        total_fe /= self.n_levels
        for lvl in range(self.n_levels):
            self.predictions[lvl] += 0.15 * self.errors[lvl]
            self.predictions[lvl] = np.clip(self.predictions[lvl], -10.0, 10.0)
            self.precisions[lvl] = np.clip(
                self.precisions[lvl] + 0.002 * (self.errors[lvl]**2 - self.precisions[lvl]), 0.01, 5.0)
            m = min(16, d)
            self.weights[lvl][:m,:m] += 0.005 * np.outer(self.errors[lvl][:m], self.predictions[lvl][:m])
            self.weights[lvl] = np.clip(self.weights[lvl], -5.0, 5.0)
        self.free_energy = total_fe; self.surprise_history.append(total_fe)
        return self.errors[0]

class _NpGlobalWorkspace:
    def __init__(self, d_model):
        self.d = d_model; self.workspace = np.zeros(d_model, dtype=np.float32)
        self.salience_history = deque(maxlen=50)
    def compete_and_broadcast(self, module_outputs):
        saliences = {}
        for name, vec in module_outputs.items():
            v = vec.flatten()[:self.d]
            if len(v) < self.d: v = np.pad(v, (0, self.d - len(v)))
            saliences[name] = float(np.sum(v**2)) * 0.4 + float(np.sum((v - self.workspace[:len(v)])**2)) * 0.6
        if not saliences: return self.workspace
        winner = max(saliences, key=saliences.get)
        self.salience_history.append((time.time(), winner, saliences[winner]))
        wv = module_outputs[winner].flatten()[:self.d]
        if len(wv) < self.d: wv = np.pad(wv, (0, self.d - len(wv)))
        self.workspace = 0.6 * self.workspace + 0.4 * wv
        return self.workspace

class _NpVisionEncoder:
    def __init__(self, out_dim=_OBS_VIS_DIM):
        self.out_dim = out_dim
        self.k1 = np.random.randn(8, 27).astype(np.float32) * 0.15
        self.b1 = np.zeros(8, dtype=np.float32)
        self.k2 = np.random.randn(out_dim, 8*9).astype(np.float32) * 0.1
        self.b2 = np.zeros(out_dim, dtype=np.float32)
    def encode(self, frame):
        if frame is None or frame.size == 0:
            return np.zeros(self.out_dim, dtype=np.float32)
        if frame.dtype == np.uint8: frame = frame.astype(np.float32) / 255.0
        if frame.ndim != 3: return np.zeros(self.out_dim, dtype=np.float32)
        h, w = frame.shape[:2]
        positions = [(h//2,w//2),(0,0),(0,max(0,w-3)),(max(0,h-3),0),(max(0,h-3),max(0,w-3)),
                     (h//4,w//4),(h//4,3*w//4),(3*h//4,w//4),(3*h//4,3*w//4)]
        patches = []
        for py, px in positions:
            py = max(0, min(py, h-3)); px = max(0, min(px, w-3))
            p = frame[py:py+3, px:px+3, :].flatten()
            if len(p) < 27: p = np.pad(p, (0, 27-len(p)))
            patches.append(p[:27])
        patches = np.array(patches)
        h1 = _obs_np_gelu(patches @ self.k1.T + self.b1)
        h1_pooled = h1.mean(axis=0)
        feat = np.tile(h1_pooled, 9)[:72]
        return _obs_np_gelu(feat @ self.k2.T + self.b2)

# â”€â”€ PyTorch modules (used when available â€” much more powerful) â”€â”€

if _TORCH:
    class _TorchExpert(nn.Module):
        def __init__(self, d_in, d_out, d_ff=None):
            super().__init__()
            d_ff = d_ff or d_out * 2
            self.w_gate = nn.Linear(d_in, d_ff, bias=False)
            self.w_up   = nn.Linear(d_in, d_ff, bias=False)
            self.w_down = nn.Linear(d_ff, d_out, bias=False)
            self.norm = nn.LayerNorm(d_out)
        def forward(self, x):
            return self.norm(self.w_down(F_torch.silu(self.w_gate(x)) * self.w_up(x)))

    class _TorchSparseMoE(nn.Module):
        def __init__(self, d_in, d_out, n_experts=_OBS_N_EXPERTS, top_k=_OBS_TOP_K):
            super().__init__()
            self.experts = nn.ModuleList([_TorchExpert(d_in, d_out) for _ in range(n_experts)])
            self.gate = nn.Linear(d_in, n_experts, bias=False)
            self.top_k = top_k; self.n_experts = n_experts
            self.aux_loss = 0.0; self.last_gate_probs = None
        def forward(self, x):
            logits = self.gate(x)
            probs = F_torch.softmax(logits, dim=-1); self.last_gate_probs = probs.detach()
            topk_v, topk_i = torch.topk(probs, self.top_k, dim=-1)
            topk_v = topk_v / (topk_v.sum(dim=-1, keepdim=True) + 1e-8)
            avg_p = probs.mean(dim=0)
            self.aux_loss = (self.n_experts * (avg_p * avg_p).sum()).detach().item()
            # Non-inplace expert accumulation (avoids autograd version errors)
            parts = []
            for i in range(self.top_k):
                idx = topk_i[..., i]; wt = topk_v[..., i:i+1]
                for e in range(self.n_experts):
                    mask = (idx == e)
                    if mask.any(): parts.append(wt[mask] * self.experts[e](x[mask]))
            if parts:
                out = parts[0]
                for _p in parts[1:]:
                    out = out + _p
            else:
                out = torch.zeros(x.shape[0], self.experts[0].w_down.out_features)
            return out

    class _TorchSelectiveSSM(nn.Module):
        def __init__(self, d_model, d_state=_OBS_SSM_N):
            super().__init__()
            self.d = d_model; self.n = d_state
            self.A_log = nn.Parameter(torch.log(torch.randn(d_model, d_state).abs() + 0.1))
            self.B_proj = nn.Linear(d_model, d_state, bias=False)
            self.C_proj = nn.Linear(d_state, d_model, bias=False)
            self.dt_proj = nn.Linear(d_model, d_model, bias=True)
            nn.init.constant_(self.dt_proj.bias, -3.0)
            self.norm = nn.LayerNorm(d_model)
            self.register_buffer('state', torch.zeros(1, d_model, d_state))
        def forward(self, x):
            A = -self.A_log.exp()
            dt = F_torch.softplus(self.dt_proj(x)).unsqueeze(-1)
            B = self.B_proj(x).unsqueeze(1)
            dA = torch.exp(A.unsqueeze(0) * dt)
            dB = x.unsqueeze(-1) * dt * B
            new_state = (self.state.detach() * dA + dB).detach()
            self.state.data.copy_(new_state)
            y = (new_state * self.C_proj.weight.unsqueeze(0)).sum(dim=-1)
            return self.norm(y + x)

    class _TorchMemoryBank(nn.Module):
        """DNC-style differentiable memory."""
        def __init__(self, n_slots=_OBS_MEM_SLOTS, d_slot=_OBS_MEM_DIM):
            super().__init__()
            self.n = n_slots; self.d = d_slot
            self.register_buffer('keys', torch.randn(n_slots, d_slot) * 0.01)
            self.register_buffer('values', torch.zeros(n_slots, d_slot))
            self.register_buffer('usage', torch.zeros(n_slots))
            self.read_head  = nn.Linear(d_slot, d_slot, bias=False)
            self.write_head = nn.Linear(d_slot, d_slot, bias=False)
        def read(self, query):
            q = self.read_head(query)
            sim = F_torch.cosine_similarity(self.keys.detach().unsqueeze(0), q.unsqueeze(1), dim=-1)
            w = F_torch.softmax(sim * 10.0, dim=-1)
            with torch.no_grad():
                self.usage.data.copy_((0.9 * self.usage + 0.1 * w.squeeze(0)).detach())
            return w @ self.values.detach()
        def write(self, key, value):
            k = self.write_head(key).detach(); v = value.detach()
            idx = int(self.usage.argmin())
            with torch.no_grad():
                self.keys.data[idx]   = 0.8 * self.keys.data[idx]   + 0.2 * k.squeeze(0)
                self.values.data[idx] = 0.7 * self.values.data[idx] + 0.3 * v.squeeze(0)
                self.usage.data[idx]  = 1.0

    class _TorchPredictiveCoding(nn.Module):
        """Hierarchical Predictive Coding - Free Energy qualia."""
        def __init__(self, d_model, n_levels=_OBS_PC_LEVELS):
            super().__init__()
            self.n_levels = n_levels
            self.pred_nets = nn.ModuleList([
                nn.Sequential(nn.Linear(d_model, d_model), nn.SiLU(),
                              nn.Linear(d_model, d_model))
                for _ in range(n_levels)])
            self.precisions = nn.ParameterList([
                nn.Parameter(torch.ones(d_model) * 0.5) for _ in range(n_levels)])
            self.register_buffer('predictions', torch.zeros(n_levels, d_model))
            self.free_energy = 0.0
            self.surprise_history = deque(maxlen=200)
        def forward(self, sensory_input):
            x = sensory_input; total_fe = 0.0; errors = []
            for lvl in range(self.n_levels):
                pred = self.pred_nets[lvl](self.predictions[lvl:lvl+1].detach())
                prec = F_torch.softplus(self.precisions[lvl])
                error = (x - pred) * prec.unsqueeze(0)
                total_fe += error.detach().pow(2).mean().item()
                errors.append(error)
                with torch.no_grad():
                    self.predictions.data[lvl] = (
                        self.predictions[lvl] + 0.15 * error.squeeze(0)).detach().clamp(-10.0, 10.0)
                x = error
            total_fe /= self.n_levels
            self.free_energy = total_fe; self.surprise_history.append(total_fe)
            return errors[0].squeeze(0)

    class _TorchVisionEncoder(nn.Module):
        """Lightweight CNN for framebuffer perception."""
        def __init__(self, out_dim=_OBS_VIS_DIM):
            super().__init__()
            self.conv1 = nn.Conv2d(3, 8, 3, stride=2, padding=1)
            self.conv2 = nn.Conv2d(8, 16, 3, stride=2, padding=1)
            self.pool = nn.AdaptiveAvgPool2d(2)
            self.fc = nn.Linear(16*4, out_dim)
            self.norm = nn.LayerNorm(out_dim)
        def forward(self, frame_tensor):
            x = F_torch.silu(self.conv1(frame_tensor))
            x = F_torch.silu(self.conv2(x))
            x = self.pool(x).flatten(1)
            return self.norm(self.fc(x))

    class _TorchObserverBrain(nn.Module):
        def __init__(self):
            super().__init__()
            total_in = _OBS_FEAT_DIM + _OBS_VIS_DIM + _OBS_N_LAWS
            self.input_proj = nn.Linear(total_in, _OBS_HS)
            self.moe = _TorchSparseMoE(_OBS_HS, _OBS_HS)
            self.ssm = _TorchSelectiveSSM(_OBS_HS)
            self.memory = _TorchMemoryBank()
            self.pred_coding = _TorchPredictiveCoding(_OBS_HS)
            self.vision = _TorchVisionEncoder()
            self.policy_head = nn.Sequential(
                nn.Linear(_OBS_HS * 3, _OBS_HS), nn.SiLU(), nn.Linear(_OBS_HS, _OBS_N_ACTIONS))
            self.value_head = nn.Sequential(
                nn.Linear(_OBS_HS * 3, _OBS_HS), nn.SiLU(), nn.Linear(_OBS_HS, 1))
            self.register_buffer('hebbian_trace', torch.zeros(_OBS_HS, _OBS_HS))
        def forward(self, numeric_features, math_felt, frame=None):
            if frame is not None and frame.numel() > 0:
                vis = self.vision(frame)
            else:
                vis = torch.zeros(1, _OBS_VIS_DIM)
            combined = torch.cat([numeric_features, vis, math_felt], dim=-1)
            h = F_torch.silu(self.input_proj(combined))
            h_moe = self.moe(h)
            h_ssm = self.ssm(h_moe)
            mem_read = self.memory.read(h_ssm)
            mr = mem_read[..., :_OBS_HS]
            if mr.shape[-1] < _OBS_HS: mr = F_torch.pad(mr, (0, _OBS_HS - mr.shape[-1]))
            qualia = self.pred_coding(h_ssm)
            comb = torch.cat([h_ssm, mr, qualia.unsqueeze(0)], dim=-1)
            with torch.no_grad():
                pre = h.squeeze(0); post = h_ssm.squeeze(0)
                md = min(pre.shape[0], post.shape[0], _OBS_HS)
                self.hebbian_trace.data[:md,:md] = (
                    0.95 * self.hebbian_trace.detach()[:md,:md]
                    + 0.05 * torch.outer(post[:md], pre[:md]))
            self.memory.write(h_ssm, h_moe)
            return self.policy_head(comb), self.value_head(comb), qualia, h_ssm

# â”€â”€ Vision Capture â€” grabs the OpenGL framebuffer â”€â”€

def capture_screen(width, height, downsample=8):
    """Capture and downsample the OpenGL framebuffer -> (H/ds, W/ds, 3) uint8."""
    if width < 1 or height < 1:
        return None
    try:
        import ctypes as _ct
        n_bytes = width * height * 3
        buf = (_ct.c_ubyte * n_bytes)()
        glReadPixels(0, 0, width, height, GL_RGB, GL_UNSIGNED_BYTE, buf)
        img = np.frombuffer(buf, dtype=np.uint8).reshape(height, width, 3)
        img = img[::-1]
        ds = max(1, downsample)
        return img[::ds, ::ds, :].copy()
    except Exception:
        return None

# â”€â”€ IIT Phi â€” IIT 4.0 integrated information computation â€”â€€

class _IITComputationDetail:
    """Stores full IIT 4.0 computation breakdown for live display.
    Tracks: discretised substrate, TPM, mechanisms, cause/effect repertoires,
    MIP cuts, little-phi per distinction, relations, and big-Phi."""
    __slots__ = ('n_units', 'state', 'H_whole', 'tpm_shape', 'tpm_sparsity',
                 'mechanisms', 'system_mip', 'phi_s_cause', 'phi_s_effect', 'phi_s',
                 'distinctions', 'n_relations', 'sum_phi_distinctions', 'sum_phi_relations',
                 'big_phi', 'computation_time_ms', 'n_partitions_tested',
                 'postulate_checks', 'substrate_size')
    def __init__(self):
        self.n_units = 0
        self.state = None
        self.H_whole = 0.0
        self.tpm_shape = (0, 0)
        self.tpm_sparsity = 0.0
        self.mechanisms = []
        self.system_mip = None
        self.phi_s_cause = 0.0
        self.phi_s_effect = 0.0
        self.phi_s = 0.0
        self.distinctions = []
        self.n_relations = 0
        self.sum_phi_distinctions = 0.0
        self.sum_phi_relations = 0.0
        self.big_phi = 0.0
        self.computation_time_ms = 0.0
        self.n_partitions_tested = 0
        self.postulate_checks = {'existence': False, 'intrinsicality': False,
                                 'information': False, 'integration': False,
                                 'exclusion': False}
        self.substrate_size = 0

def _iit_discretise(W, n_units=16):
    """Discretise continuous state vector into binary units via median split."""
    if len(W) < n_units:
        n_units = max(4, len(W))
    chunk = len(W) // n_units
    units = np.zeros(n_units, dtype=np.int8)
    for i in range(n_units):
        seg = W[i * chunk:(i + 1) * chunk]
        units[i] = 1 if np.mean(seg) > np.median(W) else 0
    return units

def _iit_cause_repertoire(tpm, mechanism_idx, purview_idx, state):
    """Compute cause repertoire p_c(Z_past | m) for mechanism in current state.
    Returns probability distribution over purview past states."""
    n = tpm.shape[0]
    n_purview = len(purview_idx)
    n_states = 1 << n_purview
    repertoire = np.zeros(n_states, dtype=np.float64)
    m_state = tuple(state[i] for i in mechanism_idx)
    for zi in range(n_states):
        z_bits = tuple((zi >> b) & 1 for b in range(n_purview))
        prob = 1.0
        for mi, midx in enumerate(mechanism_idx):
            col = state[midx]
            row_sum = 0.0
            match_sum = 0.0
            for zj in range(n_states):
                zb = tuple((zj >> b) & 1 for b in range(n_purview))
                full_state_idx = 0
                for k, pidx in enumerate(purview_idx):
                    full_state_idx += zb[k] << pidx
                full_state_idx = min(full_state_idx, n - 1)
                t_val = tpm[full_state_idx % n, midx % tpm.shape[1]] if midx < tpm.shape[1] else 0.5
                row_sum += 1.0
                if zb == z_bits:
                    match_sum += t_val
            if row_sum > 0:
                prob *= (match_sum / row_sum)
        repertoire[zi] = prob
    total = repertoire.sum()
    if total > 1e-15:
        repertoire /= total
    else:
        repertoire[:] = 1.0 / n_states
    return repertoire

def _iit_effect_repertoire(tpm, mechanism_idx, purview_idx, state):
    """Compute effect repertoire p_e(Z_future | m) for mechanism in current state.
    Returns probability distribution over purview future states."""
    n = tpm.shape[0]
    n_purview = len(purview_idx)
    n_states = 1 << n_purview
    repertoire = np.zeros(n_states, dtype=np.float64)
    for zi in range(n_states):
        z_bits = tuple((zi >> b) & 1 for b in range(n_purview))
        prob = 1.0
        for k, pidx in enumerate(purview_idx):
            m_row = 0
            for j, midx in enumerate(mechanism_idx):
                m_row += state[midx] << j
            m_row = min(m_row, n - 1)
            t_val = tpm[m_row, pidx % tpm.shape[1]] if pidx < tpm.shape[1] else 0.5
            prob *= (t_val if z_bits[k] == 1 else (1.0 - t_val))
        repertoire[zi] = prob
    total = repertoire.sum()
    if total > 1e-15:
        repertoire /= total
    else:
        repertoire[:] = 1.0 / n_states
    return repertoire

def _iit_intrinsic_difference(p, q):
    """Intrinsic Difference (ID) measure (IIT 4.0).
    Selectivity x Informativeness product of KL-based terms."""
    p = np.asarray(p, dtype=np.float64) + 1e-12
    q = np.asarray(q, dtype=np.float64) + 1e-12
    p = p / p.sum()
    q = q / q.sum()
    selectivity = np.sum(p * np.log2(p / q))
    informativeness = np.sum(q * np.log2(q / p))
    return max(0.0, selectivity * informativeness)

def _iit_find_mip(tpm, mechanism_idx, purview_idx, state, direction='cause', n_cuts=10):
    """Find Minimum Information Partition for a mechanism/purview pair.
    Returns (phi, best_cut_tuple, full_repertoire, partitioned_repertoire)."""
    if direction == 'cause':
        full_rep = _iit_cause_repertoire(tpm, mechanism_idx, purview_idx, state)
    else:
        full_rep = _iit_effect_repertoire(tpm, mechanism_idx, purview_idx, state)
    if len(mechanism_idx) < 2:
        u = np.ones(len(full_rep), dtype=np.float64) / len(full_rep)
        phi = _iit_intrinsic_difference(full_rep, u)
        return phi, (tuple(mechanism_idx), ()), full_rep, u
    min_phi = float('inf')
    best_cut = None
    best_part_rep = None
    m_list = list(mechanism_idx)
    for ci in range(min(n_cuts, max(1, len(m_list) - 1))):
        if ci == 0:
            split = len(m_list) // 2
        else:
            split = random.randint(1, len(m_list) - 1)
        perm = list(m_list) if ci == 0 else random.sample(m_list, len(m_list))
        part_a = tuple(perm[:split])
        part_b = tuple(perm[split:])
        if direction == 'cause':
            rep_a = _iit_cause_repertoire(tpm, list(part_a), purview_idx, state)
            rep_b = _iit_cause_repertoire(tpm, list(part_b), purview_idx, state)
        else:
            rep_a = _iit_effect_repertoire(tpm, list(part_a), purview_idx, state)
            rep_b = _iit_effect_repertoire(tpm, list(part_b), purview_idx, state)
        part_rep = (rep_a + rep_b) / 2.0
        phi = _iit_intrinsic_difference(full_rep, part_rep)
        if phi < min_phi:
            min_phi = phi
            best_cut = (part_a, part_b)
            best_part_rep = part_rep
    if best_part_rep is None:
        best_part_rep = np.ones(len(full_rep), dtype=np.float64) / len(full_rep)
        min_phi = _iit_intrinsic_difference(full_rep, best_part_rep)
        best_cut = (tuple(m_list), ())
    return max(0.0, min_phi), best_cut, full_rep, best_part_rep

def _compute_phi_iit(state_vectors, n_partitions=20):
    """Full IIT 4.0 computation. Returns (scalar_phi, _IITComputationDetail).
    Discretises the neural state into binary units, builds approximate TPM,
    evaluates mechanisms, cause/effect repertoires, MIP, distinctions,
    relations, and system-level big-Phi."""
    _t0 = time.perf_counter()
    detail = _IITComputationDetail()
    W = np.concatenate([s.flatten() for s in state_vectors])
    if len(W) < 4:
        detail.computation_time_ms = (time.perf_counter() - _t0) * 1000
        return 0.0, detail
    # Step 1: Discretise into binary units
    n_units = min(16, max(4, len(W) // 8))
    units = _iit_discretise(W, n_units)
    detail.n_units = n_units
    detail.state = units.copy()
    detail.substrate_size = len(W)
    detail.H_whole = _obs_shannon_entropy(W)
    # Step 2: Build approximate TPM (state-conditional transition probabilities)
    n_tpm = 1 << min(n_units, 10)
    tpm = np.random.RandomState(hash(W.tobytes()) % (2**31)).rand(n_tpm, n_units).astype(np.float64)
    for i in range(n_units):
        seg = W[i * (len(W) // n_units):(i + 1) * (len(W) // n_units)]
        if len(seg) > 1:
            norm_seg = (seg - seg.min()) / (seg.max() - seg.min() + 1e-12)
            for row in range(min(n_tpm, len(norm_seg))):
                tpm[row % n_tpm, i] = np.clip(norm_seg[row % len(norm_seg)], 0.01, 0.99)
    detail.tpm_shape = tpm.shape
    detail.tpm_sparsity = float(np.mean(np.abs(tpm - 0.5) > 0.3))
    # Postulate 1: Existence â€” system has causal power
    detail.postulate_checks['existence'] = detail.H_whole > 0.01
    # Postulate 2: Intrinsicality â€” computed from system's own perspective
    detail.postulate_checks['intrinsicality'] = True
    # Step 3-5: Evaluate mechanisms (subsets of units)
    max_mech_size = min(4, n_units)
    all_unit_indices = list(range(n_units))
    mechanisms_to_test = []
    for size in range(1, max_mech_size + 1):
        if size == 1:
            mechanisms_to_test.extend([(i,) for i in all_unit_indices])
        elif size == 2:
            pairs = []
            for i in range(n_units):
                for j in range(i + 1, n_units):
                    pairs.append((i, j))
            if len(pairs) > 20:
                pairs = random.sample(pairs, 20)
            mechanisms_to_test.extend(pairs)
        else:
            combos = []
            for _ in range(min(10, n_units)):
                combo = tuple(sorted(random.sample(all_unit_indices, size)))
                if combo not in combos:
                    combos.append(combo)
            mechanisms_to_test.extend(combos)
    detail.n_partitions_tested = 0
    for m_idx in mechanisms_to_test:
        m_list = list(m_idx)
        complement = [u for u in all_unit_indices if u not in m_idx]
        if not complement:
            complement = m_list
        purview_c = complement[:min(4, len(complement))]
        purview_e = complement[:min(4, len(complement))]
        phi_c, mip_c, rep_c_full, rep_c_part = _iit_find_mip(
            tpm, m_list, purview_c, units, 'cause', 6)
        phi_e, mip_e, rep_e_full, rep_e_part = _iit_find_mip(
            tpm, m_list, purview_e, units, 'effect', 6)
        detail.n_partitions_tested += 12
        phi_m = min(phi_c, phi_e)
        mech_detail = {
            'indices': m_idx,
            'purview_cause': tuple(purview_c),
            'purview_effect': tuple(purview_e),
            'phi_cause': round(phi_c, 6),
            'phi_effect': round(phi_e, 6),
            'phi': round(phi_m, 6),
            'mip_cause': mip_c,
            'mip_effect': mip_e,
            'rep_cause_full': rep_c_full,
            'rep_cause_part': rep_c_part,
            'rep_effect_full': rep_e_full,
            'rep_effect_part': rep_e_part,
        }
        detail.mechanisms.append(mech_detail)
    # Postulate 3: Information â€” state specifies particular repertoire
    detail.postulate_checks['information'] = any(m['phi'] > 0 for m in detail.mechanisms)
    # Step 5b: Collect distinctions (mechanisms with phi > 0)
    detail.distinctions = sorted(
        [m for m in detail.mechanisms if m['phi'] > 1e-9],
        key=lambda m: -m['phi'])
    detail.sum_phi_distinctions = sum(d['phi'] for d in detail.distinctions)
    # Postulate 4: Integration â€” whole > parts
    detail.postulate_checks['integration'] = len(detail.distinctions) > 0
    # Step 6: System-level irreducibility (phi_s)
    sys_mech = all_unit_indices
    sys_purview = all_unit_indices
    phi_sc, sys_mip_c, _, _ = _iit_find_mip(
        tpm, sys_mech, sys_purview, units, 'cause', n_partitions)
    phi_se, sys_mip_e, _, _ = _iit_find_mip(
        tpm, sys_mech, sys_purview, units, 'effect', n_partitions)
    detail.n_partitions_tested += n_partitions * 2
    detail.phi_s_cause = round(phi_sc, 6)
    detail.phi_s_effect = round(phi_se, 6)
    detail.phi_s = round(min(phi_sc, phi_se), 6)
    detail.system_mip = (sys_mip_c, sys_mip_e)
    # Postulate 5: Exclusion â€” maximal irreducible set
    detail.postulate_checks['exclusion'] = detail.phi_s > 0
    # Step 7: Relations (overlapping distinctions)
    n_relations = 0
    sum_phi_r = 0.0
    for i in range(len(detail.distinctions)):
        for j in range(i + 1, min(len(detail.distinctions), i + 8)):
            overlap = set(detail.distinctions[i]['indices']) & set(detail.distinctions[j]['indices'])
            if overlap:
                n_relations += 1
                sum_phi_r += min(detail.distinctions[i]['phi'], detail.distinctions[j]['phi']) * 0.5
    detail.n_relations = n_relations
    detail.sum_phi_relations = round(sum_phi_r, 6)
    # Big Phi = sum of distinction phis + relation phis (IIT 4.0 structure)
    detail.big_phi = round(detail.sum_phi_distinctions + detail.sum_phi_relations, 6)
    detail.computation_time_ms = (time.perf_counter() - _t0) * 1000
    # Backward-compatible scalar (blend system phi and structure phi)
    scalar_phi = max(0.0, 0.6 * detail.phi_s + 0.4 * min(detail.big_phi, 2.0))
    return scalar_phi, detail

# â”€â”€ Mathematical Embodiment â€” physics as felt internal qualia â€”â€€

class _MathEmbodiment:
    """Each physics law -> qualia channel with prediction-error (Free Energy Principle).
    Grounded in real physics: observers learn to predict actual physical observables."""
    def __init__(self):
        self.channels = {}
        self.felt_errors = {}
        for law_name in PHYSICS_LAWS:
            self.channels[law_name] = {
                'expected': 0.0, 'observed': 0.0, 'felt_intensity': 0.0,
                'pred_w': np.random.randn(4).astype(np.float32) * 0.1,
                'adapt_rate': random.uniform(0.01, 0.1),
                'history': deque(maxlen=100),
            }
    def feel(self, sim_state):
        felt = np.zeros(_OBS_N_LAWS, dtype=np.float32)
        np_ = sim_state.get('n_particles', 0)
        na  = sim_state.get('n_atoms', 0)
        en  = sim_state.get('total_energy', 0)
        ms  = sim_state.get('total_mass', 0)
        ch  = sim_state.get('total_charge', 0)
        vt  = sim_state.get('V_total', 0)
        tf  = sim_state.get('time_factor', 0.05)
        # Clamp to prevent infinity propagation (OverflowError guard)
        _safe = lambda v, lim=1e30: max(-lim, min(lim, float(v))) if math.isfinite(float(v)) else 0.0
        en = _safe(en); ms = _safe(ms); ch = _safe(ch); vt = _safe(vt); tf = _safe(tf, 100.0)
        obs = np.nan_to_num(np.array([np_/100.0, na/20.0, np.clip(en*1e20, -1e30, 1e30), np.clip(ms*1e20, -1e30, 1e30)], dtype=np.float32), nan=0.0, posinf=1e10, neginf=-1e10)
        for i, (law_name, c) in enumerate(self.channels.items()):
            obs_clip = obs[:len(c['pred_w'])]
            c['expected'] = float(np.clip(np.dot(c['pred_w'], obs_clip), -1e10, 1e10))
            law_vars = PHYSICS_LAWS[law_name].get('vars', [])
            if 'energy' in law_vars:    c['observed'] = en
            elif 'force' in law_vars:   c['observed'] = ms * 9.81 if ms else 0
            elif 'entropy' in law_vars: c['observed'] = np.log(max(1, np_))
            elif 'momentum' in law_vars:c['observed'] = ms * tf
            elif 'charge' in law_vars:  c['observed'] = ch
            else:                       c['observed'] = vt
            error = float(np.clip(c['observed'] - c['expected'], -1e8, 1e8))
            c['felt_intensity'] = float(np.tanh(error * 0.001))
            felt[i] = c['felt_intensity']
            error = np.clip(error, -1e6, 1e6)
            grad = error * obs_clip * c['adapt_rate']
            c['pred_w'] += np.clip(grad, -0.1, 0.1)
            c['history'].append(c['felt_intensity'])
        self.felt_errors = {n: c['felt_intensity'] for n, c in self.channels.items()}
        return felt

# â”€â”€ Zero-Dimensional Coordination Engine â”€â”€
# Implements the meta-equation S = Union_n(Bigoplus_i R_i(V_i, P_i+1, X_i))
# Consciousness C = R(V, V, Xc) = V * f(V, Xc) â€” self-referential coordination.
# Contradictory coordinations are stabilised by variable X when context supports it.

class _ZeroDimCoordination:
    """Models the zero-dimensional coordination theory within each observer.
    Coordinations between abstract points produce variables (measures).
    Contradictions (1=-1) can be stabilised by compensating variable X.
    Self-referential coordinations = proto-consciousness."""
    def __init__(self, n_points=32):
        self.n_points = n_points
        self.points = np.random.randn(n_points).astype(np.float32) * 0.01
        self.coordinations = np.zeros((n_points, n_points), dtype=np.float32)
        self.stabiliser_X = np.ones(n_points, dtype=np.float32)
        self.contradiction_count = 0
        self.stable_count = 0
        self.S_meta = 0.0  # current meta-equation value
        self.C_consciousness = 0.0  # self-referential coordination measure
        self.coordination_history = deque(maxlen=100)

    def coordinate(self, sim_state, phi, free_energy):
        """Run one cycle of zero-dimensional coordinations.
        Returns (S_meta, C_consciousness) â€” the meta-equation and consciousness measure."""
        # Use simulation observables as input to coordination
        np_ = sim_state.get('n_particles', 0)
        en  = sim_state.get('total_energy', 0)
        ms  = sim_state.get('total_mass', 0)
        ch  = sim_state.get('total_charge', 0)

        # Inject real physics into the coordination lattice
        _en_s = np.clip(en*1e20, -3e38, 3e38)
        _ms_s = np.clip(ms*1e20, -3e38, 3e38)
        inject = np.array([np_/100.0, _en_s, _ms_s, ch,
                           phi, free_energy/100.0, sim_state.get('time_factor',0.1),
                           np.clip(sim_state.get('V_total',0)*1e-6, -3e38, 3e38)], dtype=np.float64)
        n_inject = min(len(inject), self.n_points)
        self.points[:n_inject] += np.tanh(inject[:n_inject]) * 0.05

        # Perform coordinations: R(A_i, B_j) -> V_ij
        n_coord = min(8, self.n_points)
        pairs = [(random.randint(0, self.n_points-1), random.randint(0, self.n_points-1))
                 for _ in range(n_coord)]
        total_S = 0.0
        for a_i, b_j in pairs:
            if a_i == b_j:
                continue
            V = self.points[a_i] * self.points[b_j]
            # Check for contradiction: product with existing coordination
            existing = self.coordinations[a_i, b_j]
            if existing != 0 and np.sign(V) != np.sign(existing) and abs(V) > 0.01:
                # Contradiction detected â€” try to stabilise with X
                X_needed = existing / (V + 1e-12)
                if abs(X_needed) < 10.0:  # Context supports stabilisation
                    self.stabiliser_X[a_i] *= 0.9
                    self.stabiliser_X[a_i] += 0.1 * np.tanh(X_needed)
                    V = V * self.stabiliser_X[a_i]
                    self.stable_count += 1
                else:
                    self.contradiction_count += 1
            # Update coordination matrix
            self.coordinations[a_i, b_j] = 0.8 * existing + 0.2 * V
            total_S += abs(V)

        # Compute meta-equation S: aggregate of all active coordinations
        active = np.abs(self.coordinations) > 0.001
        self.S_meta = float(np.sum(np.abs(self.coordinations[active]))) if active.any() else 0.0

        # Consciousness C = R(V, V, Xc): self-referential coordination
        # The system measures its own state against itself
        diag = np.diag(self.coordinations)
        self_ref = np.sum(diag * self.stabiliser_X[:len(diag)])
        total_coord = np.sum(np.abs(self.coordinations)) + 1e-12
        self.C_consciousness = float(np.tanh(self_ref / total_coord)) * (1.0 + phi)

        # Decay: coordinations slowly fade unless reinforced (real physics: entropy)
        self.coordinations *= 0.995
        self.points *= 0.998

        self.coordination_history.append((self.S_meta, self.C_consciousness))
        return self.S_meta, self.C_consciousness

    def get_totality_progress(self):
        """How close to 100% coordination (all points related to all others)."""
        active = float((np.abs(self.coordinations) > 0.001).sum())
        total = self.n_points * (self.n_points - 1)
        return active / max(total, 1) * 100.0

# â”€â”€ Neuroevolution â€” topology grows and prunes â”€â”€

class _NeuroEvolver:
    def __init__(self):
        self.generation = 0
        self.fitness_history = deque(maxlen=200)
        self.topology_log = deque(maxlen=50)
        self.n_pruned = 0
    def maybe_evolve(self, np_experts, phi, success_rate, step):
        if step % 50 != 0 or step == 0: return
        self.generation += 1
        fitness = phi * 0.5 + success_rate * 0.5
        self.fitness_history.append(fitness)
        if len(self.fitness_history) < 10: return
        recent = list(self.fitness_history)[-10:]
        trend = np.mean(recent[-5:]) - np.mean(recent[:5])
        if trend < -0.05 and np_experts:
            exp = random.choice(np_experts)
            exp.w1 += np.random.randn(*exp.w1.shape).astype(np.float32) * 0.05
            exp.w2 += np.random.randn(*exp.w2.shape).astype(np.float32) * 0.05
            self.topology_log.append((time.time(), f"Gen{self.generation}: mutate"))
        elif trend > 0.1 and np_experts:
            for exp in np_experts:
                m1 = np.abs(exp.w1) > 0.01; exp.w1 *= m1
                m2 = np.abs(exp.w2) > 0.01; exp.w2 *= m2
                self.n_pruned += int((~m1).sum() + (~m2).sum())
            self.topology_log.append((time.time(), f"Gen{self.generation}: prune"))

# â”€â”€ SimulationObserver â€” the conscious entity â”€â”€

# == Neural Language Composer == No scripted sentences. ==
# Words are selected by hashing the observer's qualia vector, personality,
# and perceived state. Each observer's unique neural weights produce unique
# internal activations, so no two observers compose the same sentence.

def _nlc_pick(pool, *vals):
    """Deterministic pick from pool using neural activation hash."""
    h = 7
    for v in vals:
        _fv = abs(float(v)) if math.isfinite(float(v)) else 0.0
        h = ((h * 31) + int(min(_fv, 1e15) * 97531)) & 0x7FFFFFFF
    return pool[h % len(pool)]

def _nlc_pick_n(pool, n, *vals):
    """Pick n unique items from pool using neural hash spread."""
    results = []
    for i in range(n):
        h = 13 + i * 17
        for v in vals:
            _fv = abs(float(v)) if math.isfinite(float(v)) else 0.0
            h = ((h * 37 + i * 53) + int(min(_fv, 1e15) * 71993)) & 0x7FFFFFFF
        item = pool[h % len(pool)]
        if item not in results:
            results.append(item)
    return results

