def _rot2d(x, y, angle):
    c, s = math.cos(angle), math.sin(angle)
    return x * c - y * s, x * s + y * c


def _lerp_pose(pose_a, pose_b, t):
    result = {}
    all_keys = set(pose_a.keys()) | set(pose_b.keys())
    for k in all_keys:
        va = pose_a.get(k, (0.0, 0.0))
        vb = pose_b.get(k, (0.0, 0.0))
        result[k] = (va[0] + (vb[0] - va[0]) * t, va[1] + (vb[1] - va[1]) * t)
    return result


class HumanoidSkeleton:
    """Research-grade articulated humanoid skeleton.
    H-Anim ISO/IEC 19774 joint hierarchy.
    Proportions from Winter (2009) Biomechanics and Motor Control."""

