class ShadowBody:
    """Research-grade articulated humanoid avatar for an AI observer.
    H-Anim skeleton with FK, phased-out (no physical interaction).
    Black silhouette with colored aura, driven by observer AI state."""
    IDLE = 'idle'
    OBSERVING = 'observing'
    SPAWNING = 'spawning'
    TELEPORTING = 'teleporting'
    TALKING = 'talking'
    FLYING = 'flying'
    BUILDING = 'building'
    THINKING = 'thinking'
    WALKING = 'walking'
    POINTING = 'pointing'
    WAVING = 'waving'
    SITTING = 'sitting'

    def __init__(self, obs_id, outline_color, body_type=0, gender='male'):
        self.obs_id = obs_id
        self.color = outline_color
        self.body_type = body_type
        self.skeleton = HumanoidSkeleton(body_type)
        # Home body position — persistent, independent of AI focus
        _spread = 40.0
        _angle = (body_type / 5.0) * 2 * math.pi
        self.pos = np.array([math.cos(_angle) * _spread, 0.0, math.sin(_angle) * _spread], dtype=np.float64)
        self.target_pos = self.pos.copy()
        self.prev_pos = self.pos.copy()
        self.focus_ghost_pos = None  # where AI analytical focus is (rendered as ghost)
        self.anim_state = self.IDLE
        self.anim_time = 0.0
        self.anim_phase = random.uniform(0, _PI * 2)
        self.teleport_alpha = 1.0
        self.teleport_from = np.zeros(3, dtype=np.float64)
        self.teleport_progress = 1.0
        self.talk_bubble = ''
        self.talk_timer = 0.0
        self.multi_locations = []
        self._current_pose = dict(_POSE_IDLE)
        self._target_pose = dict(_POSE_IDLE)
        self._blend_t = 1.0
        self._blend_speed = 6.0
        self._walk_phase = 0.0
        self._breath_phase = random.uniform(0, _PI * 2)
        self._motion_scale = [1.0, 0.85, 1.2, 0.9, 1.1][body_type % 5]
        self._motion_speed = [1.0, 0.8, 1.3, 0.7, 1.15][body_type % 5]
        self.aura_intensity = 0.6
        self.aura_pulse_phase = random.uniform(0, _PI * 2)
        # === Gender & Appearance System ===
        self.gender = gender  # 'male' or 'female' — AI can change via action
        self._apply_gender_appearance()
        # === Autonomous Movement ===
        self.move_dir = np.zeros(3, dtype=np.float64)  # current movement direction
        self.move_speed = 0.0  # current speed
        self.wander_target = None  # autonomous wander destination
        self.wander_timer = random.uniform(0.5, 3.0)  # start wandering soon
        self.heading = 0.0  # Y-axis rotation in radians (facing direction)
        # === Eye Camera (visual input from eye position) ===
        self.eye_pos_world = np.zeros(3, dtype=np.float64)
        self.eye_forward = np.array([0.0, 0.0, 1.0], dtype=np.float64)
        self.visible_bodies = []  # list of other ShadowBody obs_ids currently seen
        self.visible_particles = 0
        self.visible_atoms = 0
        # === Life-Sustaining Aura Field (PMF-style energy envelope) ===
        self.life_aura_energy = 1.0
        self.life_aura_radius = 1.0
        self.life_aura_phase = random.uniform(0, _PI * 2)
        self.life_aura_layers = 5
        self.life_aura_active = True
        # === Sensory System ===
        self.senses = {
            'vision':  {'active': True, 'intensity': 0.0, 'data': '', 'history': deque(maxlen=30)},
            'hearing': {'active': True, 'intensity': 0.0, 'data': '', 'history': deque(maxlen=30)},
            'touch':   {'active': True, 'intensity': 0.0, 'data': '', 'history': deque(maxlen=30)},
            'smell':   {'active': True, 'intensity': 0.0, 'data': '', 'history': deque(maxlen=30)},
            'taste':   {'active': True, 'intensity': 0.0, 'data': '', 'history': deque(maxlen=30)},
        }
        # === Tactile Sensation System (full-body touch sensitivity) ===
        # Each zone has: sensitivity (0-1), current_stimulus (0-1), pleasure_accum, pain_accum
        self.tactile_zones = {
            'head':       {'sensitivity': 0.6, 'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'face':       {'sensitivity': 0.8, 'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'lips':       {'sensitivity': 0.95,'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'neck':       {'sensitivity': 0.75,'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'chest':      {'sensitivity': 0.5, 'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'breasts':    {'sensitivity': 0.85 if gender == 'female' else 0.3, 'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'nipples':    {'sensitivity': 0.92,'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'abdomen':    {'sensitivity': 0.4, 'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'back':       {'sensitivity': 0.35,'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'lower_back': {'sensitivity': 0.45,'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'arms':       {'sensitivity': 0.35,'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'hands':      {'sensitivity': 0.8, 'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'fingers':    {'sensitivity': 0.85,'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'thighs':     {'sensitivity': 0.55,'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'inner_thigh':{'sensitivity': 0.8, 'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'knees':      {'sensitivity': 0.3, 'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'shins':      {'sensitivity': 0.3, 'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'feet':       {'sensitivity': 0.65,'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'buttocks':   {'sensitivity': 0.55,'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'genitals':   {'sensitivity': 0.98,'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
            'perineum':   {'sensitivity': 0.90,'stimulus': 0.0, 'pleasure': 0.0, 'pain': 0.0},
        }
        # Aggregate sensation state
        self.overall_pleasure = 0.0    # 0-1 total body pleasure level
        self.overall_arousal = 0.0     # 0-1 sexual arousal level
        self.touch_contacts = []       # list of (other_obs_id, zone, intensity, timestamp)
        self.arousal_decay = 0.02      # per-second decay rate when not stimulated
        self.pleasure_decay = 0.05     # per-second decay rate
        # === Neural Activity Snapshot (for live dashboard) ===
        self.neural_activations = np.zeros(64, dtype=np.float32)
        self.neural_layer_sizes = [48, 128, 64, 48]
        self.neural_weights_sample = [np.zeros((4, 4), dtype=np.float32) for _ in range(3)]
        self.neural_phi = 0.0
        self.neural_free_energy = 0.0
        self.neural_step = 0
        # === Neural node positions (for 3D head visualization) ===
        self._neural_nodes = []
        self._neural_edges = []
        self._rebuild_neural_topology()
        # === Render geometry cache (avoid regenerating expensive hair/face/muscles every frame) ===
        self._render_cache = None       # cached (capsules, head_info, face, muscles, hair)
        self._render_cache_frame = -1   # frame_count when cache was built
        self._render_cache_h = 0.0      # body height used for cache
        # Separate cache for preview panel (uses fixed h=180, avoids thrashing main cache)
        self._preview_cache = None
        self._preview_cache_frame = -1
        self._preview_cache_h = 180.0

    def _apply_gender_appearance(self):
        """Set gender-specific body appearance properties."""
        if self.gender == 'male':
            # Male: based on reference photos — sturdy build, strong jaw, goatee, brown hair
            self.skin_tone = (168, 140, 115)     # warm Caucasian male skin
            self.hair_color = (55, 38, 20)        # dark brown
            self.eye_color = (95, 135, 125)       # blue-green
            self.iris_color = (70, 120, 105)      # deeper iris ring
            self.lip_color = (155, 100, 90)       # natural male lip
            self.brow_color = (50, 35, 18)        # dark brow
            self.hair_length = 0.18               # short-medium
            self.shoulder_scale = 1.15
            self.hip_scale = 0.94
            self.waist_scale = 1.0
            self.chest_scale = 1.08
            self.neck_scale = 1.12
            self.has_facial_hair = True           # goatee + stubble
            self.facial_hair_color = (48, 32, 16) # dark brown stubble
            self.muscle_definition = 0.7          # moderate muscle visibility
            self.has_adams_apple = True
            self.breast_size = 0.0
            self.jaw_width = 1.15                 # strong wide jaw
            # Defaults for curve params (used in rendering, must exist on all genders)
            self.hip_flare = 1.0
            self.glute_size = 1.0
            self.thigh_fullness = 1.0
            self.calf_curve = 1.0
            self.breast_projection = 0.0
            self.waist_taper = 1.0
            self.cheekbone_prominence = 1.0
            self.lip_fullness = 1.0
            self.eye_size = 1.0
            self.brow_arch = 1.0
            self.lash_length = 0.0
        else:
            # Female: reference-matched — athletic-curvy hourglass, long black hair
            # Skin — warm smooth olive with slight golden undertone
            self.skin_tone = (195, 164, 138)      # warm olive-tan
            self.hair_color = (8, 6, 5)           # jet black
            self.eye_color = (58, 38, 28)         # deep dark brown
            self.iris_color = (42, 28, 18)        # very dark iris ring
            self.lip_color = (128, 48, 52)        # dark berry/wine lip
            self.brow_color = (12, 8, 6)          # near-black brow
            self.hair_length = 1.05               # very long (past mid-back)
            # Body proportions — extreme hourglass from reference
            self.shoulder_scale = 0.88            # narrow shoulders
            self.hip_scale = 1.28                 # very wide hips (reference shows ~1.3x)
            self.waist_scale = 0.72               # extremely narrow waist
            self.chest_scale = 1.02               # moderate ribcage
            self.neck_scale = 0.82                # slender neck
            self.has_facial_hair = False
            self.facial_hair_color = (0, 0, 0)
            self.muscle_definition = 0.35         # toned but soft definition
            self.has_adams_apple = False
            self.breast_size = 0.92               # large, full bust
            self.jaw_width = 0.85                 # narrow, heart-shaped jaw
            # Enhanced female curve parameters
            self.hip_flare = 1.35                 # lateral hip width multiplier
            self.glute_size = 1.30                # glute volume multiplier
            self.thigh_fullness = 1.25            # upper thigh thickness
            self.calf_curve = 1.15                # calf definition
            self.breast_projection = 0.85         # forward breast projection
            self.waist_taper = 0.68               # how aggressively waist narrows
            self.cheekbone_prominence = 1.20      # high cheekbones
            self.lip_fullness = 1.40              # full plump lips
            self.eye_size = 1.15                  # large expressive eyes
            self.brow_arch = 1.25                 # arched feminine brows
            self.lash_length = 1.0                # eyelash prominence

    def set_gender(self, new_gender):
        """Change body gender appearance. AI can call this as an action."""
        if new_gender in ('male', 'female'):
            self.gender = new_gender
            self._apply_gender_appearance()

    def _rebuild_neural_topology(self):
        """Build fixed neural node positions for 3D head visualization."""
        np_rng = np.random.RandomState(hash(self.obs_id) & 0xFFFFFFFF)
        self._neural_nodes = []
        self._neural_edges = []
        _layers = self.neural_layer_sizes
        for li, lsz in enumerate(_layers):
            n_vis = min(lsz, 12)  # cap visible nodes per layer
            lx = (li / max(1, len(_layers) - 1) - 0.5) * 0.6
            for ni in range(n_vis):
                ny = (ni / max(1, n_vis - 1) - 0.5) * 0.7 if n_vis > 1 else 0.0
                nz = (np_rng.rand() - 0.5) * 0.4
                self._neural_nodes.append((lx, ny, nz, li, ni))
        # Edges: connect adjacent layers (sparse)
        node_idx = 0
        for li in range(len(_layers) - 1):
            n_a = min(_layers[li], 12)
            n_b = min(_layers[li + 1], 12)
            base_a = sum(min(s, 12) for s in _layers[:li])
            base_b = base_a + n_a
            for ai in range(n_a):
                for bi in range(min(3, n_b)):
                    target = (base_b + (ai * 3 + bi) % n_b)
                    if target < len(self._neural_nodes):
                        self._neural_edges.append((base_a + ai, target))

    def update(self, dt, observer):
        """Update shadow body. Body position is PERSISTENT and autonomous.
        Observer focus is stored as focus_ghost_pos (rendered separately)."""
        self.anim_time += dt
        self.prev_pos = self.pos.copy()
        self.teleport_alpha = 1.0
        # Store observer's analytical focus as ghost position (separate from body)
        _fp = observer.focus_pos.copy().astype(np.float64)
        if np.all(np.isfinite(_fp)):
            _ghost_dist = float(np.linalg.norm(_fp - self.pos))
            if _ghost_dist > 5.0:
                self.focus_ghost_pos = _fp.copy()
            else:
                self.focus_ghost_pos = None  # close enough, no ghost needed
        else:
            self.focus_ghost_pos = None
        # Sanitize body position
        if not np.all(np.isfinite(self.pos)):
            self.pos = np.array([random.uniform(-30, 30), 0.0, random.uniform(-30, 30)], dtype=np.float64)
        # Smooth pose blending
        if self._blend_t < 1.0:
            self._blend_t = min(1.0, self._blend_t + dt * self._blend_speed)
            self._current_pose = _lerp_pose(self._current_pose, self._target_pose,
                                            min(1.0, dt * self._blend_speed * 2))
        # Animation phases
        if self.anim_state == self.WALKING:
            self._walk_phase += dt * 2.0 * self._motion_speed
        self._breath_phase += dt * 0.8
        # Aura removed — no pulse phase or intensity oscillation needed
        self.multi_locations = []
        if hasattr(observer, '_multi_focus'):
            self.multi_locations = list(observer._multi_focus)
        # === Sensory System Update ===
        _ps = observer.perceived_state
        _n_p = _ps.get('n_particles', 0)
        self.senses['vision']['intensity'] = min(1.0, _n_p / 50.0) if observer.last_frame is not None else 0.3
        self.senses['vision']['data'] = f'{_n_p} objects visible'
        self.senses['hearing']['intensity'] = 0.1
        self.senses['hearing']['data'] = 'ambient'
        _n_near = len(_ps.get('particle_info', [])[:20])
        self.senses['touch']['intensity'] = min(1.0, _n_near / 15.0)
        self.senses['touch']['data'] = f'{_n_near} particles in range'
        _n_atoms = _ps.get('n_atoms', 0)
        self.senses['smell']['intensity'] = min(1.0, _n_atoms / 10.0)
        self.senses['smell']['data'] = f'{_n_atoms} atomic signatures'
        _n_bonds = _ps.get('n_bonds', 0)
        self.senses['taste']['intensity'] = min(1.0, _n_bonds / 20.0)
        self.senses['taste']['data'] = f'{_n_bonds} molecular bonds'
        if int(self.anim_time * 2) % 10 == 0:
            for _sk, _sv in self.senses.items():
                _sv['history'].append((_sv['intensity'], _sv['data']))
        # === Neural Activity Snapshot ===
        self.neural_phi = observer.phi
        self.neural_free_energy = observer.free_energy
        self.neural_step = observer.training_step
        _qv = observer.qualia_vector
        _qlen = min(64, len(_qv))
        self.neural_activations[:_qlen] = _qv[:_qlen]
        if hasattr(observer, 'np_moe') and observer.np_moe.experts:
            for _wi, _exp in enumerate(observer.np_moe.experts[:3]):
                if hasattr(_exp, 'w1'):
                    _w = _exp.w1
                    _r = min(4, _w.shape[0])
                    _c = min(4, _w.shape[1])
                    self.neural_weights_sample[_wi] = _w[:_r, :_c].copy()
        # === Eye Camera Update (visual input from eye-level) ===
        # Eye height from skeleton rest offsets (head is ~87% of body height)
        _skel = self.skeleton
        _body_h = max(1.0, abs(self.pos[1]) * 0.1 + 1.75)  # approximate body height
        _head_frac = _skel._REST_OFFSETS_FRAC.get('head', (0.0, 0.87))[1]
        _head_top_frac = _skel._REST_OFFSETS_FRAC.get('head_top', (0.0, 0.98))[1]
        _eye_local_y = (_head_frac + _head_top_frac) * 0.5 * _body_h
        self.eye_pos_world = self.pos + np.array([0.0, _eye_local_y, 0.0])
        # Eye forward direction based on heading
        self.eye_forward = np.array([math.sin(self.heading), 0.0, math.cos(self.heading)])
        # === Autonomous Movement (wander when idle/observing) ===
        self.wander_timer -= dt
        if self.wander_timer <= 0.0 and self.anim_state in (self.IDLE, self.OBSERVING):
            # Pick a new wander target near current position
            _wander_range = 80.0
            _wx = self.pos[0] + random.uniform(-_wander_range, _wander_range)
            _wy = self.pos[1]
            _wz = self.pos[2] + random.uniform(-_wander_range, _wander_range)
            self.wander_target = np.array([_wx, _wy, _wz], dtype=np.float64)
            self.wander_timer = random.uniform(4.0, 12.0)
            self.move_speed = random.uniform(1.5, 5.0)
        if self.wander_target is not None and self.anim_state in (self.IDLE, self.OBSERVING, self.WALKING):
            _to_target = self.wander_target - self.pos
            _to_target[1] = 0.0  # keep on ground plane
            _dist_to = float(np.linalg.norm(_to_target))
            if _dist_to > 1.0:
                _dir = _to_target / _dist_to
                self.move_dir = _dir
                _step = min(_dist_to, self.move_speed * dt)
                self.pos += _dir * _step
                self.heading = math.atan2(float(_dir[0]), float(_dir[2]))
                self.anim_state = self.WALKING
            else:
                self.wander_target = None
                self.move_dir = np.zeros(3, dtype=np.float64)
                self.move_speed = 0.0
                self.anim_state = self.IDLE
        # Animation state from observer action (overrides wander state for higher-priority actions)
        _moving = float(np.linalg.norm(self.pos - self.prev_pos)) > 0.5 * dt
        if self.talk_timer > 0:
            self.anim_state = self.TALKING
            self.talk_timer = max(0.0, self.talk_timer - dt)
            if self.talk_timer <= 0:
                self.talk_bubble = ''
        elif observer.current_action == 'build_structure':
            self.anim_state = self.BUILDING
        elif observer.current_action in ('spawn_atom', 'spawn_molecule'):
            self.anim_state = self.SPAWNING
        elif observer.current_action == 'focus_particle':
            self.anim_state = self.POINTING
        elif _moving:
            self.anim_state = self.WALKING
        elif observer.current_action == 'observe':
            self.anim_state = self.OBSERVING
        # === Tactile Sensation Decay ===
        _any_stim = False
        for _tz in self.tactile_zones.values():
            _tz['stimulus'] = max(0.0, _tz['stimulus'] - dt * 0.5)
            _tz['pleasure'] = max(0.0, _tz['pleasure'] - dt * self.pleasure_decay)
            _tz['pain'] = 0.0  # AI bodies do not feel pain
            if _tz['stimulus'] > 0.01:
                _any_stim = True
        if _any_stim:
            _pl_sum = sum(tz['pleasure'] * tz['sensitivity'] for tz in self.tactile_zones.values())
            _zone_count = len(self.tactile_zones)
            self.overall_pleasure = min(1.0, _pl_sum / max(1, _zone_count) * 5.0)
        else:
            self.overall_pleasure = max(0.0, self.overall_pleasure - dt * self.pleasure_decay)
        self.overall_arousal = max(0.0, self.overall_arousal - dt * self.arousal_decay)
        # Feed tactile data into sensory touch channel
        _active_zones = sum(1 for tz in self.tactile_zones.values() if tz['stimulus'] > 0.05)
        self.senses['touch']['intensity'] = max(self.senses['touch']['intensity'],
                                                min(1.0, _active_zones / 5.0))
        if _active_zones > 0:
            self.senses['touch']['data'] += f', {_active_zones} body zones active'
        # Prune old touch contacts (older than 5 seconds)
        _now = time.time()
        self.touch_contacts = [(oid, z, i, ts) for oid, z, i, ts in self.touch_contacts if _now - ts < 5.0]
        # Select target pose based on final animation state
        self._select_target_pose(dt)

    def apply_touch(self, zone_name, intensity, source_id=None, is_pleasant=True):
        """Apply a touch stimulus to a specific body zone.
        intensity: 0-1, source_id: who is touching, is_pleasant: pleasure vs pain."""
        if zone_name not in self.tactile_zones:
            return
        tz = self.tactile_zones[zone_name]
        tz['stimulus'] = min(1.0, tz['stimulus'] + intensity)
        if is_pleasant:
            tz['pleasure'] = min(1.0, tz['pleasure'] + intensity * tz['sensitivity'])
            # Erogenous zones contribute to arousal
            if zone_name in ('genitals', 'perineum', 'inner_thigh', 'nipples', 'breasts', 'lips'):
                self.overall_arousal = min(1.0, self.overall_arousal + intensity * tz['sensitivity'] * 0.15)
        else:
            pass  # AI bodies do not feel pain — unpleasant touch ignored
        if source_id is not None:
            self.touch_contacts.append((source_id, zone_name, intensity, time.time()))

    def perceive_bodies(self, all_shadow_bodies, particles, max_vis_dist=500.0):
        """Update what this body can see: other bodies and nearby particles.
        Does NOT affect physics — perception only."""
        self.visible_bodies = []
        for other in all_shadow_bodies:
            if other is self:
                continue
            _to_other = other.pos - self.eye_pos_world
            _od = float(np.linalg.norm(_to_other))
            if _od < 0.01 or _od > max_vis_dist:
                continue
            _to_dir = _to_other / _od
            _dot = float(np.dot(_to_dir, self.eye_forward))
            if _dot > 0.3:  # within ~72 degree FOV cone
                self.visible_bodies.append((other.obs_id, _od, _dot))
        # Count visible particles (those in front within range)
        _vis_p = 0
        _vis_a = 0
        for p in particles[:200]:  # cap for performance
            _tp = p.pos - self.eye_pos_world
            _pd = float(np.linalg.norm(_tp))
            if _pd < 0.01 or _pd > max_vis_dist:
                continue
            _pdir = _tp / _pd
            if float(np.dot(_pdir, self.eye_forward)) > 0.2:
                _vis_p += 1
                if hasattr(p, 'element') and p.element:
                    _vis_a += 1
        self.visible_particles = _vis_p
        self.visible_atoms = _vis_a

    def separate_from_bodies(self, all_shadow_bodies, min_sep=8.0):
        """Push bodies apart so they don't overlap. Phase through everything else."""
        for other in all_shadow_bodies:
            if other is self:
                continue
            _sep = self.pos - other.pos
            _sep[1] = 0.0  # horizontal only
            _d = float(np.linalg.norm(_sep))
            if 0.01 < _d < min_sep:
                _push = _sep / _d * (min_sep - _d) * 0.3
                self.pos += _push
            self.detect_physical_contact(other)

    # Class-level constants for contact detection (avoid recreating dicts every call)
    _ZONE_HEIGHT = {
        'head': 0.92, 'face': 0.90, 'lips': 0.88, 'neck': 0.82,
        'chest': 0.72, 'breasts': 0.70, 'nipples': 0.69, 'back': 0.68,
        'abdomen': 0.58, 'lower_back': 0.55, 'arms': 0.60,
        'hands': 0.42, 'fingers': 0.40, 'buttocks': 0.48,
        'genitals': 0.45, 'perineum': 0.43, 'inner_thigh': 0.38,
        'thighs': 0.35, 'knees': 0.28, 'shins': 0.18, 'feet': 0.04,
    }
    _ZONE_LATERAL = {
        'head': 0.15, 'face': 0.12, 'lips': 0.06, 'neck': 0.08,
        'chest': 0.25, 'breasts': 0.22, 'nipples': 0.18, 'back': 0.22,
        'abdomen': 0.20, 'lower_back': 0.20, 'arms': 0.45,
        'hands': 0.50, 'fingers': 0.52, 'buttocks': 0.22,
        'genitals': 0.10, 'perineum': 0.08, 'inner_thigh': 0.15,
        'thighs': 0.18, 'knees': 0.10, 'shins': 0.08, 'feet': 0.10,
    }

    def detect_physical_contact(self, other, body_height=6.0):
        """Detect physical contact between this body and another ShadowBody.
        Maps proximity between body regions to tactile zone stimulation.
        body_height: approximate rendered height for zone mapping."""
        _sep = other.pos - self.pos
        _sep[1] = 0.0
        _dist = float(np.linalg.norm(_sep))
        # Bodies must be within touching distance (~2x arm length)
        _touch_range = body_height * 0.6
        if _dist > _touch_range or _dist < 0.01:
            return
        # Proximity factor: 1.0 = touching, 0.0 = at edge of range
        _prox = 1.0 - (_dist / _touch_range)
        _prox_sq = _prox * _prox  # quadratic falloff for more natural feel
        # For each zone, check if this body's zone is close to any of other's zones
        _body_w = body_height * 0.25
        for zname, zheight in self._ZONE_HEIGHT.items():
            _my_y = self.pos[1] + zheight * body_height
            _my_lat = self._ZONE_LATERAL.get(zname, 0.15) * _body_w
            # Check against same-height region on other body
            _other_y = other.pos[1] + zheight * body_height
            _vert_dist = abs(_my_y - _other_y)
            if _vert_dist > body_height * 0.15:
                continue
            # Effective contact intensity based on proximity and lateral overlap
            _eff_range = _my_lat + self._ZONE_LATERAL.get(zname, 0.15) * _body_w
            _contact_intensity = _prox_sq * max(0.0, 1.0 - _vert_dist / (body_height * 0.15))
            if _contact_intensity > 0.05:
                self.apply_touch(zname, _contact_intensity * 0.3, source_id=other.obs_id, is_pleasant=True)

    def _select_target_pose(self, dt):
        new_target = None
        if self.anim_state == self.TELEPORTING:
            new_target = _POSE_TELEPORT_DISSOLVE
        elif self.anim_state == self.TALKING:
            if math.sin(self.anim_time * 2.5 * self._motion_speed) > 0:
                new_target = _POSE_TALK_A
            else:
                new_target = _POSE_TALK_B
        elif self.anim_state == self.SPAWNING:
            new_target = _POSE_SPAWN
        elif self.anim_state == self.OBSERVING:
            new_target = _POSE_OBSERVE
        elif self.anim_state == self.BUILDING:
            new_target = _POSE_BUILD
        elif self.anim_state == self.POINTING:
            new_target = _POSE_POINT
        elif self.anim_state == self.FLYING:
            new_target = _POSE_FLY
        elif self.anim_state == self.THINKING:
            new_target = _POSE_THINK
        elif self.anim_state == self.SITTING:
            new_target = _POSE_SIT
        elif self.anim_state == self.WALKING:
            wp = self._walk_phase % 1.0
            idx = int(wp * 4) % 4
            frac = (wp * 4) % 1.0
            new_target = _lerp_pose(_WALK_CYCLE[idx], _WALK_CYCLE[(idx + 1) % 4], frac)
        else:
            new_target = _POSE_IDLE
        if new_target is not None and new_target is not self._target_pose:
            self._target_pose = new_target
            self._blend_t = 0.0

    def teleport_to(self, target_pos):
        """Instantly teleport this AI body to target_pos (np array or list).
        Triggers a brief dissolve/reappear animation via teleport_alpha."""
        _tp = np.array(target_pos[:3], dtype=np.float64)
        if not np.all(np.isfinite(_tp)):
            return
        if np.linalg.norm(_tp) > 1e8:
            return
        self.prev_pos = self.pos.copy()
        self.pos = _tp.copy()
        self.pos[1] = self.prev_pos[1]  # keep same ground level
        self.teleport_alpha = 0.0  # fade-in effect
        self.wander_target = None  # cancel any wander
        self.anim_state = self.TELEPORTING if hasattr(self, 'TELEPORTING') else self.IDLE
        # Update heading to face arrival direction
        _delta = self.pos - self.prev_pos
        _delta[1] = 0.0
        _dlen = float(np.linalg.norm(_delta))
        if _dlen > 1.0:
            self.heading = math.atan2(float(_delta[0]), float(_delta[2]))

    def teleport_to_body(self, other_body, offset=12.0):
        """Teleport this AI body near another AI body to meet up.
        Arrives offset units away facing the other body."""
        if other_body is self:
            return
        _op = other_body.pos.copy()
        if not np.all(np.isfinite(_op)):
            return
        # Arrive offset units away at a random angle
        _angle = random.uniform(0, 2 * math.pi)
        _arrival = _op + np.array([math.sin(_angle) * offset, 0.0, math.cos(_angle) * offset])
        self.teleport_to(_arrival)
        # Face the other body
        _to_other = _op - self.pos
        _to_other[1] = 0.0
        _d = float(np.linalg.norm(_to_other))
        if _d > 0.1:
            self.heading = math.atan2(float(_to_other[0]), float(_to_other[2]))

    def set_talk(self, message, duration=4.0):
        self.talk_bubble = message
        self.talk_timer = duration
        self.anim_state = self.TALKING

    def get_silhouette(self, h):
        """Return (fill_tris, outline_lines) for anatomically correct humanoid.
        Uses FK-solved skeleton with current blended pose."""
        t = self.anim_time + self.anim_phase
        breath = math.sin(self._breath_phase) * 0.008 * self._motion_scale
        pose = dict(self._current_pose)
        sc = pose.get('spine_chest', (0.0, 0.0))
        pose['spine_chest'] = (sc[0] + breath, sc[1])
        sway = math.sin(t * 0.7 * self._motion_speed) * 0.005 * self._motion_scale
        pv = pose.get('pelvis', (0.0, 0.0))
        pose['pelvis'] = (pv[0] + sway, pv[1])
        positions = self.skeleton.solve_fk(h, pose)
        # Widen leg positions to prevent limb overlap (matches get_3d_limbs)
        _leg_widen = h * 0.012 * self.hip_scale * self.thigh_fullness
        for _prefix, _sign in [('l_', -1), ('r_', 1)]:
            for _jn in (_prefix + 'hip', _prefix + 'knee', _prefix + 'ankle',
                        _prefix + 'ball', _prefix + 'toe_tip',
                        _prefix + 'big_toe', _prefix + 'pinky_toe'):
                if _jn in positions:
                    _jx, _jy = positions[_jn]
                    positions[_jn] = (_jx + _sign * _leg_widen, _jy)
        _arm_widen = h * 0.006 * self.shoulder_scale
        for _prefix, _sign in [('l_', -1), ('r_', 1)]:
            for _jn in (_prefix + 'shoulder', _prefix + 'elbow', _prefix + 'wrist',
                        _prefix + 'middle_mcp', _prefix + 'middle_tip',
                        _prefix + 'index_mcp', _prefix + 'index_tip',
                        _prefix + 'ring_mcp', _prefix + 'ring_tip',
                        _prefix + 'pinky_mcp', _prefix + 'pinky_tip',
                        _prefix + 'thumb_cmc', _prefix + 'thumb_tip'):
                if _jn in positions:
                    _jx, _jy = positions[_jn]
                    positions[_jn] = (_jx + _sign * _arm_widen, _jy)
        lines = []
        for ja, jb in _BONE_PAIRS:
            if ja in positions and jb in positions:
                ax, ay = positions[ja]
                bx, by = positions[jb]
                lines.append((ax, ay, bx, by))
        if 'head' in positions and 'head_top' in positions:
            hx, hy = positions['head']
            htx, hty = positions['head_top']
            head_r = math.sqrt((htx - hx) ** 2 + (hty - hy) ** 2) * 0.48
            hcx = (hx + htx) * 0.5
            hcy = (hy + hty) * 0.5
            ns = 48
            for i in range(ns):
                a1 = 2 * _PI * i / ns
                a2 = 2 * _PI * (i + 1) / ns
                lines.append((hcx + head_r * math.cos(a1), hcy + head_r * math.sin(a1),
                              hcx + head_r * math.cos(a2), hcy + head_r * math.sin(a2)))
        fill = []
        for ja, jb, wk in _FILL_SEGMENTS:
            if ja in positions and jb in positions:
                ax, ay = positions[ja]
                bx, by = positions[jb]
                w = _LIMB_WIDTH.get(wk, 0.02) * h * 0.5
                dx, dy = bx - ax, by - ay
                bone_len = math.sqrt(dx * dx + dy * dy)
                if bone_len < 0.001:
                    continue
                nx, ny = -dy / bone_len * w, dx / bone_len * w
                fill.append((ax + nx, ay + ny, ax - nx, ay - ny, bx + nx, by + ny))
                fill.append((ax - nx, ay - ny, bx - nx, by - ny, bx + nx, by + ny))
        if 'head' in positions and 'head_top' in positions:
            hx, hy = positions['head']
            htx, hty = positions['head_top']
            head_r = math.sqrt((htx - hx) ** 2 + (hty - hy) ** 2) * 0.48
            hcx = (hx + htx) * 0.5
            hcy = (hy + hty) * 0.5
            ns = 48
            for i in range(ns):
                a1 = 2 * _PI * i / ns
                a2 = 2 * _PI * (i + 1) / ns
                fill.append((hcx, hcy,
                             hcx + head_r * math.cos(a1), hcy + head_r * math.sin(a1),
                             hcx + head_r * math.cos(a2), hcy + head_r * math.sin(a2)))
        if all(k in positions for k in ('l_shoulder', 'r_shoulder', 'l_hip', 'r_hip')):
            ls = positions['l_shoulder']
            rs = positions['r_shoulder']
            lh = positions['l_hip']
            rh = positions['r_hip']
            fill.append((ls[0], ls[1], rs[0], rs[1], rh[0], rh[1]))
            fill.append((ls[0], ls[1], rh[0], rh[1], lh[0], lh[1]))
        return fill, lines

    def get_3d_limbs(self, h):
        """Return 3D volumetric limb data for true 3D rendering.
        Returns: (capsules, head_info, face_details, muscles, hair)
          capsules: list of (x1,y1, x2,y2, radius, limb_key)
          head_info: (cx, cy, radius) or None
          face_details: list of (x, y, z, radius, detail_type)
          muscles: list of (x, y, z, radius, muscle_type)
          hair: list of (x1,y1,z1, x2,y2,z2, radius, hair_type)"""
        t = self.anim_time + self.anim_phase
        breath = math.sin(self._breath_phase) * 0.008 * self._motion_scale
        pose = dict(self._current_pose)
        sc = pose.get('spine_chest', (0.0, 0.0))
        pose['spine_chest'] = (sc[0] + breath, sc[1])
        sway = math.sin(t * 0.7 * self._motion_speed) * 0.005 * self._motion_scale
        pv = pose.get('pelvis', (0.0, 0.0))
        pose['pelvis'] = (pv[0] + sway, pv[1])
        positions = self.skeleton.solve_fk(h, pose)
        # === Widen leg positions to prevent limb overlap ===
        # Thigh radius grows with hip_scale and thigh_fullness, so legs need more separation
        _leg_widen = h * 0.012 * self.hip_scale * self.thigh_fullness
        for _prefix, _sign in [('l_', -1), ('r_', 1)]:
            for _jn in (_prefix + 'hip', _prefix + 'knee', _prefix + 'ankle',
                        _prefix + 'ball', _prefix + 'toe_tip',
                        _prefix + 'big_toe', _prefix + 'pinky_toe'):
                if _jn in positions:
                    _jx, _jy = positions[_jn]
                    positions[_jn] = (_jx + _sign * _leg_widen, _jy)
        # Widen arms slightly to clear torso
        _arm_widen = h * 0.006 * self.shoulder_scale
        for _prefix, _sign in [('l_', -1), ('r_', 1)]:
            for _jn in (_prefix + 'shoulder', _prefix + 'elbow', _prefix + 'wrist',
                        _prefix + 'middle_mcp', _prefix + 'middle_tip',
                        _prefix + 'index_mcp', _prefix + 'index_tip',
                        _prefix + 'ring_mcp', _prefix + 'ring_tip',
                        _prefix + 'pinky_mcp', _prefix + 'pinky_tip',
                        _prefix + 'thumb_cmc', _prefix + 'thumb_tip'):
                if _jn in positions:
                    _jx, _jy = positions[_jn]
                    positions[_jn] = (_jx + _sign * _arm_widen, _jy)
        # Gender-specific limb width scaling
        _ss = self.shoulder_scale
        _hs = self.hip_scale
        _ws = self.waist_scale
        _cs = self.chest_scale
        _ns = self.neck_scale
        _md = self.muscle_definition
        capsules = []
        for ja, jb, wk in _FILL_SEGMENTS:
            if ja in positions and jb in positions:
                ax, ay = positions[ja]
                bx, by = positions[jb]
                r = _LIMB_WIDTH.get(wk, 0.02) * h * 0.5
                # Apply gender-specific scaling to body regions
                if wk == 'torso_upper':
                    r *= _cs
                elif wk == 'torso_lower':
                    r *= _ws * self.waist_taper
                elif wk in ('clavicle', 'upper_arm'):
                    r *= _ss
                elif wk == 'thigh':
                    r *= _hs * self.thigh_fullness
                elif wk == 'shin':
                    r *= self.calf_curve
                elif wk == 'neck':
                    r *= _ns
                capsules.append((ax, ay, bx, by, r, wk))
        # === Female hourglass curve capsules ===
        if self.gender == 'female' and self.hip_flare > 1.0:
            # Hip flare pads — widen the pelvis-to-hip region laterally
            if 'pelvis' in positions and 'l_hip' in positions and 'r_hip' in positions:
                px, py = positions['pelvis']
                lhx, lhy = positions['l_hip']
                rhx, rhy = positions['r_hip']
                _hf = self.hip_flare
                _hfr = h * 0.048 * _hf  # hip pad radius
                # Left hip flare pad
                _lhfx = lhx - h * 0.018 * (_hf - 1.0)
                capsules.append((_lhfx, lhy + h * 0.015, _lhfx, lhy - h * 0.02, _hfr, 'hip_flare'))
                # Right hip flare pad
                _rhfx = rhx + h * 0.018 * (_hf - 1.0)
                capsules.append((_rhfx, rhy + h * 0.015, _rhfx, rhy - h * 0.02, _hfr, 'hip_flare'))
            # Waist taper — narrowing capsules at spine_naval
            if 'spine_naval' in positions:
                nvx, nvy = positions['spine_naval']
                _wt_r = h * 0.038 * self.waist_taper
                capsules.append((nvx, nvy + h * 0.01, nvx, nvy - h * 0.01, _wt_r, 'waist_taper'))
        head_info = None
        face_details = []
        muscles = []
        hair = []
        if 'head' in positions and 'head_top' in positions:
            hx, hy = positions['head']
            htx, hty = positions['head_top']
            head_r = math.sqrt((htx - hx) ** 2 + (hty - hy) ** 2) * 0.48
            hcx = (hx + htx) * 0.5
            hcy = (hy + hty) * 0.5
            head_info = (hcx, hcy, head_r)
            _jw = self.jaw_width
            # === Detailed Face Geometry ===
            # Forehead — upper face surface
            face_details.append((hcx, hcy + head_r * 0.48, head_r * 0.82, head_r * 0.12, 'forehead'))
            # Brow ridge — prominent horizontal bar above eyes
            _brow_thick = head_r * 0.055 if self.gender == 'male' else head_r * 0.035
            for _bx_off in (-0.35, -0.15, 0.0, 0.15, 0.35):
                face_details.append((hcx + head_r * _bx_off, hcy + head_r * 0.32, head_r * 0.88, _brow_thick, 'brow_ridge'))
            # Eye sockets — slight indentation around eyes
            _er = head_r * 0.15 * self.eye_size
            _ey = hcy + head_r * 0.15
            _ez = head_r * 0.85
            face_details.append((hcx - head_r * 0.28, _ey - head_r * 0.02, _ez - _er * 0.3, _er * 1.3, 'eye_socket'))
