def _create_atom_at_pos(z, pos):
    """Shared atom creation — SINGLE code path for J key, sphere nav, AI spawn, and molecules.
    Identical rendering and behavior regardless of who triggers it.
    Returns the new Atom (already appended to global particles list)."""
    data = atom_data[z]
    sym = data['symbol']
    A = round(data['atomic_weight'])
    N = A - z
    sub = []
    for _ in range(z):
        sub.append(Particle('proton', pos=pos.copy()))
    for _ in range(N):
        sub.append(Particle('neutron', pos=pos.copy()))
    for _ in range(z):
        sub.append(Particle('electron', pos=pos.copy()))
    new_atom = Atom(sym, A, sub, pos.copy())
    particles.append(new_atom)
    return new_atom

def _execute_observer_action(obs, action_type, params):
    """Execute a resolved observer action on the simulation."""
    global time_factor, _obs_last_spawn_time
    # SAFETY: Prevent AI from triggering program exit or destructive actions
    _BLOCKED_AI_ACTIONS = {"exit", "close", "quit", "shutdown", "escape", "esc_y"}
    if action_type in _BLOCKED_AI_ACTIONS:
        _obs_activity_log.append((time.time(), obs.name, action_type, "BLOCKED: forbidden action", False))
        obs.learn(action_type, False)
        return
    ok = False
    _now = time.time()
    # Gate spawn/load actions behind user permission toggle
    _SPAWN_ACTIONS = {'spawn_atom', 'spawn_molecule', 'build_structure'}
    if action_type in _SPAWN_ACTIONS and not _ai_spawn_allowed:
        _obs_activity_log.append((_now, obs.name, action_type, 'BLOCKED: AI spawn permission OFF', False))
        obs.learn(action_type, False)
        return
    if action_type == 'spawn_atom':
        z = params.get('Z', 1)
        if z not in atom_data:
            z = 1  # Default to Hydrogen if invalid Z
        pos = np.array(params.get('pos', [0, 0, 0]), dtype=float)
        # Sanitize position: NaN/Inf falls back to camera.pos (prevents invisible atoms)
        if not np.all(np.isfinite(pos)):
            pos = camera.pos.copy()
        # Constrain spawn position to near camera (within 200 units)
        cam_dist = np.linalg.norm(pos - camera.pos)
        if cam_dist > 200.0:
            pos = camera.pos + (pos - camera.pos) / max(cam_dist, 1e-6) * 200.0 * random.uniform(0.3, 1.0)
        # Use shared atom creation — identical to J key / sphere nav placement
        new_atom = _create_atom_at_pos(z, pos)
        new_atom.spawned_by = obs.name
        _obs_last_spawn_time = _now
        ok = True
    elif action_type == 'spawn_molecule':
        idx = params.get('molecule_idx', 0)
        pos = np.array(params.get('pos', [0, 0, 0]), dtype=float)
        # Sanitize position: NaN/Inf falls back to camera.pos (prevents invisible molecules)
        if not np.all(np.isfinite(pos)):
            pos = camera.pos.copy()
        # Constrain spawn position to near camera
        cam_dist = np.linalg.norm(pos - camera.pos)
        if cam_dist > 200.0:
            pos = camera.pos + (pos - camera.pos) / max(cam_dist, 1e-6) * 200.0 * random.uniform(0.3, 1.0)
        if 0 <= idx < len(molecules_catalog):
            spawn_molecule(molecules_catalog[idx], pos, spawned_by=obs.name)
            _obs_last_spawn_time = _now
            ok = True
    elif action_type == 'change_time':
        if not _ai_time_control_allowed:
            _obs_activity_log.append((_now, obs.name, action_type, 'BLOCKED: AI time control permission OFF', False))
            obs.learn(action_type, False)
            return
        new_tf = params.get('new_time_factor', time_factor)
        time_factor = max(0.001, min(2.0, new_tf))
        ok = True
    elif action_type == 'toggle_run_odds':
        _self_assembly.toggle_run_odds(simulation_time, particle_list=particles)
        ok = True
    elif action_type == 'focus_particle':
        obs.focus_target_id = params.get('target_id')
        # Teleport body to the focused particle's position
        _target_id = params.get('target_id')
        if _target_id is not None:
            for _fp in particles:
                if id(_fp) == _target_id:
                    _sb_idx = next((i for i, sb in enumerate(_shadow_bodies) if sb.obs_id == obs.name), -1)
                    if _sb_idx >= 0:
                        _shadow_bodies[_sb_idx].teleport_to(_fp.pos)
                    break
        ok = True
    elif action_type == 'teleport':
        # AI teleports body to arbitrary position
        _tp = np.array(params.get('pos', [0, 0, 0]), dtype=float)
        _sb_idx = next((i for i, sb in enumerate(_shadow_bodies) if sb.obs_id == obs.name), -1)
        if _sb_idx >= 0:
            _shadow_bodies[_sb_idx].teleport_to(_tp)
            ok = True
    elif action_type == 'teleport_to_peer':
        # AI teleports body to another AI body to meet up
        _peer_name = params.get('peer_name', '')
        _sb_idx = next((i for i, sb in enumerate(_shadow_bodies) if sb.obs_id == obs.name), -1)
        _peer_idx = next((i for i, sb in enumerate(_shadow_bodies) if sb.obs_id == _peer_name), -1)
        if _sb_idx >= 0 and _peer_idx >= 0 and _sb_idx != _peer_idx:
            _shadow_bodies[_sb_idx].teleport_to_body(_shadow_bodies[_peer_idx])
            ok = True
    elif action_type == 'toggle_loadin':
        li_key = params.get('key', '')
        if li_key in _ai_loadins:
            _toggle_loadin(li_key, source=obs.name)
            ok = True
    elif action_type == 'launch_gna':
        if not _gna_allowed:
            _obs_activity_log.append((_now, obs.name, action_type, 'BLOCKED: GNA AI permission OFF', False))
            obs.learn(action_type, False)
            return
        if not _gna_running:
            _launch_gna()
            ok = True
    elif action_type == 'stop_gna':
        if _gna_running:
            _stop_gna()
            ok = True
    # Log to activity log
    detail = str(params)[:60] if params else ''
    _obs_activity_log.append((_now, obs.name, action_type, detail if ok else f'BLOCKED: {detail}', ok))
    obs.learn(action_type, ok)
    if ok:
        _history_log.append((simulation_time, f"[AI] {obs.name}: {action_type}"))
        if len(_history_log) > _history_max:
            _history_log.pop(0)

