            # === TAB 6: IP Map (Atlas with zoom/pan) ===
            self._map_frame = ttk.Frame(nb)
            nb.add(self._map_frame, text=" 🗺️ IP Map ")
            # Controls bar
            map_ctrl = tk.Frame(self._map_frame, bg="#1a1a2e", height=32)
