            ('cookie', 'COOKIE_TRACKING', 'Process is sending/receiving tracking cookies'),
            ('upload', 'DATA_UPLOAD', 'Process is uploading data'),
            ('exfil', 'DATA_EXFIL', 'Potential data exfiltration detected'),
