# === Deterministic Time Travel Frame Buffer ===
# Dense recording of simulation state every render frame.
# Reverse time restores from recorded frames (byte-identical determinism).
# Forward within recorded range replays from frames.
# Forward past recorded range runs live physics and records new frames.
# When reversing past recorded frames, runs live reverse physics.
_det_frames = []          # Ring buffer: [(sim_time, exp_scale, cloud_r, V_total, V_pct, [(pos,vel),...]), ...]
_det_frame_max = 18000    # Max frames stored (~5 min at 60fps)
_det_playhead = -1        # -1 = live mode, 0..N-1 = replay index
_reverse_live_mode = False # True when recorded frames exhausted during reverse â€” runs live reverse physics

def _record_particle_states(particles):
    """Record full state for all particles, including atom sub-particles and quarks.
    Returns list of tuples: (pos, vel, sub_data) where sub_data is None for non-atoms,
    or [(sp_pos, sp_vel, [(q_pos, q_vel), ...]), ...] for atoms."""
    states = []
    for p in particles:
        if p.is_atom and hasattr(p, 'sub_particles') and p.sub_particles:
            sub_data = []
            for sp in p.sub_particles:
                quarks = []
                for q in getattr(sp, 'constituent_quarks', []):
                    quarks.append((q.pos.copy(), q.vel.copy()))
                sub_data.append((sp.pos.copy(), sp.vel.copy(), quarks))
            states.append((p.pos.copy(), p.vel.copy(), sub_data))
        else:
            states.append((p.pos.copy(), p.vel.copy(), None))
    return states

def _restore_particle_states(particles, states):
    """Restore full state for all particles from recorded states,
    including atom sub-particles and their constituent quarks."""
    for i, p in enumerate(particles):
        if i >= len(states):
            break
        st = states[i]
        p.pos = st[0].copy()
        p.vel = st[1].copy()
        # Restore sub-particle + quark state if this is an atom
        sub_data = st[2] if len(st) > 2 else None
        if sub_data is not None and p.is_atom and hasattr(p, 'sub_particles'):
            for si, sp in enumerate(p.sub_particles):
                if si >= len(sub_data):
                    break
                sp.pos = sub_data[si][0].copy()
                sp.vel = sub_data[si][1].copy()
                quark_data = sub_data[si][2] if len(sub_data[si]) > 2 else []
                for qi, q in enumerate(getattr(sp, 'constituent_quarks', [])):
                    if qi >= len(quark_data):
                        break
                    q.pos = quark_data[qi][0].copy()
                    q.vel = quark_data[qi][1].copy()

def _interpolate_particle_states(particles, states_a, states_b, blend):
    """Interpolate particle state between two recorded snapshots, including sub-particles."""
    n_a = len(states_a)
    n_b = len(states_b)
    for i, p in enumerate(particles):
        if i < n_a and i < n_b:
            sa = states_a[i]
            sb = states_b[i]
            p.pos = sa[0] + (sb[0] - sa[0]) * blend
            p.vel = sa[1] + (sb[1] - sa[1]) * blend
            sub_a = sa[2] if len(sa) > 2 else None
            sub_b = sb[2] if len(sb) > 2 else None
            if sub_a is not None and sub_b is not None and p.is_atom and hasattr(p, 'sub_particles'):
                for si, sp in enumerate(p.sub_particles):
                    if si >= len(sub_a) or si >= len(sub_b):
                        break
                    sp.pos = sub_a[si][0] + (sub_b[si][0] - sub_a[si][0]) * blend
                    sp.vel = sub_a[si][1] + (sub_b[si][1] - sub_a[si][1]) * blend
                    q_a = sub_a[si][2] if len(sub_a[si]) > 2 else []
                    q_b = sub_b[si][2] if len(sub_b[si]) > 2 else []
                    for qi, q in enumerate(getattr(sp, 'constituent_quarks', [])):
                        if qi >= len(q_a) or qi >= len(q_b):
                            break
                        q.pos = q_a[qi][0] + (q_b[qi][0] - q_a[qi][0]) * blend
                        q.vel = q_a[qi][1] + (q_b[qi][1] - q_a[qi][1]) * blend
        elif i < n_a:
            sa = states_a[i]
            p.pos = sa[0].copy()
            p.vel = sa[1].copy()
            sub_a = sa[2] if len(sa) > 2 else None
            if sub_a is not None and p.is_atom and hasattr(p, 'sub_particles'):
                for si, sp in enumerate(p.sub_particles):
                    if si >= len(sub_a):
                        break
                    sp.pos = sub_a[si][0].copy()
                    sp.vel = sub_a[si][1].copy()
                    for qi, q in enumerate(getattr(sp, 'constituent_quarks', [])):
                        q_data = sub_a[si][2] if len(sub_a[si]) > 2 else []
                        if qi < len(q_data):
                            q.pos = q_data[qi][0].copy()
                            q.vel = q_data[qi][1].copy()

def _find_nearest_frame_by_time(target_time):
    """Binary search _det_frames for the frame nearest to target_time.
    Returns frame index or -1 if no frames."""
    if not _det_frames:
        return -1
    lo, hi = 0, len(_det_frames) - 1
    while lo < hi:
        mid = (lo + hi) // 2
        if _det_frames[mid][0] < target_time:
            lo = mid + 1
        else:
            hi = mid
    # lo is now the first frame >= target_time; check which neighbor is closer
    if lo > 0 and abs(_det_frames[lo - 1][0] - target_time) < abs(_det_frames[lo][0] - target_time):
        return lo - 1
    return lo

# (Behavioral extrapolation cache removed — all time factors use raw physics only)

# === Space Expansion (Hubble-like, CMB-calibrated) ===
# Real Hubble constant H0 = 67.4 km/s/Mpc ~ 2.184e-18 /s.
# CMB temperature scales as T_cmb = 2.725 K / a(t), where a(t) is the scale factor.
# We use H_real scaled up so expansion is visible within the simulation's
# timescale while preserving the correct exponential growth character.
# At H_sim = 2.184e-6, expansion doubles every ~317,000 sim-seconds (~3.7 days).
# This is 1e12× faster than reality but keeps the same Hubble-flow physics.
H_real = 2.184e-18    # true Hubble constant (/s) — for reference
H_sim = 2.184e-6      # sim Hubble parameter: H_real × 1e12 (visible expansion)
expansion_scale = 1.0  # current cumulative expansion factor (starts at 1)

def sphere_coords_to_3d_pos(degree, xz, xx, xy, radius):
    """Convert dimensional sphere coordinates to a 3D simulation position.
    degree (0-360) â†’ azimuthal angle (longitude),
    xz (0-59)      â†’ polar angle (latitude, mapped 0-180Â°),
    xx (0-59)      â†’ radial depth fraction,
    xy (0-59)      â†’ fine radial subdivision,
    radius          â†’ current expansion radius of the universe."""
    theta = math.radians(degree)                    # azimuthal (longitude)
    phi = math.pi * xz / max(59.0, 1.0)            # polar (latitude, 0â†’Ï€)
    r_frac = (xx + xy / 60.0) / 60.0               # 0..1 radial fraction
    r = radius * max(0.05, r_frac)                  # at least 5% of radius
    x_3d = r * math.sin(phi) * math.cos(theta)
    y_3d = r * math.sin(phi) * math.sin(theta)
    z_3d = r * math.cos(phi)
    return np.array([x_3d, y_3d, z_3d] + [0.0] * (dims - 3))

def _safe_float(v):
    """Clamp a value to a safe finite range for location hashing."""
    import math as _m
    if _m.isnan(v) or _m.isinf(v):
        return 0.0
    return max(-1e15, min(1e15, v))


def particle_infinity_location(p):
    """Compute a particle's unique location within the V_total infinity map.
    Returns a high-precision fractional address (0..1) within INFINITY_MAP,
    deterministic and ever-changing based on the particle's state and V_total.
    This is the particle's 'address in infinity' â€” where it exists in the
    dimensional sphere at this moment in time.
    Positions are comoving: divided by expansion_scale so the 5,184,000 grid
    represents the full expanded space and locations become finer decimals
    as the universe expands."""
    _einv = 1.0 / max(1e-30, expansion_scale)  # comoving inverse
    _pos_hash = _safe_float((float(p.pos[0]) * _einv) * 7.13 + (float(p.pos[1]) * _einv) * 11.37 + (float(p.pos[2]) * _einv) * 3.91)
    _vel_hash = _safe_float(float(p.vel[0]) * 2.71 + float(p.vel[1]) * 5.43 + float(p.vel[2]) * 1.67)
    _mass_c = _safe_float(p.mass * 1e10) if p.mass > 0 else 1e-20
    _e_c = _safe_float(p.energy_kin + getattr(p, 'energy_rot', 0) + 1e-40)
    _charge_c = _safe_float((p.charge + 2.0) * 3.7)
    _spin_c = _safe_float((getattr(p, 'spin', 0) + 1.0) * 13.0)
    _raw = abs(_pos_hash) + abs(_vel_hash) + abs(_mass_c) + abs(_e_c) + abs(_charge_c) + abs(_spin_c)
    _raw += _safe_float(abs(V_total) * 1e-8) + _safe_float(simulation_time * 0.0137)
    _raw = _safe_float(_raw)
    if _raw == 0.0:
        _raw = 1e-20
    _frac = (_raw % INFINITY_MAP) / INFINITY_MAP
    return _frac


def particle_frame_location(p):
    """Compute a particle's deterministic state-space frame location (Î¦).
    Unlike the ever-changing âˆž address, this is a FIXED coordinate for the
    current simulation frame â€” it gives the exact, solved location of this
    particle within the dimensional sphere at this instant. When paused,
    this value is frozen and represents the particle's definite position
    in the infinity map.
    Positions are comoving: divided by expansion_scale so locations become
    smaller decimal addresses as the universe expands.
    Returns (location_index, degree, coord_str)."""
    # Use individual position components with prime multipliers for unique spreading
    # Comoving: divide by expansion_scale so the grid covers expanded space
    _einv = 1.0 / max(1e-30, expansion_scale)
    _px = _safe_float(float(p.pos[0]) * _einv)
    _py = _safe_float(float(p.pos[1]) * _einv)
    _pz = _safe_float(float(p.pos[2]) * _einv)
    _vx = _safe_float(float(p.vel[0]))
    _vy = _safe_float(float(p.vel[1]))
    _vz = _safe_float(float(p.vel[2]))
    _mass_v = _safe_float(p.mass * 1e12)
    _e_v = _safe_float(p.energy_kin + getattr(p, 'energy_rot', 0))
    _charge_v = _safe_float(p.charge)
    _spin_v = _safe_float(getattr(p, 'spin', 0))
    # Per-particle unique hash using non-commutative combination of all state
    _h1 = _px * 7.13 + _py * 11.37 + _pz * 3.91
    _h2 = _vx * 2.71 + _vy * 5.43 + _vz * 1.67
    _h3 = _mass_v * 0.0031 + _e_v * 0.0017 + _charge_v * 197.3 + _spin_v * 53.0
    # Use id(p) for a truly unique per-particle seed that survives even when
    # multiple particles share identical state (e.g. freshly spawned)
    _pid = id(p) % 5184000
    # Combine: particle-specific terms dominate, time modulates slowly
    _state = abs(_h1) * 137.036 + abs(_h2) * 29.97 + abs(_h3) + _pid
    _state += _safe_float(simulation_time * 0.37)  # slow time modulation
    _state = _safe_float(_state)
    if _state == 0.0:
        _state = 1e-20
    loc = int(_state % INFINITY_MAP)
    cycle = loc // 216000
    rem = loc % 216000
    xz = rem // 3600
    xx = (rem % 3600) // 60
    xy = rem % 60
    degree = (cycle / 24.0) * 360.0
    coord_str = f"{degree:.1f}\u00b0,{xz},{xx},{xy}"
    return loc, degree, coord_str


def parse_time_input(txt):
    """Parse a time input string into seconds.
    Supported formats:
      - Plain number â‰¤100 â†’ None (caller treats as time factor %)
      - 'Xs' â†’ X seconds          e.g. '500s' = 500 seconds
      - 'Xm' â†’ X minutes          e.g. '30m' = 1800 seconds
      - 'Xh' â†’ X hours            e.g. '2h' = 7200 seconds
      - 'Xy' â†’ X years            e.g. '1y' = 31,540,000 seconds
      - '2h30m15s' â†’ combined     e.g. 2*3600 + 30*60 + 15 = 9015 seconds
      - 'HH:MM:SS' â†’ hours:min:s  e.g. '1:30:00' = 5400 seconds
      - 'MM:SS' â†’ min:sec         e.g. '5:30' = 330 seconds
    Returns (mode, value) where mode is 'time_seconds', 'time_factor', or None on error.
    """
    import re
    txt = txt.strip().lower()
    if not txt:
        return None, 0.0
    # Check for colon-separated format (HH:MM:SS or MM:SS)
    if ':' in txt:
        parts = txt.split(':')
        try:
            nums = [float(p) for p in parts]
        except ValueError:
            return None, 0.0
        if len(nums) == 3:
            return 'time_seconds', nums[0] * 3600 + nums[1] * 60 + nums[2]
        elif len(nums) == 2:
            return 'time_seconds', nums[0] * 60 + nums[1]
        return None, 0.0
    # Check for suffix-based format (e.g. '2h30m15s', '500s', '1y')
    _has_suffix = bool(re.search(r'[hmsy]', txt))
    if _has_suffix:
        total = 0.0
        for val_str, unit in re.findall(r'([0-9]*\.?[0-9]+)\s*([hmsy])', txt):
            v = float(val_str)
            if unit == 's':
                total += v
            elif unit == 'm':
                total += v * 60.0
            elif unit == 'h':
                total += v * 3600.0
            elif unit == 'y':
                total += v * 3.154e7
        if total != 0.0:
            return 'time_seconds', total
        return None, 0.0
    # Plain number: try float
    try:
        val = float(txt)
    except ValueError:
        return None, 0.0
    # â‰¤100 â†’ time factor %; >100 â†’ seconds to jump to
    if abs(val) <= 100:
        return 'time_factor', val
    else:
        return 'time_seconds', val


def particle_infinity_addr_str(p):
    """Format a particle's infinity location as a high-precision string.
    Returns e.g. '0.00000003184729...' â€” the ever-changing address in the
    dimensional sphere of V_total."""
    frac = particle_infinity_location(p)
    if frac == 0.0:
        return "0." + "0" * 18 + "..."
    s = f"{frac:.20f}"
    return s.rstrip('0') + '...'


def particle_frame_addr_str(p):
    """Format a particle's state-space frame location as a string.
    Returns e.g. 'Î¦:142857 (45.0Â°,2,13,57)' â€” the solved, fixed location
    at this exact frame/instant in time."""
    loc, deg, coord = particle_frame_location(p)
    return f"{loc:,}/{INFINITY_MAP:,} ({coord})"


def vtotal_to_sphere_coords(v_total_val):
    """Convert V_total to dimensional sphere coordinates.
    Returns (degree, xz, xx, xy, cycle, time_str, location_index)."""
    _abs_v = abs(v_total_val)
    if math.isnan(_abs_v) or math.isinf(_abs_v):
        _abs_v = 0.0
    loc = int(_abs_v % INFINITY_MAP)
    cycle = loc // 216000  # 0-23 (60*60*60 = 216000)
    rem = loc % 216000
    xz = rem // 3600  # 0-59
    xx = (rem % 3600) // 60  # 0-59
    xy = rem % 60  # 0-59
    degree = (cycle / 24.0) * 360.0
    # Map to time: cycle=hour, xz=minute, xx=second, xy=fractional
    time_str = f"{cycle:02d}:{xz:02d}:{xx:02d}.{xy:02d}"
    return degree, xz, xx, xy, cycle, time_str, loc


def _mandelbrot_compute(res, center_r, center_i, zoom, max_iter):
    """Compute an INVERTED (outward-looking) Mandelbrot grid.
    Uses c → 1/c̄ inversion: the exterior of the standard set maps to the
    rendered plane, so scrolling expands outward from the boundary.
    The boundary itself is the 'barrier of translation' between the
    sphere (inward) and Mandelbrot (outward) coordinate systems.
    Returns (iter_grid, r_min, r_max, i_min, i_max) in the INVERTED plane."""
    scale = 3.5 / max(zoom, 0.001)
    r_min = center_r - scale / 2.0
    r_max = center_r + scale / 2.0
    i_min = center_i - scale / 2.0
    i_max = center_i + scale / 2.0
    r = np.linspace(r_min, r_max, res)
    i = np.linspace(i_min, i_max, res)
    C_view = r[np.newaxis, :] + 1j * i[:, np.newaxis]
    # Inversion: map each view-plane point through 1/c̄ (Riemann sphere
    # antipodal map).  Points near the origin in the view correspond to
    # the FAR exterior of the standard set; points far from the origin
    # correspond to points near the set boundary — exactly the outward-
    # looking perspective described by the 180° rotation (image 3).
    mag_sq = np.abs(C_view) ** 2
    safe = mag_sq > 1e-30
    C = np.where(safe, np.conj(C_view) / np.where(safe, mag_sq, 1.0), 0.0 + 0j)
    Z = np.zeros_like(C)
    M = np.full(C.shape, max_iter, dtype=np.int32)
    mask = np.ones(C.shape, dtype=bool)
    for n in range(max_iter):
        Z[mask] = Z[mask] ** 2 + C[mask]
        escaped = mask & (np.abs(Z) > 2.0)
        M[escaped] = n
        mask &= ~escaped
        if not mask.any():
            break
    # Invert iteration counts: exterior points that escape quickly should
    # appear as HIGH values (far outward), interior (never-escape) stays 0.
    # This makes the 3D wireframe rise outward from the boundary.
    M_out = np.where(M < max_iter, max_iter - M, 0).astype(np.int32)
    return M_out, r_min, r_max, i_min, i_max


def _mandelbrot_iter_color(n, max_iter):
    """Map INVERTED iteration count to an RGBA color tuple.
    n=0 = interior/boundary (dark); n>0 = exterior (colored by outward distance).
    Higher n = farther outward = brighter."""
    if n <= 0:
        return (8, 8, 40, 220)
    t = n / max(max_iter, 1)
    if t < 0.15:
        r = int(t / 0.15 * 80)
        g = int(t / 0.15 * 20)
        b = int(80 + t / 0.15 * 120)
        return (r, g, b, 220)
    elif t < 0.4:
        f = (t - 0.15) / 0.25
        return (int(80 + f * 100), int(20 + f * 200), int(200 - f * 80), 220)
    elif t < 0.65:
        f = (t - 0.4) / 0.25
        return (int(180 + f * 75), int(220 - f * 40), int(120 - f * 80), 220)
    else:
        f = (t - 0.65) / 0.35
        return (int(255 - f * 60), int(180 - f * 120), int(40 + f * 40), 220)


def _mandelbrot_build_image(data, max_iter, draw_w, draw_h):
    """Vectorized: convert iteration grid to a pyglet ImageData scaled to draw_w x draw_h.
    Returns a pyglet.image.ImageData ready for .blit()."""
    res_y, res_x = data.shape
    t = data.astype(np.float64) / max(max_iter, 1)
    inside = data <= 0  # Inverted: 0 = interior/boundary (dark)
    # Allocate RGB arrays
    r = np.zeros_like(t)
    g = np.zeros_like(t)
    b = np.zeros_like(t)
    # Inside set
    r[inside] = 8; g[inside] = 8; b[inside] = 40
    # Band 1: t < 0.15
    m1 = (~inside) & (t < 0.15)
    f1 = t[m1] / 0.15
    r[m1] = f1 * 80; g[m1] = f1 * 20; b[m1] = 80 + f1 * 120
    # Band 2: 0.15 <= t < 0.4
    m2 = (~inside) & (t >= 0.15) & (t < 0.4)
    f2 = (t[m2] - 0.15) / 0.25
    r[m2] = 80 + f2 * 100; g[m2] = 20 + f2 * 200; b[m2] = 200 - f2 * 80
    # Band 3: 0.4 <= t < 0.65
    m3 = (~inside) & (t >= 0.4) & (t < 0.65)
    f3 = (t[m3] - 0.4) / 0.25
    r[m3] = 180 + f3 * 75; g[m3] = 220 - f3 * 40; b[m3] = 120 - f3 * 80
    # Band 4: t >= 0.65
    m4 = (~inside) & (t >= 0.65)
    f4 = (t[m4] - 0.65) / 0.35
    r[m4] = 255 - f4 * 60; g[m4] = 180 - f4 * 120; b[m4] = 40 + f4 * 40
    # Clamp and convert to uint8
    r = np.clip(r, 0, 255).astype(np.uint8)
    g = np.clip(g, 0, 255).astype(np.uint8)
    b = np.clip(b, 0, 255).astype(np.uint8)
    # Interleave into RGB bytes (pyglet expects bottom-to-top row order)
    rgb = np.stack([r, g, b], axis=-1)  # (res_y, res_x, 3)
    raw = bytes(rgb.tobytes())
    img = pyglet.image.ImageData(res_x, res_y, 'RGB', raw, pitch=res_x * 3)
    return img


def _mandelbrot_to_sphere_loc(c_real, c_imag):
    """Map Mandelbrot complex coordinates to an INFINITY_MAP location address.
    Standard Mandelbrot view: real âˆˆ [-2.5, 1.5], imag âˆˆ [-2.0, 2.0].
    Returns integer location 0..INFINITY_MAP-1."""
    nr = (c_real + 2.5) / 4.0
    ni = (c_imag + 2.0) / 4.0
    nr = max(0.0, min(0.9999, nr))
    ni = max(0.0, min(0.9999, ni))
    row = int(nr * 2160)
    col = int(ni * 2400)
    return row * 2400 + col


def _sphere_loc_to_mandelbrot(loc):
    """Reverse map: INFINITY_MAP location â†’ Mandelbrot (c_real, c_imag)."""
    loc = loc % INFINITY_MAP
    row = loc // 2400
    col = loc % 2400
    c_real = -2.5 + (row / 2160.0) * 4.0
    c_imag = -2.0 + (col / 2400.0) * 4.0
    return c_real, c_imag


