            if _aid is not None:
                _hud_hotkey_rects.append((_bx_cur, _by_cur - 2, _btn_w, _btn_h, _aid, _dtxt))
            _hk_lbl.text = _dtxt
            _hk_lbl.x = _bx_cur + 4
            _hk_lbl.y = _by_cur
            _hk_lbl.draw()
            _bx_cur += _btn_w + _btn_gap

