    # F1 info overlay â€” full-screen scrollable panel with 8-column layout (col 8 = observer AI)
    if show_info_overlay and _f1_page == 0:
        _f1_px = int(WIDTH * 0.01)
        _f1_py = int(HEIGHT * 0.02)
        _f1_pw = int(WIDTH * 0.98)
        _f1_ph = int(HEIGHT * 0.96)
        Rectangle(_f1_px, _f1_py, _f1_pw, _f1_ph,
                  color=_TH_PANEL[:3]).draw()
        Label('SIMULATION INFO', x=WIDTH // 2, y=_f1_py + _f1_ph - 14, font_size=16,
              color=_TH_TEXT_ACC, anchor_x='center', anchor_y='center').draw()
        _f1_col_top = _f1_py + _f1_ph - 35
        _f1_col_pad = 8
        _f1_ncols = _NUM_F1_COLS
        _f1_col_w = (_f1_pw - (_f1_ncols + 1) * _f1_col_pad) // _f1_ncols
