        _p9_lines.append('=== FIVE POSTULATES ===')
        _p9_lines.append('1. EXISTENCE    — The substrate must exist in a state')
        _p9_lines.append('2. INTRINSICALITY — Cause-effect power is intrinsic')
        _p9_lines.append('3. INFORMATION  — Cause-effect repertoire is specific')
        _p9_lines.append('4. INTEGRATION  — Irreducible over minimum partition (MIP)')
        _p9_lines.append('5. EXCLUSION    — Maximal irreducible set wins')
