        _p9_lines.append('=== COMPUTATION PIPELINE ===')
        _p9_lines.append('1. Discretise internal states -> binary units (median split)')
        _p9_lines.append('2. Build Transition Probability Matrix (TPM) from state history')
        _p9_lines.append('3. For each mechanism subset:')
        _p9_lines.append('   a. Compute cause repertoire p(past | mechanism)')
        _p9_lines.append('   b. Compute effect repertoire p(future | mechanism)')
        _p9_lines.append('   c. Find Minimum Information Partition (MIP)')
